import { useState } from 'react';
import cx from 'classnames';
import { Highlight } from 'prism-react-renderer';

import { useTheme } from '../../context';
import { customTheme } from '../../themes';
import { CopyButton } from '../CopyButton/CopyButton';
import { Field } from '../forms/Field/Field';
import { Icon } from '../Icon/Icon';
import { RyeconCaretDown, RyeconCaretUp } from '../ryecons';
import { Sizes } from '../types';

export interface CodeSnippetProps {
  /** The code to display */
  code: string;

  /** The language of the code being displayed */
  language?: 'bash' | 'sql' | 'json' | 'python' | 'yaml' | 'graphql' | 'markdown ';

  /** Custom classnames */
  className?: string;

  /** Label for the code snippet */
  label?: string;

  /** Whether the label should be hidden */
  labelIsHidden?: boolean;

  /** Tooltip for the code snippet */
  tooltip?: string;

  /** Boolean to determine whether to include a copy button */
  includeCopyButton?: boolean;

  /** Whether to include line numbers */
  includeLineNumbers?: boolean;

  /** Custom header content to display between label and copy button */
  customHeader?: React.ReactNode;

  /** Maximum number of lines to show before collapsing. If not set, all lines are shown */
  maxLines?: number;

  /** Should be opaque before hover, or translucent  */
  toggleOpacity?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;

  /** Whether to remove the border around the code snippet */
  isBorderless?: boolean;
}

export const CodeSnippet: React.FC<CodeSnippetProps> = ({
  code,
  language = 'bash',
  className,
  label,
  labelIsHidden = false,
  tooltip,
  customHeader,
  maxLines,
  includeCopyButton = false,
  includeLineNumbers = true,
  toggleOpacity = false,
  testId = 'code-snippet',
  trackingId = 'code-snippet',
  isBorderless = false,
}): React.ReactElement => {
  const { themeClass } = useTheme();
  const [isExpanded, setIsExpanded] = useState(false);

  // Determine if header should be rendered (only when there's actual content)
  const hasHeaderContent = Boolean(label || tooltip || customHeader);

  return (
    <div
      className="group relative"
      data-testid={testId}
      data-trackingid={trackingId}
      data-theme={themeClass}
    >
      {hasHeaderContent && (
        <div
          className={cx('bg-bgBackground px-2 pt-1', {
            'border-borderMuted border border-b-0': !isBorderless,
            'rounded-t-md': !isBorderless,
          })}
        >
          <div className="flex flex-wrap items-center justify-between gap-1">
            {(label || tooltip) && (
              <Field
                label={label}
                labelIsHidden={labelIsHidden}
                tooltip={tooltip}
                className="flex-1"
                testId={`${testId}-wrapper`}
                trackingId={`${trackingId}-wrapper`}
              >
                <div />
              </Field>
            )}
            {customHeader && (
              <div className="flex items-center gap-2">{customHeader}</div>
            )}
          </div>
        </div>
      )}

      <div className="relative">
        <Highlight theme={customTheme} code={code.trim()} language={language}>
          {({ className: highlightClassName, tokens, getLineProps, getTokenProps }) => {
            const shouldLimitLines = maxLines && !isExpanded;
            const visibleTokens = shouldLimitLines ? tokens.slice(0, maxLines) : tokens;

            // Determine if footer will actually be rendered (only when there are hidden lines)
            const totalHiddenLines = maxLines ? tokens.length - maxLines : 0;
            const hasFooterContent = totalHiddenLines > 0;

            return (
              <pre
                className={cx(
                  'bg-bgBackground font-code overflow-auto',
                  {
                    // Border classes - only apply if not borderless
                    'border-borderMuted border': !isBorderless,
                    // Top border radius: rounded if no header, square if header exists (and not borderless)
                    'rounded-t-md': !isBorderless && !hasHeaderContent,
                    // Bottom border radius: rounded if no footer, square if footer exists (and not borderless)
                    'rounded-b-md': !isBorderless && !hasFooterContent,
                    // Border top: no border if header exists (to connect), full border if no header
                    'border-t-0': !isBorderless && hasHeaderContent,
                    'max-h-96': shouldLimitLines,
                  },
                  highlightClassName,
                  className,
                )}
              >
                {includeCopyButton && (
                  <div className="absolute right-2 top-0.5">
                    <CopyButton
                      inputLabel={`${language} code`}
                      text={code}
                      type="tertiary"
                      size={Sizes.xs}
                      testId={`${testId}-copy-button`}
                      trackingId={`${trackingId}-copy-button`}
                      className={cx(
                        'transition-opacity group-hover:opacity-100 group-focus:opacity-100',
                        { 'opacity-40': !toggleOpacity },
                      )}
                    />
                  </div>
                )}
                {visibleTokens.map((line, i) => (
                  <div
                    {...getLineProps({ line, key: i })}
                    key={i}
                    className="table-row"
                  >
                    {includeLineNumbers && (
                      <div
                        className={cx(
                          'text-fgDecorative table-cell select-none pl-2 text-right',
                        )}
                      >
                        {i + 1}
                      </div>
                    )}
                    <div
                      className={cx('table-cell whitespace-pre-wrap pl-2', {
                        'pt-1': i === 0,
                        'pb-2': i === visibleTokens.length - 1 && !shouldLimitLines,
                      })}
                    >
                      {line.map((token, key) => (
                        <span {...getTokenProps({ token, key })} key={key} />
                      ))}
                    </div>
                  </div>
                ))}
              </pre>
            );
          }}
        </Highlight>
      </div>

      {maxLines && (
        <Highlight theme={customTheme} code={code.trim()} language={language}>
          {({ tokens }) => {
            const totalHiddenLines = maxLines ? tokens.length - maxLines : 0;

            if (totalHiddenLines <= 0) {
              return <div />;
            }

            return (
              <button
                type="button"
                onClick={() => setIsExpanded(!isExpanded)}
                className={cx(
                  'bg-bgBackground px-4 py-2 text-sm transition-colors',
                  'text-fgMain hover:bg-bgMainHover flex w-full items-center justify-between',
                  {
                    'border-borderMuted border border-t-0': !isBorderless,
                    'rounded-b-md': !isBorderless,
                  },
                )}
                data-testid={`${testId}-expand-button`}
                data-trackingid={`${trackingId}-expand-button`}
              >
                <span>
                  {isExpanded ? 'Show less' : `Show ${totalHiddenLines} more lines`}
                </span>
                <Icon
                  ryecon={isExpanded ? RyeconCaretUp : RyeconCaretDown}
                  size="sm"
                  className="text-fgDecorative"
                />
              </button>
            );
          }}
        </Highlight>
      )}
    </div>
  );
};
