import cx from 'classnames';
import { line } from 'd3';
import { twMerge } from 'tailwind-merge';

import { ColorSet } from '../../Chart';
import { useChartContext } from '../../ChartProvider/ChartProvider';
import { InteractionMeta, Point, Shape } from '../../types';
import {
  CategoryAxisScale,
  LinearAxisScale,
  LogAxisScale,
  TimeAxisScale,
} from '../../util';
import { calculateXOffset, calculateXPosition } from '../../util/margins';
import { isPlotFocused } from '../../util/plot';

export interface LineExtras {
  className?: string;
  hasDots?: boolean;
  dotComponent?: Shape;
  hasLeading?: boolean;
  hasTrailing?: boolean;
}

/** @deprecated */
export const Line: Shape<LineExtras> = (props) => {
  const {
    data,
    xAccessor,
    yAccessor,
    className,
    hasLeading,
    hasTrailing,
    getColor,
    plotId,
  } = props;
  const { chartMeta } = useChartContext() ?? {};
  const xScale = chartMeta?.xScale as CategoryAxisScale | TimeAxisScale;
  const yScale = chartMeta?.yScale as LinearAxisScale | LogAxisScale;

  const getX = xAccessor ?? chartMeta?.xAccessor;
  const getY = yAccessor ?? chartMeta?.yAccessor;

  if (!getX || !getY) {
    throw new Error('Lines require an x and y accessor');
  }

  const xOffset = calculateXOffset(xScale);

  const keyLineCoordinates: Point[] = (data ?? [])?.map((item: unknown) => {
    const xCoordinate = xScale.scale(getX(item)) ?? 0;
    const yCoordinate = yScale.scale(getY(item)) ?? 0;

    return [xCoordinate + xOffset, yCoordinate];
  });

  const leadingLine: Point[] = [
    [chartMeta?.margin?.left ?? 0, keyLineCoordinates[0][1] ?? chartMeta?.plotHeight],
    keyLineCoordinates[0],
  ];

  const lastPoint: Point = keyLineCoordinates[keyLineCoordinates.length - 1];
  const trailingLine: Point[] = [
    lastPoint,
    [chartMeta?.plotWidth ?? 0, lastPoint[1] ?? chartMeta?.plotHeight ?? 0],
  ];

  const lineClass = cx(
    'fill-transparent transition-all',
    createLineClassNames(
      getColor(),
      isPlotFocused(chartMeta?.focusPlotId, plotId),
      chartMeta?.interactionItem?.plotId === plotId,
    ),
    className,
  );

  return (
    <g
      filter={chartMeta?.interactionItem?.plotId === plotId ? 'url(#glow)' : undefined}
    >
      {hasLeading && (
        <path d={line()(leadingLine) ?? undefined} className={lineClass} />
      )}
      <path d={line()(keyLineCoordinates) ?? undefined} className={lineClass} />
      {hasTrailing && (
        <path d={line()(trailingLine) ?? undefined} className={lineClass} />
      )}
    </g>
  );
};

Line.shapeName = 'Line';
/**
 * Positions tooltip at it's top left on the line
 *
 */
Line.getInteractionMeta = ({ chartMeta }): InteractionMeta => {
  const xOffset = chartMeta ? calculateXOffset(chartMeta?.xScale) : 0;
  return {
    tooltipX: { at: 'left', offset: xOffset },
    tooltipY: { at: 'top', offset: 0 },
  };
};

Line.getInteractionPoints = ({ chartMeta, plot, item }) => {
  const xOffset = calculateXPosition(chartMeta?.xScale, false, 0);
  const xCoordinate =
    (chartMeta?.xScale.scale(plot.xAccessor(item)) ?? 0) + xOffset / 2;
  const yCoordinate = chartMeta?.yScale.scale(plot.yAccessor(item)) ?? 0;

  return [
    {
      plotName: plot.name,
      plotId: plot.id,
      fullItem: item,
      shape: plot.shape,
      point: [xCoordinate, yCoordinate],
    },
  ];
};

const createLineClassNames = (
  colorSet: ColorSet,
  focused: boolean,
  interaction: boolean,
) => {
  let extraClasses: string | undefined = '';
  if (focused && interaction) {
    extraClasses = colorSet.strokeInteract;
  }

  if (focused && !interaction) {
    extraClasses = colorSet.focused;
  }

  if (!focused) {
    extraClasses = colorSet.unfocused;
  }

  return twMerge(colorSet.stroke, extraClasses);
};
