import { useCallback } from 'react';
import type { Placement } from '@floating-ui/react';

import { BaseButton, ButtonType } from '../Button/BaseButton.internal';
import { getIconProps } from '../Icon/helpers';
import { Icon } from '../Icon/Icon';
import type { MenuButtonProps } from '../MenuButton/MenuButton';
import type { Ryecon } from '../ryecons/types';
import { Tooltip } from '../Tooltip';
import { Sizes, SizeType } from '../types';
import {
  iconButtonClassNames,
  IconButtonStyleType,
} from './iconButtonClassNames.internal';

export type IconButtonPropTypes = ButtonType;

interface BaseIconButtonProps {
  /** Accessible label for the button: optional for backward compatibility, will be required soon */
  label?: string;

  ryecon: Ryecon;

  /** Class to apply to icon (e.g. animate-spin) */
  iconClassname?: string;

  /** The button functionality type */
  buttonType?: ButtonType;

  /** The button size */
  size?: SizeType;

  /** Custom button classnames */
  className?: string;

  /** An Onclick handler function */
  onClick?(event: React.MouseEvent): void;

  /** A boolean representing whether the button is disabled */
  isDisabled?: boolean;

  /** Define the icon button style */
  styleType?: IconButtonStyleType;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** An optional tooltip */
  tooltip?: React.ReactNode;

  /**
   * Controls where a tooltip is placed in relation to the target.
   * If not provided, tooltip will default to `autoPlacement`
   */
  tooltipPlacement?: Placement;

  /** If specified, clicking this button will open a menu */
  menu?: MenuButtonProps;
}

/**
 * @deprecated Use Button instead. Size and type props handle styling. All interactive states are baked in.
 */
export type IconButtonProps = BaseIconButtonProps;

/**
 * @deprecated Use Button instead. Size and type props handle styling. All interactive states are baked in.
 */
export const IconButton: React.FC<IconButtonProps> = ({
  ryecon,
  iconClassname,
  label,
  className,
  size = Sizes.md,
  onClick,
  isDisabled,
  buttonType = 'button',
  styleType = 'none',
  testId = 'icon-button',
  trackingId = 'icon-button',
  tooltip = null,
  tooltipPlacement,
}): React.ReactElement => {
  const handleClick = useCallback(
    (e: React.MouseEvent) => {
      if (onClick && !isDisabled) {
        onClick(e);
      }
    },
    [onClick, isDisabled],
  );

  const classNames = iconButtonClassNames({ className, isDisabled, size, styleType });

  const iconProps = getIconProps({ className: iconClassname, size }, { ryecon });

  const button =
    styleType === 'none' ? (
      <button
        type={buttonType}
        className={classNames}
        onClick={handleClick}
        disabled={isDisabled}
        data-testid={testId}
        data-trackingid={trackingId}
        aria-label={label}
      >
        {<Icon {...iconProps} />}
      </button>
    ) : (
      <BaseButton
        ariaLabel={label}
        buttonType={buttonType}
        className={classNames}
        isDisabled={isDisabled}
        ryecon={ryecon}
        iconClassname={iconClassname}
        isRounded={true}
        onClick={handleClick}
        size={Sizes[size]}
        testId={testId}
        trackingId={trackingId}
      />
    );

  if (tooltip) {
    const placementProps = tooltipPlacement
      ? { placement: tooltipPlacement }
      : { autoPlacement: true };
    return (
      <Tooltip childrenAreInteractive content={tooltip} {...placementProps}>
        {button}
      </Tooltip>
    );
  }
  return button;
};
