import { type FC, useEffect, useState } from 'react';
import cx from 'classnames';

import { Switch } from '@/externals/headlessui';
import { Controller, useFormContext } from '@/externals/react-hook-form';
import { BaseInputProps } from '../../../globalTypes';
import { get } from '../../../utils';
import { HelpIcon } from '../../HelpIcon';
import { RyeconCheckmark } from '../../ryecons';
import { FormFieldMessage } from '../FormFieldMessage/FormFieldMessage';

interface CustomToggleProps {
  name: string;

  /** @deprecated Toggle only has one size now. */
  size?: 'sm' | 'md' | 'lg';

  /** Display (View-Only) Content */
  children?: React.ReactNode;

  /** Description Text */
  description?: React.ReactNode;

  /** Boolean representing that the toggle should start enabled. For use in standalone toggles only.
   * For setting defaults in react-hook-form, use the defaultValues object passed to useForm instead. */
  defaultEnabled?: boolean;

  /** Custom onChange handler. Allows for extra handling past the default react-hook-form usage */
  onChange?(checked: boolean): void;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;
}

export type ToggleProps = BaseInputProps & CustomToggleProps;

const ToggleInternal: FC<ToggleProps> = ({
  children,
  label,
  description,
  className,
  defaultEnabled = false,
  helpLink,
  onHelpClick,
  onChange,
  error,
  isDisabled,
  isEdit = false,
  testId = 'toggle',
  trackingId = 'toggle',
  name,
}) => {
  const [isTurnedOn, setIsTurnedOn] = useState(defaultEnabled);

  useEffect(() => {
    if (defaultEnabled !== isTurnedOn) {
      setIsTurnedOn(defaultEnabled);
    }
  }, [setIsTurnedOn, isTurnedOn, defaultEnabled]);

  const hasCustomViewOnly = !!children;
  const shouldHaveStandardStyles = !error && isEdit && !isDisabled;
  const shouldHaveErrorStyles = !!error && isEdit && !isDisabled;
  const shouldHaveDisabledStyles = isDisabled || !isEdit;

  const toggleClasses = cx(
    'focus:ring-offset-bgMain relative inline-flex h-5 w-10 flex-shrink-0 rounded-full border transition-colors duration-200 ease-in-out focus:outline-none focus:ring-2 focus:ring-offset-2',
    {
      'cursor-not-allowed': shouldHaveDisabledStyles,
      'cursor-pointer': shouldHaveStandardStyles,
      'border-borderDanger focus:ring-focusDanger': shouldHaveErrorStyles,
      'focus:ring-focusBrand': !shouldHaveErrorStyles,
      'bg-bgDuotoneDanger': isTurnedOn && shouldHaveErrorStyles,
      'border-borderDisabled bg-bgDisabled': isTurnedOn && shouldHaveDisabledStyles,
      'border-borderDisabled bg-bgMain': !isTurnedOn && shouldHaveDisabledStyles,
      'bg-bgBrandSelection hover:bg-bgBrandSelectionHover border-borderBrand':
        isTurnedOn && shouldHaveStandardStyles,
      'border-borderMain bg-bgMain hover:bg-bgMainHover hover:border-borderMainHover':
        !isTurnedOn && shouldHaveStandardStyles,
    },
  );

  return (
    <div
      className={className}
      data-testid={`${testId}-wrapper`}
      data-trackingid={`${trackingId}-wrapper`}
    >
      <Switch.Group as="div" className="flex items-start">
        {(isEdit || !hasCustomViewOnly) && (
          <Switch
            data-testid={testId}
            data-trackingid={trackingId}
            checked={isTurnedOn}
            onChange={(value) => {
              if (onChange) {
                onChange(value);
              }
              setIsTurnedOn(value);
            }}
            disabled={isDisabled || !isEdit}
            className={toggleClasses}
          >
            <span aria-hidden className="pointer-events-none absolute inset-0.5">
              <RyeconCheckmark
                className={cx('absolute left-1 top-[0.0625rem] h-3 w-3', {
                  hidden: !isTurnedOn,
                  'text-fgWhite': !shouldHaveDisabledStyles,
                  'text-fgDisabled': shouldHaveDisabledStyles,
                })}
                height={12}
                width={12}
              />
              <span
                className={cx(
                  'absolute left-0 top-0 h-3.5 w-3.5 transform rounded-full shadow ring-0 transition duration-200 ease-in-out',
                  {
                    'translate-x-0': !isTurnedOn,
                    'translate-x-5': isTurnedOn,
                    'bg-bgInverseActive': !isTurnedOn && !shouldHaveDisabledStyles,
                    'bg-bgWhite': isTurnedOn && !shouldHaveDisabledStyles,
                    'bg-fgDisabled': shouldHaveDisabledStyles,
                  },
                )}
              />
            </span>
          </Switch>
        )}
        <Switch.Label
          as="span"
          className={cx({ 'ml-3': isEdit || !hasCustomViewOnly })}
        >
          {!!label && (
            <div
              className={cx('font-label-lg flex', {
                'text-fgAlt': !error && !isDisabled,
                'text-fgDanger': shouldHaveErrorStyles,
                'text-fgDecorative cursor-not-allowed': shouldHaveDisabledStyles,
                'cursor-pointer': shouldHaveStandardStyles,
              })}
            >
              {label}
              {Boolean(helpLink) && !onHelpClick && (
                <HelpIcon className="ml-1 flex items-center" linkTo={helpLink} />
              )}
              {!helpLink && onHelpClick && (
                <HelpIcon className="ml-1 flex items-center" onClick={onHelpClick} />
              )}
            </div>
          )}
          <FormFieldMessage
            name={name}
            description={description}
            errorMessage={error}
            isEdit={isEdit}
            testId={testId}
            trackingId={trackingId}
          />
        </Switch.Label>
      </Switch.Group>
      {!isEdit && hasCustomViewOnly && (
        <div
          data-testid={`${testId}-display`}
          data-trackingid={`${trackingId}-display`}
        >
          {children}
        </div>
      )}
    </div>
  );
};

export const Toggle: React.FC<ToggleProps> = (props) => {
  const { defaultEnabled, name, onChange: providedOnChange, error } = props;
  const formContext = useFormContext();
  const errors = formContext?.formState.errors;
  const errorMessage = get(errors && errors, name)?.message ?? error;

  return (
    <>
      {!!formContext?.control && (
        <Controller
          control={formContext.control}
          name={name}
          render={({ field: { onChange: hookFormChange, value } }) => {
            return (
              <ToggleInternal
                {...props}
                error={errorMessage}
                defaultEnabled={defaultEnabled ?? value}
                onChange={(value) => {
                  if (providedOnChange && value !== undefined) {
                    providedOnChange(value);
                  }
                  hookFormChange(value);
                }}
              />
            );
          }}
        />
      )}
      {!formContext?.control && <ToggleInternal {...props} />}
    </>
  );
};
