import classNames from 'classnames';

import { FileTreeItem } from './FileTreeItem';
import { NodeDataProps, TreeNodeValues } from './types';

export type FileTreeItemWrapperProps = {
  /**
   * Data for the file or folder
   */
  data: NodeDataProps;
  isDragging?: boolean;
  isHighlighted?: boolean;
  isOver?: boolean;
  isOpen?: boolean;
  isReadOnly?: boolean;
  isProjectRoot?: boolean;
  hideInlineFileActions?: boolean;
  showExpandButton?: boolean;
  showExpandButtonOnHover?: boolean;
  onClick: (
    e: React.MouseEvent<HTMLButtonElement, MouseEvent>,
    data: TreeNodeValues,
    isExpandButtonClick?: boolean,
  ) => void;
};

export const DefaultFileTreeItemWrapper = ({
  data,
  isDragging = false,
  isHighlighted = false,
  isOver = false,
  isReadOnly = false,
  isOpen = false,
  isProjectRoot = false,
  hideInlineFileActions = false,
  showExpandButton = false,
  showExpandButtonOnHover = false,
  onClick,
}: FileTreeItemWrapperProps) => {
  return (
    <div
      data-testid="DefaultFileTreeItemWrapper"
      className={classNames(isOver ? 'bg-bgMainHover' : '')} // same as each item's hover state
      style={{
        opacity: isDragging ? 0.5 : 1,
        paddingLeft: data.depth * 8,
      }}
    >
      <FileTreeItem
        node={data}
        isOpen={isOpen}
        isReadOnly={isReadOnly}
        onClick={onClick}
        isHighlighted={isHighlighted}
        hideInlineFileActions={hideInlineFileActions}
        isProjectRoot={isProjectRoot}
        showExpandButton={showExpandButton}
        showExpandButtonOnHover={showExpandButtonOnHover}
      />
    </div>
  );
};
