import cx from 'classnames';

interface BodyProps {
  /** If the text should be bold */
  bold?: boolean;
  /** The text to render */
  children: string;
  /** The boldness of the text */
  fontWeight?: 100 | 200 | 300 | 400 | 500 | 600 | 700 | 800 | 900;
  /** The size of text to render */
  size?: 'xs' | 'sm' | 'md' | 'lg';
  /** An optional testId for cypress */
  testId?: string;
  /** class overrides to add to <p> */
  className?: string;
}

const fontSizeClasses = {
  xs: 'font-body-sm',
  sm: 'font-body-sm',
  md: 'font-body',
  lg: 'font-body-lg',
};

export const Body = ({
  bold,
  children,
  fontWeight = 400,
  size = 'md',
  testId,
  className = '',
}: BodyProps) => (
  <p
    className={cx(
      fontSizeClasses[size],
      {
        'font-thin': !bold && fontWeight === 100,
        'font-extralight': !bold && fontWeight === 200,
        'font-light': !bold && fontWeight === 300,
        'font-normal': !bold && fontWeight === 400,
        'font-medium': !bold && fontWeight === 500,
        'font-semibold': bold || fontWeight === 600,
        'font-bold': !bold && fontWeight === 700,
        'font-extrabold': !bold && fontWeight === 800,
        'font-black': !bold && fontWeight === 900,
      },
      className,
    )}
    data-testid={testId}
  >
    {children}
  </p>
);
