import { HTMLProps } from 'react';
import cx from 'classnames';
type HeadingSize = '1' | '2' | '3' | '4' | '5' | '6';
type HeadingComponent = 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6';

interface HeadingProps {
  /** The text to render */
  children: string;
  /** Component tag override.  Perhaps you want the font size to be h4 but the component to be a <p/> */
  component?: HeadingComponent;
  /** The size of header to render */
  size?: HeadingSize;
  /** An optional testId for cypress */
  testId?: string;
}

interface NativeHProps extends HTMLProps<HTMLHeadingElement> {
  children: string;
  className: string;
  'data-testid'?: string;
}

const headingFontClasses: Record<HeadingSize, string> = {
  1: 'font-heading-1',
  2: 'font-heading-2',
  3: 'font-heading-3',
  4: 'font-heading-4',
  5: 'font-heading-5',
  6: 'font-heading-6',
};

const componentMap: Record<HeadingComponent, React.FC<NativeHProps>> = {
  h1: ({ children, ...others }: NativeHProps) => <h1 {...others}>{children}</h1>,
  h2: ({ children, ...others }: NativeHProps) => <h2 {...others}>{children}</h2>,
  h3: ({ children, ...others }: NativeHProps) => <h3 {...others}>{children}</h3>,
  h4: ({ children, ...others }: NativeHProps) => <h4 {...others}>{children}</h4>,
  h5: ({ children, ...others }: NativeHProps) => <h5 {...others}>{children}</h5>,
  h6: ({ children, ...others }: NativeHProps) => <h6 {...others}>{children}</h6>,
};

const componentFromSize: Record<HeadingSize, HeadingComponent> = {
  1: 'h1',
  2: 'h2',
  3: 'h3',
  4: 'h4',
  5: 'h5',
  6: 'h6',
};

export const Heading = ({ children, component, size = '1', testId }: HeadingProps) => {
  const Component = componentMap[component || componentFromSize[size]];

  return (
    <Component
      className={cx(headingFontClasses[size], 'text-fgMain')}
      data-testid={testId}
    >
      {children}
    </Component>
  );
};
