import { Link, LinkProps } from 'react-router-dom';
import cx from 'classnames';

import { SourdoughComponent } from '../../globalTypes';
import { IconText, type IconTextProps } from '../elements/IconText/IconText';
import {
  TextSubtext,
  type TextSubtextProps,
} from '../elements/TextSubtext/TextSubtext';
import { Checkbox, CheckboxProps } from '../forms/Checkbox';
import { Icon, type StatusIconVariant } from '../Icon';
import { getIconProps } from '../Icon/helpers';
import { isIconProps, isRyeconIconProps } from '../Icon/helpers.internal';
import { IconButton, type IconButtonProps } from '../IconButton/IconButton';
import { LoadingBlock } from '../LoadingBlock/LoadingBlock';
import { MenuButton, type MenuButtonProps } from '../MenuButton/MenuButton';
import { RyeconEllipsisHorizontal, RyeconSpinner } from '../ryecons';
import type { Ryecon } from '../ryecons/types';
import { Tooltip, type TooltipProps } from '../Tooltip';
import type { SizeType } from '../types';
import type { ListProps, ListSkeletonFeatures } from './List';

export interface ListActions extends Omit<IconButtonProps, 'onClick'> {
  onClick?(id: number | string): void;
}

export interface ListItemProps extends SourdoughComponent {
  /** unique identifier for list item */
  id: number | string;

  /** Text for the list item */
  text?: React.ReactNode;

  /** Text that comes after the 'text' title */
  trailingText?: React.ReactNode;

  /** Text that comes under the 'text' title */
  description?: React.ReactNode;

  /** A tooltip for the main list item icon */
  iconTooltip?: Omit<TooltipProps, 'children'>;

  /** Icon color class names */
  iconColorClassName?: string;

  /** Icon color variant, use for default colors */
  statusIconVariant?: StatusIconVariant;

  ryecon?: Ryecon;

  /** Link to link the overall item to */
  link?: LinkProps & React.RefAttributes<HTMLAnchorElement>;

  /** A list of items to show below the main text */
  meta?: IconTextProps[];

  /** Trailing text, shown at the end of a list item (right side) */
  trailingInfo?: TextSubtextProps;

  /** Per row actions */
  actions?: ListActions[];

  /** Per row context menu */
  contextMenu?: MenuButtonProps;

  /** Feature to show as skeleton */
  skeletonFeatures?: ListProps['skeletonFeatures'];

  /** Click handler for the list item */
  onClick?: (id: number | string) => void;

  /** Checkbox configuration for the list item */
  checkbox?: CheckboxProps;
}

const shouldSkeletonFeature = (
  feature: ListSkeletonFeatures,
  all: ListItemProps['skeletonFeatures'] | undefined,
  skeleton: boolean | undefined,
): boolean => {
  if (!skeleton) {
    return false;
  }

  if (!all) {
    return true;
  }

  return !!all[feature];
};

/**
 * skeletonFeatures can have icon | ryecon
 * and each can be boolean or IconProperty | Ryecon respectively
 */
type SkeletonIconConfig = {
  ryecon?: Ryecon;
};
const getSkeletonIcon = (
  skeleton?: boolean,
  skeletonFeatures?: ListItemProps['skeletonFeatures'],
): SkeletonIconConfig => {
  const noSkeletonConfig = { ryecon: undefined };
  // neither provided
  if (skeleton === false || !skeletonFeatures?.ryecon) {
    return noSkeletonConfig;
  }

  // should skeleton at this point
  // figure out if we need to default to a spinner

  const { ryecon } = skeletonFeatures;
  // default to spinner
  if (ryecon === true) {
    return { ryecon: RyeconSpinner };
  }

  // icon or ryecon provided
  if (ryecon) {
    return { ryecon: ryecon as Ryecon };
  }

  return noSkeletonConfig;
};

const skeletonMeta = {
  text: '',
  skeleton: true,
};

export const ListItemInternals: React.FC<ListItemProps> = ({
  id,
  text,
  trailingText,
  description,
  meta,
  iconColorClassName,
  statusIconVariant,
  ryecon,
  iconTooltip = { content: undefined },
  trailingInfo,
  actions = [],
  skeleton,
  skeletonFeatures,
  contextMenu,
  checkbox,
}) => {
  const metaMarkup = (skeleton ? new Array(2).fill(skeletonMeta) : meta ?? []).map(
    (item, index) => (
      <IconText
        key={`${id}-${index}`}
        {...item}
        testId={item.testId ?? `list-item-meta-${index}`}
        trackingId={item.trackingId ?? item.testId ?? 'list-item-meta'}
        size={item.size ?? 'sm'}
        className={cx(item.className, 'relative z-[1] mr-3')}
        textClassname="truncate text-fgDecorative"
        iconClassname="text-fgAlt"
        skeleton={shouldSkeletonFeature('meta', skeletonFeatures, skeleton)}
      />
    ),
  );

  const handleActionClick = (onClick: (id: number | string) => void) => {
    onClick(id);
  };

  const iconSkelConfig = getSkeletonIcon(skeleton, skeletonFeatures);
  const isSkeletonIcon = !!iconSkelConfig.ryecon;
  const isRyeconSpinner =
    iconSkelConfig.ryecon && iconSkelConfig.ryecon.displayName === 'RyeconSpinner';
  const iconProps = getIconProps(
    {
      className: cx('pointer-events-none relative z-[1]', iconColorClassName, {
        'animate-spin': isRyeconSpinner,
        'text-fgDisabled': skeleton,
      }),
      size: 'md' as SizeType,
    },
    {
      statusIconVariant,
      ryecon: isSkeletonIcon ? iconSkelConfig.ryecon : ryecon,
    },
  );
  const showIcon = isIconProps(iconProps);

  return (
    <div className="flex items-center justify-between">
      <div
        className={cx('flex flex-grow gap-2 self-start truncate', {
          'items-center': !trailingInfo && !meta && !skeleton,
        })}
      >
        {checkbox && (
          <div className="relative z-[1] -mt-0.5 flex-shrink-0 self-start">
            <Checkbox
              {...checkbox}
              testId={checkbox.testId || `list-item-${id}-checkbox`}
              name={checkbox.name || `checkbox-${id}`}
              isEdit={checkbox.isEdit ?? true}
            />
          </div>
        )}
        {showIcon && (
          <div
            className={cx('relative z-[1] flex-shrink', {
              'inline-flex items-center': !trailingInfo && !meta && !skeleton,
              'pt-[1px]': !!trailingInfo || !!meta || !!skeleton,
            })}
          >
            <Tooltip {...iconTooltip} className="flex items-center" portal>
              <Icon {...iconProps} />
            </Tooltip>
          </div>
        )}
        <div className="flex flex-col truncate">
          <div className="text-fgMain font-body pointer-events-none z-[1] truncate font-medium">
            {shouldSkeletonFeature('title', skeletonFeatures, skeleton) ? (
              <LoadingBlock width={250} height={25} />
            ) : (
              <>
                <span className="font-medium">{text}</span>
                {trailingText && (
                  <span
                    className={cx('text-fgDecorative', {
                      'ml-1.5': text,
                    })}
                  >
                    {trailingText}
                  </span>
                )}
              </>
            )}
          </div>
          {!!description && (
            <p className="text-fgDecorative font-caption pointer-events-none z-[1] truncate">
              {description}
            </p>
          )}
          {((!skeleton && !!metaMarkup.length) ||
            shouldSkeletonFeature('meta', skeletonFeatures, skeleton)) && (
            <div className="flex pt-1" data-testid="list-item-meta">
              {metaMarkup}
            </div>
          )}
        </div>
      </div>
      {shouldSkeletonFeature('trailing', skeletonFeatures, skeleton) && (
        <TextSubtext
          className="z-[1] hidden self-start text-right sm:flex"
          textClassName="truncate"
          subtext="loading"
          skeleton
        />
      )}
      {!!trailingInfo && (
        <TextSubtext
          {...trailingInfo}
          className={cx(
            trailingInfo.className,
            'z-[1] hidden self-start text-right sm:flex',
          )}
          textClassName={cx(trailingInfo.textClassName, 'truncate')}
        />
      )}
      {!!actions.length && (
        <div className="ml-5 flex self-start">
          {actions.map((action, index) => {
            if (!isRyeconIconProps(action)) {
              return null;
            }
            return (
              <IconButton
                {...action}
                onClick={(e) => {
                  e.stopPropagation();
                  action.onClick && handleActionClick(action.onClick);
                }}
                isDisabled={skeleton}
                key={index}
                className={cx(
                  'text-fgDecorative relative z-[1] ml-5 first:ml-0',
                  action.className,
                )}
                size="sm"
              />
            );
          })}
        </div>
      )}
      {!!contextMenu && (
        <MenuButton
          buttonStyle="icon-button"
          buttonVariant={{
            variant: 'ryecon',
            ryecon: RyeconEllipsisHorizontal,
            tooltip: '',
          }}
          menuAlignment="right"
          testId="list-item-context-menu"
          {...contextMenu}
          onMenuToggleClick={(e) => {
            e.stopPropagation();
            contextMenu.onMenuToggleClick && contextMenu.onMenuToggleClick(e);
          }}
          className={cx('ml-5 mt-1', contextMenu.className)}
        />
      )}
    </div>
  );
};

export const ListItem: React.FC<ListItemProps> = (props) => {
  const clickableClasses =
    'focus-visible:outline-borderBrand hover:bg-bgMainHover active:bg-bgMainActive group-hover/item:bg-bgMainHover';

  return (
    <li
      className={cx('transition-color group/item relative p-1 sm:p-3', {
        [cx(clickableClasses, 'cursor-pointer')]: props.onClick,
      })}
      data-testid={props.testId}
      onClick={() => props.onClick?.(props.id)}
    >
      {!!props.link && (
        <Link
          {...props.link}
          className={cx(
            clickableClasses,
            'absolute inset-0 z-[0] block focus-visible:z-[1]',
          )}
        />
      )}
      <ListItemInternals {...props} />
    </li>
  );
};
