import { createContext, PropsWithChildren, useContext, useMemo, useRef } from 'react';
import { useState } from 'react';
import { Menu } from '@headlessui/react';

import { useOnClickOutside } from '../../hooks';
import { MenuItems, MenuItemsProps } from '../MenuItems';

export interface ContextMenuContextProps {
  currentId: string | null;
  updateCurrentId: (menuId: string | null) => void;
}

const ContextMenuContext = createContext<ContextMenuContextProps | null>(null);

// The main wrapping component, creates the context and sets up state, handles scroll detection
export const ContextMenuProvider: React.FC<PropsWithChildren<{}>> = ({ children }) => {
  const [currentId, updateCurrentId] = useState<string | null>(null);

  const context: ContextMenuContextProps = { currentId, updateCurrentId };

  return (
    <ContextMenuContext.Provider value={context}>
      {children}
    </ContextMenuContext.Provider>
  );
};

interface MenuState {
  /**
   * Will only render the ContextMenu if isOpen is true.
   */
  isOpen: boolean;

  /**
   * Calling this should update the `isOpen` state to `false`.
   */
  close: () => void;

  /**
   * Calling this should update the `isOpen` state to `true`.
   */
  open: (mouseEvent: React.MouseEvent) => void;

  /**
   * If a mouseEvent is passed in, the ContextMenu will be
   * rendered relative to the mouseEvent rather than source
   * component.
   */
  mouseEvent: React.MouseEvent | null;
}

interface ContextMenuProps extends MenuItemsProps, ContextMenuHookParams {
  /**
   * If the user right-clicks on the children, the ContextMenu
   * will be opened.
   */
  children?: React.ReactNode;

  /**
   * Defaults to `true`. If explicitly overridden, you can prevent
   * portaling and render this UI element in place.
   */
  shouldPortal?: boolean;

  /** Enable additional logging */
  debug?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** For targeting the wrapper span which captures right-click */
  rightClickTarget?: React.DetailedHTMLProps<
    React.HTMLAttributes<HTMLSpanElement>,
    HTMLSpanElement
  >;
}

interface ClickOutsideParams {
  close: () => void;
  menuRef: React.RefObject<HTMLDivElement | null>;
}

/**
 * As a performance optimization, we're pulling this hook
 * into a component we can optionally render only when the
 * ContextMenu is open.
 */
const ClickOutsideHandler: React.FC<ClickOutsideParams> = ({ close, menuRef }) => {
  useOnClickOutside({
    isOpen: true,
    onClick: close,
    ref: menuRef,
  });

  return <></>;
};

const ContextMenuWithStateParams = ({
  stateOverride,
  testId = 'context-menu',
  trackingId = 'context-menu',
  children,
  rightClickTarget,
  ...props
}: PropsWithChildren<
  ContextMenuProps & {
    stateOverride: MenuState;
  }
>) => {
  const { shouldPortal = true } = props;
  const menuRef = useRef<HTMLDivElement | null>(null);
  const menuContents = stateOverride.isOpen && (
    <Menu>
      <MenuItems
        {...props}
        ref={menuRef}
        shouldPortal={shouldPortal}
        testId={`${testId}-options`}
        trackingId={`${trackingId}-options`}
        stateOverride={stateOverride}
        alignment={'auto'}
        targetPosition={
          stateOverride.mouseEvent
            ? {
                x: stateOverride.mouseEvent.clientX,
                y: stateOverride.mouseEvent.clientY,
              }
            : undefined
        }
      />
    </Menu>
  );
  return (
    <>
      {stateOverride.isOpen && (
        <ClickOutsideHandler close={stateOverride.close} menuRef={menuRef} />
      )}
      <span
        {...rightClickTarget}
        onContextMenu={(mouseEvent) => {
          mouseEvent.preventDefault();
          stateOverride.open(mouseEvent);
          mouseEvent.stopPropagation();
        }}
      >
        {children}
      </span>
      {menuContents}
    </>
  );
};

/**
 * Use {@link useContextMenu} if you would prefer to have access
 * to the open/close state logic.
 */
export const ContextMenu = (props: PropsWithChildren<ContextMenuProps>) => {
  const contextMenu = useContextMenu(props);
  return <contextMenu.ContextMenu {...props} />;
};

interface ContextMenuHookParams {
  /**
   * A unique ID is required for each ContextMenu to handle a UI with multiple context menus.
   */
  menuId: string;
}

/**
 * Returns a `ContextMenu` component you can render and methods
 * you can use to interact with the menu's state.
 *
 * Should only be used inside
 */
export const useContextMenu = ({ menuId }: ContextMenuHookParams) => {
  const context = useContext(ContextMenuContext);
  const isOpen = context?.currentId === menuId;
  const updateIsOpen = useMemo(
    () => (shouldOpen: boolean) => {
      if (shouldOpen) {
        context?.updateCurrentId(menuId);
      } else if (context?.currentId === menuId) {
        context?.updateCurrentId(null);
      }
    },
    [context, menuId],
  );

  const [mouseEvent, updateMouseEvent] = useState<React.MouseEvent | undefined>(
    undefined,
  );
  const close = useMemo(
    () => () => {
      updateIsOpen(false);
      updateMouseEvent(undefined);
    },
    [updateIsOpen],
  );

  const stateManagement: MenuState = {
    isOpen,
    close,
    open: (mouseEvent: React.MouseEvent) => {
      if (!isOpen) {
        mouseEvent?.preventDefault();
        updateIsOpen(true);
      }
      updateMouseEvent(mouseEvent);
    },
    mouseEvent: mouseEvent ?? null,
  };

  const ContextMenuComponent: React.FC<
    Omit<ContextMenuProps, 'isOpen' | 'mouseEvent' | 'close' | 'menuId' | 'ref'>
  > = (props) => (
    <ContextMenuWithStateParams
      {...props}
      stateOverride={stateManagement}
      menuId={menuId}
    />
  );
  return {
    isOpen: stateManagement.isOpen,
    open: stateManagement.open,
    close: stateManagement.close,
    ContextMenu: ContextMenuComponent,
  };
};
