import type { BaseInputProps } from '../../../../sourdough';
import { Textarea } from '../../Textarea/Textarea';
import { usePillSubComponentContext } from '../context';
import { pillsToStr } from '../utils';

export type TextareaSubProps = BaseInputProps & {
  name: string;
  description?: string;
  placeholder?: string;
  className?: string;
  testId?: string;
  trackingId?: string;
};

export function TextareaSub({
  name,
  isEdit,
  placeholder = '',
  description,
  className,
  testId = 'pill-textarea',
  trackingId = 'pill-textarea',
  ...rest
}: TextareaSubProps) {
  const {
    handleChange,
    handleKeyDown,
    handleCompositionStart,
    handleCompositionEnd,
    pills,
    uncommitted,
  } = usePillSubComponentContext();
  return (
    <Textarea
      {...rest}
      name={name}
      description={description}
      isEdit={isEdit}
      placeholder={placeholder}
      value={uncommitted}
      onChange={handleChange}
      onKeyDown={handleKeyDown}
      onCompositionStart={handleCompositionStart}
      onCompositionEnd={handleCompositionEnd}
      testId={testId}
      trackingId={trackingId}
      className={className}
    >
      {isEdit ? '' : pillsToStr(pills, ', ', uncommitted)}
    </Textarea>
  );
}
