import { useCallback, useEffect, useRef, useState } from 'react';
import React from 'react';

import { Dialog, Transition } from '@/externals/headlessui';

export interface DrawerProps {
  /** A boolean to determine whether the drawer is open */
  isOpen: boolean;

  /** Event handler for close button click */
  onClose: () => void;

  /** The content to display. Should be a `DrawerContent` component */
  children: (onClose: () => void) => React.ReactNode;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** If you set this to false, you can allow hidden children to render even when the panel is closed */
  shouldFreezeContents?: boolean;

  /** Enable drawer resizing functionality */
  resizable?: boolean;

  /** Width of the drawer in pixels */
  width?: number;

  /** Minimum width of the drawer in pixels when resizable */
  minWidth?: number;

  /** Maximum width of the drawer in pixels when resizable */
  maxWidth?: number;

  /**
   * Optional responsive default widths. When provided, the drawer will choose an initial width
   * based on the current viewport breakpoint. If the user manually resizes the drawer, that
   * size will take precedence until the drawer is closed and re-opened (unless persisted).
   */
  responsiveWidth?: Partial<Record<'base' | 'sm' | 'md' | 'lg' | 'xl' | '2xl', number>>;

  /**
   * Optional viewport edge offset (in pixels). This controls how close the drawer can get to
   * the left edge of the screen. Defaults to 64px.
   */
  edgeOffset?: number;

  /**
   * When enabled, clicking anywhere outside the drawer will call onClose. You can optionally
   * provide CSS selectors in `interactOutsideIgnoreSelectors` to ignore certain elements.
   */
  closeOnInteractOutside?: boolean;

  /** CSS selectors to ignore when `closeOnInteractOutside` is true. */
  interactOutsideIgnoreSelectors?: string[];

  /**
   * When true, allows full screen interaction without dismissing the drawer.
   * This disables the outside click behavior and allows clicks to pass through to elements behind the drawer.
   */
  allowFullScreenInteraction?: boolean;
}

export const Drawer: React.FC<DrawerProps> = ({
  isOpen,
  onClose,
  children,
  shouldFreezeContents = true,
  testId = 'drawer',
  trackingId = 'drawer',
  resizable = false,
  width = 600,
  minWidth = 300,
  maxWidth = 1200,
  responsiveWidth,
  edgeOffset = 64,
  closeOnInteractOutside = false,
  interactOutsideIgnoreSelectors = [],
  allowFullScreenInteraction = false,
}): React.ReactElement => {
  const [dialogIsOpen, setDialogIsOpen] = useState(isOpen);
  const [isResizing, setIsResizing] = useState(false);
  const [currentWidth, setCurrentWidth] = useState(
    Math.min(width, window.innerWidth - edgeOffset),
  );
  const [wasManuallyResized, setWasManuallyResized] = useState(false);
  const drawerRef = useRef<HTMLDivElement>(null);

  // Calculate viewport-aware constraints
  const getViewportConstraints = useCallback(() => {
    const maxViewportWidth = window.innerWidth - edgeOffset;
    return {
      effectiveMaxWidth: Math.min(maxWidth, maxViewportWidth),
      effectiveMinWidth: Math.min(minWidth, maxViewportWidth),
      effectiveWidth: Math.min(width, maxViewportWidth),
    };
  }, [maxWidth, minWidth, width, edgeOffset]);

  const getResponsiveDefaultWidth = useCallback((): number | null => {
    if (!responsiveWidth) return null;
    const viewport = window.innerWidth;
    // Tailwind-style breakpoints
    const breakpoints = {
      base: 0,
      sm: 640,
      md: 768,
      lg: 1024,
      xl: 1280,
      '2xl': 1536,
    } as const;

    const orderedBySizeDesc: Array<keyof typeof breakpoints> = [
      '2xl',
      'xl',
      'lg',
      'md',
      'sm',
      'base',
    ];
    const largestMatchingKey = orderedBySizeDesc.find(
      (key) =>
        viewport >= breakpoints[key] &&
        typeof responsiveWidth[key as keyof typeof responsiveWidth] === 'number',
    );
    const chosen: number | null = largestMatchingKey
      ? (responsiveWidth[largestMatchingKey] as number)
      : null;
    return chosen;
  }, [responsiveWidth]);

  const internalClassNames = 'fixed bottom-0 right-0 flex top-0';

  const startResizing = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsResizing(true);
  }, []);

  const stopResizing = useCallback(() => {
    setIsResizing(false);
    setWasManuallyResized(true);
  }, []);

  const resize = useCallback(
    (e: MouseEvent) => {
      if (isResizing) {
        const newWidth = window.innerWidth - e.clientX;
        const { effectiveMaxWidth, effectiveMinWidth } = getViewportConstraints();
        const constrainedWidth = Math.max(
          effectiveMinWidth,
          Math.min(effectiveMaxWidth, newWidth),
        );
        setCurrentWidth(constrainedWidth);
      }
    },
    [isResizing, getViewportConstraints],
  );

  // Update constraints when window resizes
  useEffect(() => {
    const handleResize = () => {
      const newConstraints = getViewportConstraints();
      setCurrentWidth((current) =>
        Math.max(
          newConstraints.effectiveMinWidth,
          Math.min(newConstraints.effectiveMaxWidth, current),
        ),
      );
      // If the user has not manually resized, also update to responsive default if provided
      if (!isResizing && !wasManuallyResized) {
        const responsiveDefault = getResponsiveDefaultWidth();
        if (typeof responsiveDefault === 'number') {
          const constrained = Math.max(
            newConstraints.effectiveMinWidth,
            Math.min(newConstraints.effectiveMaxWidth, responsiveDefault),
          );
          setCurrentWidth(constrained);
        }
      }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [
    getViewportConstraints,
    getResponsiveDefaultWidth,
    isResizing,
    wasManuallyResized,
  ]);

  useEffect(() => {
    if (isResizing) {
      window.addEventListener('mousemove', resize);
      window.addEventListener('mouseup', stopResizing);
      document.body.style.cursor = 'ew-resize';
      document.body.style.userSelect = 'none';

      return () => {
        window.removeEventListener('mousemove', resize);
        window.removeEventListener('mouseup', stopResizing);
        document.body.style.cursor = '';
        document.body.style.userSelect = '';
      };
    }
  }, [isResizing, resize, stopResizing]);

  useEffect(() => {
    if (isOpen) {
      setDialogIsOpen(true);
    }
  }, [isOpen]);

  // Update width when prop changes
  useEffect(() => {
    const { effectiveMaxWidth, effectiveMinWidth, effectiveWidth } =
      getViewportConstraints();
    // Priority: responsive default -> width prop
    const responsiveDefault = getResponsiveDefaultWidth();
    const next =
      typeof responsiveDefault === 'number' ? responsiveDefault : effectiveWidth;
    const constrained = Math.max(effectiveMinWidth, Math.min(effectiveMaxWidth, next));
    setCurrentWidth(constrained);
  }, [width, getViewportConstraints, getResponsiveDefaultWidth]);

  // Close on outside interaction, if enabled
  useEffect(() => {
    if (!closeOnInteractOutside || allowFullScreenInteraction) return;
    const handlePointerDown = (event: MouseEvent) => {
      const panelEl = drawerRef.current;
      const target = event.target as Element | null;
      if (!panelEl || !target) return;
      // Ignore clicks on specified selectors
      for (const selector of interactOutsideIgnoreSelectors) {
        try {
          if (target.closest(selector)) return;
        } catch {
          // invalid selector; ignore
        }
      }
      if (!panelEl.contains(target)) {
        onClose();
      }
    };
    document.addEventListener('mousedown', handlePointerDown, true);
    return () => document.removeEventListener('mousedown', handlePointerDown, true);
  }, [
    closeOnInteractOutside,
    interactOutsideIgnoreSelectors,
    allowFullScreenInteraction,
    onClose,
  ]);

  // Close on pressing Escape
  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        onClose();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, onClose]);

  return (
    <Transition.Root show={isOpen} as={React.Fragment}>
      {allowFullScreenInteraction ? (
        // When full screen interaction is allowed, render without Dialog wrapper
        <div className="pointer-events-none fixed inset-0 z-20">
          <div className="absolute inset-0 overflow-hidden">
            <div
              className={`${internalClassNames} pointer-events-auto`}
              data-testid={testId}
              data-trackingid={trackingId}
            >
              <Transition.Child
                as={React.Fragment}
                enter="transform transition ease-in-out duration-500"
                enterFrom="translate-x-full"
                enterTo="translate-x-0"
                leave="transform transition ease-in-out duration-500"
                leaveFrom="translate-x-0"
                leaveTo="translate-x-full"
                afterLeave={() => setDialogIsOpen(false)}
              >
                <div
                  ref={drawerRef}
                  className="shadow-hover bg-bgMain relative h-full"
                  style={{
                    width: `${currentWidth}px`,
                    transition: isResizing ? 'none' : undefined,
                  }}
                >
                  {resizable && (
                    <div
                      className="hover:bg-bgBrandHover active:bg-bgBrandActive border-borderMuted absolute left-0 top-0 z-10 h-full w-1 cursor-ew-resize border-l hover:border-0 active:border-0"
                      onMouseDown={startResizing}
                      onClick={(e) => e.stopPropagation()}
                    />
                  )}
                  <div className="h-full w-full">
                    {(dialogIsOpen || !shouldFreezeContents) && children(onClose)}
                  </div>
                </div>
              </Transition.Child>
            </div>
          </div>
        </div>
      ) : (
        // Normal Dialog behavior when full screen interaction is disabled
        <Dialog
          as="div"
          className="fixed inset-0 z-20 overflow-hidden"
          onClose={onClose}
          open={dialogIsOpen}
        >
          <div className="absolute inset-0 overflow-hidden">
            <div
              className={internalClassNames}
              data-testid={testId}
              data-trackingid={trackingId}
            >
              <Transition.Child
                as={React.Fragment}
                enter="transform transition ease-in-out duration-500"
                enterFrom="translate-x-full"
                enterTo="translate-x-0"
                leave="transform transition ease-in-out duration-500"
                leaveFrom="translate-x-0"
                leaveTo="translate-x-full"
                afterLeave={() => setDialogIsOpen(false)}
              >
                <Dialog.Panel
                  as="div"
                  ref={drawerRef}
                  className="shadow-hover bg-bgMain relative h-full"
                  style={{
                    width: `${currentWidth}px`,
                    transition: isResizing ? 'none' : undefined,
                  }}
                >
                  {resizable && (
                    <div
                      className="hover:bg-bgBrandHover active:bg-bgBrandActive border-borderMuted absolute left-0 top-0 z-10 h-full w-1 cursor-ew-resize border-l hover:border-0 active:border-0"
                      onMouseDown={startResizing}
                      onClick={(e) => e.stopPropagation()}
                    />
                  )}
                  <div className="h-full w-full">
                    {(dialogIsOpen || !shouldFreezeContents) && children(onClose)}
                  </div>
                </Dialog.Panel>
              </Transition.Child>
            </div>
          </div>
        </Dialog>
      )}
    </Transition.Root>
  );
};
