import type { Scale } from './scales';

/** @deprecated */
export const calculateXPosition = (
  scaleObj?: Scale<any, any>,
  limitMax: boolean = true,
  startAt: number = 0,
): number => {
  if (scaleObj?.kind === 'category') {
    const width = scaleObj.scale.bandwidth();
    return width > startAt && limitMax ? startAt : width;
  }
  return startAt;
};

/** @deprecated */
export const calculateXOffset = (
  xScale?: Scale<any, any>,
  startAt: number = 0,
): number => {
  const maxX = calculateXPosition(xScale, false, startAt) / 2;
  const marginX = calculateXPosition(xScale, true, startAt) / 2 || 0;
  return maxX - marginX;
};
