import { ReactNode } from 'react';
import cx from 'classnames';

import { AccordionBody } from './AccordionBody.internal';
import { AccordionHeader } from './AccordionHeader.internal';
import useAccordion from './useAccordion.internal';

export enum AccordionVariant {
  LOGS = 'logs',
  DEFAULT = 'default',
}
export interface AccordionProps {
  /** Any component.  It will be rendered on the right side of the header. */
  actions?: ReactNode;
  /** The content of the accordion */
  children?: ReactNode;
  /** If hasPermission is false, the accordion will not render */
  hasPermission?: boolean;
  /** An icon to display next to the caret open toggle button */
  icon?: ReactNode;
  /** If the accordion should render open by default */
  initialOpen?: boolean;
  /** Callback for when open is toggled */
  onToggleOpen?: (open: boolean) => void;
  /** Test id */
  testId?: string;
  /** The title text to show in the accordion header */
  title: ReactNode;
  /** The variant of the accordion content. Logs will add a gray background. Default will have a white background */
  variant?: AccordionVariant;
  /** A boolean representing whether the accordion is disabled */
  isDisabled?: boolean;
  /** A boolean for applying sticky css to the AccordionHeader */
  isSticky?: boolean;
}

const Accordion = ({
  actions,
  children,
  hasPermission = true,
  icon,
  initialOpen,
  onToggleOpen,
  testId = 'accordion',
  title,
  variant = AccordionVariant.DEFAULT,
  isDisabled = false,
  isSticky = false,
}: AccordionProps) => {
  const { contentHeight, contentRef, isOpen, toggleOpen } = useAccordion({
    initialOpen,
    onToggleOpen,
  });

  return hasPermission ? (
    <div data-testid={testId} className="overflow-clip">
      <AccordionHeader
        actions={actions}
        isOpen={isOpen}
        toggleOpen={toggleOpen}
        icon={icon}
        title={title}
        isDisabled={isDisabled}
        isSticky={isSticky}
      />
      <AccordionBody
        isOpen={isOpen}
        height={contentHeight}
        ref={contentRef}
        wrapperClassName={cx({
          'bg-bgBackground': variant === AccordionVariant.LOGS,
        })}
        className="p-2"
      >
        {children}
      </AccordionBody>
    </div>
  ) : null;
};

export { Accordion };
