import type { Placement } from '@floating-ui/react';
import cx from 'classnames';

import { Button, ButtonStyleType, Sizes } from '..';
import {
  type Ryecon,
  RyeconCheckmark,
  RyeconRerun,
  RyeconSave,
  RyeconSpinner,
} from '../ryecons';
import { Tooltip } from '../Tooltip';

export type SaveState = 'default' | 'saving' | 'success' | 'error';

export interface SaveButtonProps {
  /** Override the text to display in the default state */
  defaultText?: React.ReactNode;

  /** Override the save icon */
  defaultRyecon?: Ryecon;

  /** Override the text to display in the saving state */
  savingText?: React.ReactNode;

  /** Override the text to display in the success state */
  successText?: React.ReactNode;

  /** Override the text to display in the success state */
  errorText?: React.ReactNode;

  /** The button display state */
  state?: SaveState;

  /** The button size */
  size?: Sizes;

  /** Custom button classnames */
  className?: string;

  /** An Onclick handler function */
  onClick?(event: React.MouseEvent): void;

  /** A boolean representing whether the button is disabled */
  isDisabled?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** An optional tooltip */
  tooltip?: React.ReactNode;

  /**
   * Controls where a tooltip is placed in relation to the target.
   * If not provided, tooltip will default to `autoPlacement`
   */
  tooltipPlacement?: Placement;

  /** Should the tooltip use a portal */
  tooltipPortal?: boolean;

  /**
   * Use only in consultation with design!
   * 99.99% of the time, the default behavior is what you want.
   */
  initialButtonType?: Omit<ButtonStyleType, 'error' | 'success'>;
}

type StateMap = {
  [key in SaveState]: {
    type: ButtonStyleType;
    ryecon?: Ryecon;
    text: SaveButtonProps['defaultText'];
    disabled: boolean;
  };
};

export const SaveButton: React.FC<SaveButtonProps> = ({
  defaultText = 'Save',
  savingText = 'Saving',
  successText = 'Saved',
  errorText = 'Retry',
  state = 'default',
  defaultRyecon = RyeconSave,
  className,
  size = Sizes.md,
  onClick,
  isDisabled,
  testId = 'save-button',
  trackingId = 'save-button',
  tooltip = null,
  tooltipPortal = false,
  tooltipPlacement,
  initialButtonType = 'primary',
}): React.ReactElement => {
  const stateMap: StateMap = {
    default: {
      type: initialButtonType as ButtonStyleType,
      ryecon: defaultRyecon,
      text: defaultText,
      disabled: false,
    },
    saving: {
      type: initialButtonType as ButtonStyleType,
      ryecon: RyeconSpinner,
      text: savingText,
      disabled: true,
    },
    success: {
      type: 'success',
      ryecon: RyeconCheckmark,
      text: successText,
      disabled: true,
    },
    error: {
      type: 'error',
      ryecon: RyeconRerun,
      text: errorText,
      disabled: false,
    },
  };

  const { text, ryecon, type, disabled } = stateMap[state];

  const button = (
    <Button
      type={type as ButtonStyleType}
      text={text}
      ryecon={ryecon}
      iconClassname={cx({ 'animate-spin': state === 'saving' })}
      size={size}
      onClick={onClick}
      isDisabled={isDisabled || disabled}
      className={className}
      testId={testId}
      trackingId={trackingId}
    />
  );

  if (tooltip) {
    const placementProps = tooltipPlacement
      ? { placement: tooltipPlacement }
      : { autoPlacement: true };
    return (
      <Tooltip
        childrenAreInteractive
        portal={tooltipPortal}
        content={tooltip}
        {...placementProps}
      >
        {button}
      </Tooltip>
    );
  }
  return button;
};
