import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { getCoreRowModel, TableOptions, useReactTable } from '@tanstack/react-table';

import { BasicTable } from '../subcomponents/BasicTable';
import { VirtualTable } from '../subcomponents/VirtualTable';
import { DefaultTData, Header, SortingState } from '../types';
import { createLoadingColumns, createLoadingRows } from '../utils';
import { TableProps } from './types';

export const Table = <
  TData extends DefaultTData,
  TValue extends React.ReactNode = React.ReactNode,
>({
  columns,
  data,
  onChangeSort,
  onRowClickCustomHandler,
  initialSortColumn,
  initialSortDesc = false,
  loadingRowCount = 5,
  isLoading = false,
  isSortable = true,
  rowHeight,
  paginationProps,
  isWindowed,
  height,
  emptyStateProps,
  ...rest
}: TableProps<TData, TValue>): React.ReactElement => {
  const tableContainerRef = useRef<HTMLDivElement>(null);
  const memoizedColumns = useMemo(
    () => (isLoading ? createLoadingColumns<TData, TValue>(columns) : columns),
    [columns, isLoading],
  );
  const memoizedData = useMemo<TData[]>(() => {
    if (isLoading) {
      return createLoadingRows(loadingRowCount);
    } else if (paginationProps?.isPageLoading) {
      // if we're loading a new page, create a new page worth of loading rows
      return [...data, ...createLoadingRows<TData>(loadingRowCount)];
    }
    return data;
  }, [data, isLoading, paginationProps?.isPageLoading, loadingRowCount]);

  const initialSortId = useMemo(() => {
    if (!isSortable || !memoizedColumns.length) {
      return '';
    }
    if (initialSortColumn) {
      return initialSortColumn;
    }
    return memoizedColumns[0]?.id ?? '';
  }, [initialSortColumn, memoizedColumns, isSortable]);

  const initialSortingState = useMemo<SortingState>(
    () => (isSortable ? [{ id: initialSortId, desc: initialSortDesc }] : []),
    [isSortable, initialSortId, initialSortDesc],
  );
  const [sorting, setSorting] = useState<SortingState>(initialSortingState);

  // override column defaults so we can update column width manually
  const defaultColumn = {
    minSize: undefined,
    size: undefined,
    maxSize: undefined,
  };

  const handleSortingChange = useCallback(
    (getSortBy: any) => {
      if (onChangeSort && isSortable) {
        const newSortBy = getSortBy();
        setSorting(newSortBy); // update internal table `sorting` state
        onChangeSort(newSortBy); // inform caller of change
      }
    },
    [isSortable, onChangeSort],
  );

  const tableOptions: TableOptions<TData> = {
    data: memoizedData,
    columns: memoizedColumns,
    manualSorting: true,
    enableSortingRemoval: false,
    enableSorting: isSortable,
    state: { sorting },
    defaultColumn,
    getCoreRowModel: getCoreRowModel(),
    onSortingChange: handleSortingChange,
  };

  // https://react.dev/reference/eslint-plugin-react-hooks/lints/incompatible-library
  // eslint-disable-next-line react-hooks/incompatible-library
  const tableInstance = useReactTable(tableOptions);
  const { rows } = tableInstance.getRowModel();
  const headers = tableInstance.getFlatHeaders() as Header<TData, TValue>[];

  const handleRowClick = useCallback(
    (e: React.MouseEvent<HTMLTableRowElement, MouseEvent>, rowData: TData) => {
      if (!onRowClickCustomHandler) {
        return undefined;
      }
      if (!isLoading) {
        onRowClickCustomHandler(rowData);
      }
    },
    [onRowClickCustomHandler, isLoading],
  );

  const shouldWindow = isWindowed && !!rowHeight && !!height;
  const showEmpty = !rows.length && !isLoading;

  const showPaginationFooter = !!paginationProps && !!rowHeight;

  // If we're loading a new page, lets scroll to the loading items
  useEffect(() => {
    if (paginationProps?.isPageLoading && tableContainerRef.current && shouldWindow) {
      tableContainerRef.current.scrollTo({
        top: (memoizedData.length - loadingRowCount) * (rowHeight ?? 1),
        behavior: 'smooth',
      });
    }
  }, [
    paginationProps?.isPageLoading,
    paginationProps?.selectedPageCount,
    memoizedData.length,
    loadingRowCount,
    rowHeight,
    shouldWindow,
  ]);

  if (shouldWindow) {
    return (
      <VirtualTable
        headers={headers}
        columns={columns}
        rows={rows}
        handleRowClick={handleRowClick}
        showPaginationFooter={showPaginationFooter}
        showEmpty={showEmpty}
        paginationProps={paginationProps}
        rowHeight={rowHeight}
        height={height}
        tableContainerRef={tableContainerRef}
        emptyStateProps={emptyStateProps}
        {...rest}
      />
    );
  }

  return (
    <BasicTable
      headers={headers}
      columns={columns}
      rows={rows}
      handleRowClick={handleRowClick}
      showPaginationFooter={showPaginationFooter}
      showEmpty={showEmpty}
      paginationProps={paginationProps}
      rowHeight={rowHeight}
      height={height}
      tableContainerRef={tableContainerRef}
      emptyStateProps={emptyStateProps}
      {...rest}
    />
  );
};
