import { isValidElement, ReactElement } from 'react';
import { Link } from 'react-router-dom';
import type { Placement } from '@floating-ui/react';

import { Button, ButtonProps } from '../Button';
import { SaveButton, SaveButtonProps as SaveAction } from '../SaveButton';
import { Sizes } from '../types';

export const isSaveButton = (action: ActionType): action is SaveAction => {
  return (action as Action).text === undefined;
};

export const isCustomAction = (action: ActionType): action is ReactElement => {
  return isValidElement(action);
};

type ActionType = Action | SaveAction | ReactElement;

export type ActionList = ActionType[];
export interface Action {
  text: React.ReactNode;
  href?: string;
  onClick?(event: React.MouseEvent): void;
  buttonProps?: Partial<ButtonProps>;
  tooltip?: string;
  /**
   * Controls where a tooltip is placed in relation to the target.
   * If not provided, tooltip will default to `autoPlacement`
   */
  tooltipPlacement?: Placement;
}

export interface ActionsProps {
  actions: ActionList;
  /** Size of the action buttons */
  size?: Sizes;
}

export const Actions: React.FC<ActionsProps> = ({ actions, size = Sizes.sm }) => {
  return (
    <>
      {actions.map((action, index) => {
        if (isCustomAction(action)) {
          return (
            <div key={`action-${index}`} className="flex">
              {action}
            </div>
          );
        }

        if (isSaveButton(action)) {
          return <SaveButton key="action-save" {...action} size={size} />;
        }

        const { text, href, onClick, buttonProps, tooltip, tooltipPlacement } = action;
        const resolvedTooltip = buttonProps?.tooltip ?? tooltip;

        return (
          <div key={`action-${text}`} className="flex">
            {!!href && (
              <Link to={href}>
                <Button
                  {...buttonProps}
                  text={text}
                  tooltip={resolvedTooltip}
                  tooltipPlacement={tooltipPlacement}
                  size={size}
                />
              </Link>
            )}
            {!href && (
              <Button
                {...buttonProps}
                text={text}
                onClick={onClick}
                tooltip={resolvedTooltip}
                tooltipPlacement={tooltipPlacement}
                size={size}
              />
            )}
          </div>
        );
      })}
    </>
  );
};
