import { type ReactNode, useCallback } from 'react';
import { type ColumnDef, type Row } from '@tanstack/react-table';
import { useVirtualizer, type VirtualItem, Virtualizer } from '@tanstack/react-virtual';

import type { DefaultTData } from './types';
import type { InternalTableProps } from './types.internal';
import { getColumnStyles } from './utils';

type UseVirtualTableArgs<TData extends DefaultTData> = {
  rows: Row<TData>[];
  columns: ColumnDef<TData, ReactNode>[];
  rowHeight: number;
  overscanCount: number;
  columnOverscanCount: number;
  tableContainerRef: InternalTableProps<TData, ReactNode>['tableContainerRef'];
  headers: ColumnDef<TData, ReactNode>[];
};

type UseVirtualTableReturn<TData extends DefaultTData> = {
  /** visible rows based on scroll position */
  virtualRows: VirtualItem[];
  /** visible columns based on scroll position */
  virtualColumns: VirtualItem[];
  /** height of the table content */
  tableContentHeight: string;
  /** padding on the left side of the table to fill space for unrendered columns */
  virtualPaddingLeft: number | undefined;
  /** padding on the right side of the table to fill space for unrendered columns */
  virtualPaddingRight: number | undefined;
  /** visible headers based on scroll position */
  visibleHeaders: ColumnDef<TData, ReactNode>[];
  /** the column's "real" index as it lives in the data v.s. the index in the subset currently rendered */
  colIdxOffset: number;
  /** virtualizer for columns */
  columnVirtualizer: Virtualizer<HTMLDivElement, Element>;
};

type UseVirtualTableProps = <TData extends DefaultTData>(
  args: UseVirtualTableArgs<TData>,
) => UseVirtualTableReturn<TData>;

export const useVirtualTableProps: UseVirtualTableProps = <TData extends DefaultTData>({
  rows,
  columns,
  rowHeight,
  overscanCount,
  columnOverscanCount,
  tableContainerRef,
  headers,
}: UseVirtualTableArgs<TData>) => {
  const estimateRowSize = useCallback(() => rowHeight, [rowHeight]);
  // https://react.dev/reference/eslint-plugin-react-hooks/lints/incompatible-library
  // eslint-disable-next-line react-hooks/incompatible-library
  const rowVirtualizer = useVirtualizer({
    count: rows.length,
    estimateSize: estimateRowSize,
    overscan: overscanCount,
    getScrollElement: () => tableContainerRef.current,
  });
  const virtualRows = rowVirtualizer.getVirtualItems();

  const estimateColSize = useCallback(
    (index: number) => getColumnStyles(columns[index]).width,
    [columns],
  );
  const columnVirtualizer = useVirtualizer({
    horizontal: true,
    count: columns.length,
    getScrollElement: () => tableContainerRef.current,
    estimateSize: estimateColSize,
    overscan: columnOverscanCount,
  });
  const virtualColumns = columnVirtualizer.getVirtualItems();

  const tableContentHeight = `${rowVirtualizer.getTotalSize()}px`;

  // add empty columns to the left and right to fill out horizontal scroll container
  let virtualPaddingLeft: number | undefined;
  let virtualPaddingRight: number | undefined;

  if (columnVirtualizer && virtualColumns?.length) {
    // starting x-position of first visible column
    virtualPaddingLeft = virtualColumns[0]?.start ?? 0;

    // total width - end x-position of last visible column
    virtualPaddingRight =
      columnVirtualizer.getTotalSize() -
      (virtualColumns[virtualColumns.length - 1]?.end ?? 0); // end position
  }

  // only render headers visible within virtual container
  const visibleHeaders = virtualColumns.map((vc) => headers[vc.index]);

  // used to calculate the column's "real" index as it lives in the data
  // v.s. the index in the subset currently rendered
  const colIdxOffset = virtualColumns[0]?.index ?? 0;

  return {
    virtualRows,
    virtualColumns,
    tableContentHeight,
    virtualPaddingLeft,
    virtualPaddingRight,
    visibleHeaders,
    colIdxOffset,
    columnVirtualizer,
  };
};
