import { useCallback, useEffect, useMemo, useState } from 'react';

import { FileTreeItemType } from '..';
import { unique } from './unique';

interface OpenDirectoriesParams {
  activeFilePath: string | undefined;
  items: FileTreeItemType[];
  rootNodeName: string;
  dbtSubdirectory?: string;
}

export const useOpenDirectories = ({
  activeFilePath,
  items,
  dbtSubdirectory,
  rootNodeName,
}: OpenDirectoriesParams) => {
  const getParentNode = useCallback(
    (child: FileTreeItemType) => {
      return items.find((node) => node.id === child.parent);
    },
    [items],
  );

  const getAncestorNodeIds = useCallback(
    (child: FileTreeItemType) => {
      const ancestors: Array<string> = [child.parent];
      let currentNode = child;
      while (currentNode.parent !== rootNodeName) {
        const newParent = getParentNode(currentNode);
        if (!newParent) break;
        currentNode = newParent;
        ancestors.push(newParent.id);
      }
      return ancestors;
    },
    [getParentNode, rootNodeName],
  );

  // TODO: store the user's expanded folders in a more permanent state (so it persists between page reloads as well)
  const [openDirectories, setOpenDirectories] = useState<Array<string>>();

  useEffect(() => {
    if (!activeFilePath || items.length === 0) return;
    const activeTabNode = items.find((node) => node.id === activeFilePath);
    const openNodes =
      activeTabNode !== undefined ? [...getAncestorNodeIds(activeTabNode)] : [];
    setOpenDirectories((open) => {
      return [...(open ?? []), ...openNodes].filter(unique).sort();
    });
  }, [activeFilePath, items, getAncestorNodeIds]);

  const dbtSubdirNode = items.find(
    (node: FileTreeItemType) => node.id === dbtSubdirectory,
  );

  const dbtSubdirNodeId = dbtSubdirNode ? dbtSubdirNode.id : '';

  const dbtSubdirNodeAncestors = useMemo(
    () => (dbtSubdirNode !== undefined ? getAncestorNodeIds(dbtSubdirNode) : []),
    [dbtSubdirNode, getAncestorNodeIds],
  );

  const finalOpenDirectories = useMemo(
    () =>
      openDirectories ??
      (!!dbtSubdirNode && dbtSubdirNodeId
        ? [...dbtSubdirNodeAncestors, dbtSubdirNodeId].filter(unique)
        : []),
    [dbtSubdirNode, dbtSubdirNodeAncestors, dbtSubdirNodeId, openDirectories],
  );

  // Ensure initial open directories are preserved
  if (!openDirectories && finalOpenDirectories.length > 0) {
    setOpenDirectories((open = []) => [...open, ...finalOpenDirectories]);
  }

  return useMemo(
    () => ({
      openDirectories: finalOpenDirectories,
      setOpenDirectories,
    }),
    [finalOpenDirectories],
  );
};
