import { useState } from 'react';
import cx from 'classnames';

import { Tooltip, type TooltipProps } from '../Tooltip';
import { generateInitialsColors } from './avatarColors';

export type AvatarShape = 'circle' | 'square' | 'rounded-square';
// Exported for testing
export type AvatarSize = '2xs' | 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl';

type TooltipPropsWithoutChildren = Omit<TooltipProps, 'children' | 'content'>;

export interface AvatarProps {
  /** The URL of the avatar image */
  src?: string;
  /** The first name of the user */
  firstName?: string;
  /** The last name of the user */
  lastName?: string;
  /** The email address of the user */
  emailAddress?: string;
  /** The size of the avatar */
  size?: AvatarSize;
  /** The shape of the avatar */
  shape?: AvatarShape;
  /** The type of placeholder to show when no image is available */
  placeholderType?: 'empty' | 'initials' | 'default';
  /** Whether to show the tooltip */
  showTooltip?: boolean;
  /** Props to pass to the Tooltip component */
  tooltipProps?: TooltipPropsWithoutChildren;
  /** Alt text for the image */
  altText?: string;
  /** Custom avatar classnames */
  className?: string;
  /** data-testid for cypress targeting */
  testId?: string;
  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

const generateInitials = (
  firstName?: string,
  lastName?: string,
  emailAddress?: string,
): string => {
  // If we have any name components, use those
  if (firstName || lastName) {
    const firstInitial = firstName ? firstName.charAt(0).toUpperCase() : '';
    const lastInitial = lastName ? lastName.charAt(0).toUpperCase() : '';

    // If we only have one name, use first two letters of that name
    if (firstName && !lastName) {
      return firstName.length > 1
        ? firstName.slice(0, 2).toUpperCase()
        : firstName.toUpperCase();
    }
    if (!firstName && lastName) {
      return lastName.length > 1
        ? lastName.slice(0, 2).toUpperCase()
        : lastName.toUpperCase();
    }

    // If we have both names, use first letter of each
    return `${firstInitial}${lastInitial}`;
  }

  // Fall back to email if available
  if (emailAddress) {
    // Get the part before the @ symbol
    const localPart = emailAddress.split('@')[0];

    // If it contains a dot or underscore, treat it like first.last
    if (localPart.includes('.') || localPart.includes('_')) {
      const [first, last] = localPart.split(/[._]/);
      if (first && last) {
        return `${first.charAt(0)}${last.charAt(0)}`.toUpperCase();
      }
    }

    // Otherwise use first two characters of email
    return localPart.length > 1
      ? localPart.slice(0, 2).toUpperCase()
      : localPart.toUpperCase();
  }

  return '';
};

const generateTooltipText = (
  firstName?: string,
  lastName?: string,
  emailAddress?: string,
): React.ReactNode => {
  // If we have any name components, show the full name
  if (firstName || lastName) {
    return [firstName, lastName].filter(Boolean).join(' ');
  }

  // If no name but we have email, show that
  if (emailAddress) {
    return emailAddress;
  }

  // If nothing provided, show generic text
  return 'dbt user';
};

const AvatarContent: React.FC<AvatarProps> = ({
  src,
  shape = 'circle',
  size = 'md',
  placeholderType = 'empty',
  firstName,
  lastName,
  emailAddress,
  altText = '',
  className,
  testId = 'avatar',
  trackingId = 'avatar',
}): React.ReactElement => {
  const [imageLoaded, setImageLoaded] = useState(false);

  const hasSrc = src && src.length > 0;

  const initials = generateInitials(firstName, lastName, emailAddress);
  const shouldShowInitials = placeholderType === 'initials' && initials !== '';

  const shapeClasses = {
    'rounded-full': shape === 'circle',
    rounded: shape === 'rounded-square' && ['2xs', 'xs', 'sm'].includes(size),
    'rounded-md': shape === 'rounded-square' && ['md', 'lg', 'xl'].includes(size),
    'rounded-lg': shape === 'rounded-square' && ['2xl', '3xl'].includes(size),
  };

  const sizeClasses = {
    'h-5 w-5 font-label': size === '2xs',
    'h-6 w-6 font-label': size === 'xs',
    'h-8 w-8 font-label': size === 'sm',
    'h-10 w-10 font-label-lg': size === 'md',
    'h-12 w-12 font-label-lg': size === 'lg',
    'h-14 w-14 font-label-lg': size === 'xl',
    'h-16 w-16 font-label-lg': size === '2xl',
  };

  // Generate colors for initials placeholder if needed
  const initialsColors = shouldShowInitials
    ? generateInitialsColors(initials)
    : undefined;

  return (
    <div data-testid={testId} data-trackingid={trackingId} className={className}>
      {hasSrc && (
        <img
          className={cx(
            'inline-block object-cover',
            { hidden: !imageLoaded },
            shapeClasses,
            sizeClasses,
          )}
          src={src}
          alt={altText}
          onLoad={() => setImageLoaded(true)}
          data-testid={`${testId}-image`}
        />
      )}
      {(!hasSrc || !imageLoaded) && !shouldShowInitials && (
        <span
          className={cx(
            'bg-bgNeutralMuted inline-block overflow-hidden',
            shapeClasses,
            sizeClasses,
          )}
          data-testid={`${testId}-placeholder`}
        >
          <svg
            aria-label={altText}
            className="text-fgDecorative h-full w-full"
            fill="currentColor"
            role="img"
            viewBox="0 0 24 24"
          >
            <path d="M24 20.993V24H0v-2.996A14.977 14.977 0 0112.004 15c4.904 0 9.26 2.354 11.996 5.993zM16.002 8.999a4 4 0 11-8 0 4 4 0 018 0z" />
          </svg>
        </span>
      )}
      {(!hasSrc || !imageLoaded) && shouldShowInitials && (
        <span
          aria-label={altText}
          className={cx(
            'inline-flex items-center justify-center',
            initialsColors?.background,
            initialsColors?.foreground,
            shapeClasses,
            sizeClasses,
          )}
          data-testid={`${testId}-initials`}
          role="img"
        >
          <span className="leading-none">{initials}</span>
        </span>
      )}
    </div>
  );
};

export const Avatar: React.FC<AvatarProps> = ({
  src,
  firstName = '',
  lastName = '',
  emailAddress = '',
  size = 'md',
  shape = 'circle',
  placeholderType = 'default',
  showTooltip = false,
  tooltipProps,
  altText,
  className,
  testId = 'avatar',
  trackingId = 'avatar',
}): React.ReactElement => {
  const avatarContent = (
    <AvatarContent
      src={src}
      firstName={firstName}
      lastName={lastName}
      emailAddress={emailAddress}
      size={size}
      shape={shape}
      placeholderType={placeholderType}
      altText={altText}
      className={className}
      testId={testId}
      trackingId={trackingId}
    />
  );

  if (!showTooltip) {
    return avatarContent;
  }

  const tooltipContent = generateTooltipText(firstName, lastName, emailAddress);

  return (
    <Tooltip content={tooltipContent} {...tooltipProps}>
      {avatarContent}
    </Tooltip>
  );
};
