import cx from 'classnames';

export interface FormErrorProps {
  /** Error text */
  error: string;

  /** Classnames */
  className?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

/** This component can be used to create arbitrary form errors for content that may not have its own sourdough component */
export const FormError: React.FC<FormErrorProps> = ({
  error,
  className,
  testId = 'form-error',
  trackingId = 'form-error',
}) => {
  return (
    <p
      className={cx('text-fgDanger font-caption mt-1', className)}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      {error}
    </p>
  );
};
