import cx from 'classnames';

import { useSkeletonContext } from '../../../context/SkeletonProvider';
import { LoadingBlock } from '../../LoadingBlock/LoadingBlock';
import { DEFAULT_STATUS_BAR_CHILD_CLASSES } from '../StatusBar';

export interface StatusBarTimingTileProps {
  /** The top level text to display */
  text: React.ReactNode;

  /** DEPRECATED: Secondary text to display */
  subText?: React.ReactNode;

  /** A label for what the tile represents */
  label: string;

  /** Custom classnames */
  className?: string;

  /** Flag to render in skeleton mode */
  skeleton?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export const StatusBarTimingTile: React.FC<StatusBarTimingTileProps> = ({
  text,
  label,
  className,
  skeleton = false,
  testId = 'status-bar-timing-tile',
  trackingId = 'status-bar-timing-tile',
}): React.ReactElement => {
  const globalSkeleton = useSkeletonContext()?.skeleton;
  const shouldSkeleton = skeleton || globalSkeleton;
  return (
    <div
      className={cx(
        'flex flex-col items-center',
        DEFAULT_STATUS_BAR_CHILD_CLASSES,
        className,
      )}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      <div className="flex grow basis-0 flex-col items-center">
        <div
          className={cx('text-fgMain font-label')}
          data-testid={`${testId}-text`}
          data-trackingid={`${trackingId}-text`}
        >
          {shouldSkeleton && <LoadingBlock width={130} height={18} className="pb-2" />}
          {!shouldSkeleton && text}
        </div>
      </div>
      <div
        className="text-fgDecorative font-label flex grow basis-0 items-end"
        data-testid={`${testId}-label`}
        data-trackingid={`${trackingId}-label`}
      >
        {label}
      </div>
    </div>
  );
};
