import cx from 'classnames';

import { Icon } from '../Icon';
import { RyeconCaretDown, RyeconCaretRight } from '../ryecons';

interface AccordionIconProps {
  /** If the icon caret poits up / down */
  isOpen: boolean;
  /** If the icon should be grayed out */
  isDisabled?: boolean;
  /** If class for the icons */
  className?: string;
}

const AccordionIcon = ({ isOpen, isDisabled, className }: AccordionIconProps) => {
  const iconColor = isDisabled ? 'text-fgDisabled' : 'text-fgAlt';

  return isOpen ? (
    <Icon
      ryecon={RyeconCaretDown}
      size="md"
      className={cx('ml-[-4px] mr-[-2px]', iconColor, className)}
      testId="accordion-open-toggle"
    />
  ) : (
    <Icon
      ryecon={RyeconCaretRight}
      size="md"
      className={cx('ml-[-6px]', iconColor, className)}
      testId="accordion-open-toggle"
    />
  );
};

export { AccordionIcon };
