import React, { useCallback, useId, useMemo } from 'react';

import { ColorSet, DEFAULT_COLOR_SET } from '../Chart';
import { useChartContext } from '../ChartProvider/ChartProvider';
import { Accessor, Shape, ShapeProps } from '../types';
import { createFullPlotId } from '../util/plot';

export interface PlotProps {
  /**
   * List of data points to be plotted
   */
  data: unknown[];
  /**
   * Specific shape that will render the data points on the chart
   */
  itemComponent?: Shape;
  /**
   * Props to be applied to the itemComponent
   */
  extraItemProps?: any;
  /**
   * Other objects to be rendered within the plot
   */
  children?(props: ShapeProps): React.ReactNode;
  /**
   * Accessor callback to provide the y value of a given data point
   */
  yAccessor?: Accessor<any, any>;
  /**
   * Accessor callback to provide the x value of a given data point
   */
  xAccessor?: Accessor<any, any>;
  /**
   * Optional unique identifier of the plot, used to access plot within registry. If not provided, a unique ID will be generated.
   */
  id?: string;
  /**
   * Name of the plot, used to represent this plot in the legend
   */
  name?: string | string[];
  /**
   * Id for testing
   */
  testId?: string;
}

/** @deprecated */
export const Plot: React.FC<PlotProps> = ({
  data,
  itemComponent,
  children,
  extraItemProps,
  yAccessor,
  xAccessor,
  id,
  name,
  testId = 'plot',
}) => {
  const { chartMeta, registerPlot, unregisterPlot, colorScale } =
    useChartContext() ?? {};
  const fallbackId = useId();
  const plotId = useMemo(
    () => id ?? `plot_${itemComponent?.shapeName}_${fallbackId}`,
    [fallbackId, id, itemComponent?.shapeName],
  );

  const getColor = useCallback(
    (subPlotIndex: number = 0): ColorSet => {
      const id = createFullPlotId(plotId, subPlotIndex);
      if (colorScale) {
        return colorScale(id);
      }
      return DEFAULT_COLOR_SET[0];
    },
    [colorScale, plotId],
  );

  const accessors: { xAccessor: Accessor<any, any>; yAccessor: Accessor<any, any> } =
    React.useMemo(
      () => ({
        yAccessor: yAccessor ? yAccessor : chartMeta?.yAccessor ?? (() => null),
        xAccessor: xAccessor ? xAccessor : chartMeta?.xAccessor ?? (() => null),
      }),
      [xAccessor, yAccessor, chartMeta?.xAccessor, chartMeta?.yAccessor],
    );
  const Item = itemComponent ?? null;
  const itemProps: ShapeProps = {
    data,
    ...accessors,
    ...extraItemProps,
    chartMeta,
    plotId: plotId,
    getColor: chartMeta?.getColor ?? getColor,
  };

  React.useEffect(() => {
    if (registerPlot) {
      registerPlot({
        id: plotId,
        data,
        extraItemProps,
        shape: Item,
        name,
        getColor,
        ...accessors,
      });
    }
  }, [accessors, extraItemProps, data, registerPlot, plotId, Item, getColor, name]);

  React.useEffect(() => {
    return () => {
      if (unregisterPlot) {
        unregisterPlot(plotId);
      }
    };
  }, [plotId, unregisterPlot]);

  return (
    <g data-testid={testId} transform={`translate(0,0)`}>
      {!!Item && <Item {...itemProps} />}
      {!!children && children(itemProps)}
    </g>
  );
};
