import React, { type JSX, useCallback } from 'react';

import { FileTreeItemWrapperProps } from './DefaultFileTreeItemWrapper';
import {
  MoveFileFn,
  NodeProps,
  type OnFileSelect,
  type OnFolderSelect,
  TreeNodeValues,
} from './types';
import { useFileItemDrag } from './useFileItemDrag';

export type NodePropsAdvanced = Omit<NodeProps, 'style'> & {
  /**
   * If false disables drag and drop
   */
  isReadOnly?: boolean;
  /**
   * Called on dropping a file or folder on a new location
   */
  onMoveFile?: MoveFileFn;
  /**
   * Component will be wrapped in drag and drop and passed ragging info
   * also passed toggle to get react-vtree to open or close file
   */
  children: React.MemoExoticComponent<
    (FileTreeItemProps: FileTreeItemWrapperProps) => JSX.Element
  >;
  /**
   * Enable close folder on second click.
   */
  enableCloseFolderOnSecondClick?: boolean;
  /**
   * Used to know if we are dropping a file or folder on the root node
   */
  isRootDropPath?: boolean;

  setOpenDirectories?: (
    directories: (directories: string[] | undefined) => string[] | undefined,
    event: React.MouseEvent<HTMLButtonElement, MouseEvent>,
  ) => void;

  /**
   * Called when a file is selected
   */
  onFileSelect?: OnFileSelect;

  /**
   * Called when a folder is selected
   */
  onFolderSelect?: OnFolderSelect;

  /**
   * true if file is selected
   */
  isSelected: boolean;

  /**
   * Determines whether an expand indicator is displayed next to folders when open or closed.
   */
  showExpandButton?: boolean;
  /**
   * Determines whether an expand indicator is displayed next to folders when open or closed when item is hovered.
   */
  showExpandButtonOnHover?: boolean;
};

export const TreeNode = React.memo((props: NodePropsAdvanced) => {
  const {
    children: Component,
    data,
    isReadOnly = false,
    onMoveFile,
    setOpen,
    isOpen,
    onFileSelect,
    onFolderSelect,
    setOpenDirectories,
    isSelected,
    isRootDropPath = false,
    showExpandButton = false,
    showExpandButtonOnHover = false,
    enableCloseFolderOnSecondClick = false,
  } = props;
  const { drop, drag, isOver, isDragging } = useFileItemDrag(data, {
    isReadOnly,
    onMoveFile,
    isRootDropPath,
  });

  // If enableCloseFolderOnSecondClick is true and it's an expand button click we toggle, otherwise we only want to toggle the folder if it's closed or selected
  const getShouldToggle = useCallback(
    (isExpandButtonClick: boolean) => {
      if (!enableCloseFolderOnSecondClick) return true;
      if (isExpandButtonClick) {
        return true;
      }
      return isOpen ? isSelected : true;
    },
    [enableCloseFolderOnSecondClick, isOpen, isSelected],
  );

  const onToggle = useCallback(
    (
      event: React.MouseEvent<HTMLButtonElement, MouseEvent>,
      data: TreeNodeValues,
      isExpandButtonClick = false,
    ) => {
      if (data.pathType === 'file') {
        onFileSelect?.(data.relativePath, event, data);
      } else {
        const shouldToggle = getShouldToggle(isExpandButtonClick);
        data.relativePath &&
          onFolderSelect?.(data.relativePath, event, isExpandButtonClick);
        if (shouldToggle) {
          setOpen(!isOpen);
          setOpenDirectories?.((open: string[] | undefined) => {
            if (isOpen) {
              return open?.filter((o) => o !== data.relativePath);
            }
            return [...(open || []), data.relativePath!];
          }, event);
        }
      }
    },
    [
      onFileSelect,
      getShouldToggle,
      onFolderSelect,
      setOpen,
      isOpen,
      setOpenDirectories,
    ],
  );

  return (
    <div
      ref={(ref) => {
        drop(drag(ref));
      }}
    >
      <Component
        data={data}
        isOpen={isOpen}
        isDragging={isDragging}
        isOver={isOver}
        isReadOnly={isReadOnly}
        isHighlighted={isSelected}
        onClick={onToggle}
        showExpandButton={showExpandButton}
        showExpandButtonOnHover={showExpandButtonOnHover}
      />
    </div>
  );
});
