export const Logo: React.FC<LogoProps> = ({
  dislikesFun,
  isDark = false,
  className = '',
  title = '',
}) => {
  const labelId = useAriaLabelledby(title);

  return (
    <div
      className="flex items-center"
      aria-labelledby={labelId}
      role={title ? 'img' : undefined}
    >
      {Boolean(title) && (
        <span className="hidden" hidden id={labelId}>
          {title}
        </span>
      )}
      <Fidget isDark={isDark} dislikesFun={dislikesFun} className={className} />
      <LogoText isDark={isDark} className={className} />
    </div>
  );
};

export const Fidget: React.FC<LogoProps> = ({
  className = '',
  dislikesFun,
  title = '',
}) => {
  const [activationCount, setActivationCount] = useState<number>(0);
  const labelId = useAriaLabelledby(title);
  const spinClassName = {
    'motion-safe:animate-slow-spin': activationCount === 3,
    'motion-safe:animate-medium-spin': activationCount === 4,
    'motion-safe:animate-spin': activationCount === 5,
    'motion-safe:animate-fast-spin': activationCount >= 6,
  };

  const onDoubleClick = useCallback(() => {
    if (dislikesFun) {
      return;
    }

    setActivationCount((activationCount + 1) % 8);
  }, [activationCount, dislikesFun]);

  return (
    <div className={cx(className, { 'animation-container': activationCount === 7 })}>
      <svg
        width={24}
        height={24}
        viewBox="0 0 30 30"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        className={cx(className, spinClassName)}
        onDoubleClick={onDoubleClick}
        role={title ? 'img' : 'presentation'}
        aria-labelledby={labelId}
      >
        {Boolean(title) && <title id={labelId}>{title}</title>}
        <FidgetPath />
      </svg>
    </div>
  );
};

export const LogoText: React.FC<LogoProps> = ({
  isDark = false,
  className = '',
  title = '',
}) => {
  const labelId = useAriaLabelledby(title);

  return (
    <svg
      width={50}
      height={18}
      viewBox="1.2 1 42 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
      role={title ? 'img' : 'presentation'}
      aria-labelledby={labelId}
    >
      {Boolean(title) && <title id={labelId}>{title}</title>}
      <TextPath isDark={isDark} />
    </svg>
  );
};
