import { ReactNode, useEffect } from 'react';
import cx from 'classnames';

import { Caption, FloatingTabs } from '@/sourdough';
import { useLiveRegion } from '../../hooks';
import { ActionList, Actions } from '../Actions/Actions';
import { Badge, type BadgeProps } from '../Badge';
import { type Breadcrumb, Breadcrumbs } from '../Breadcrumbs';
import { IconText, type IconTextProps } from '../elements/IconText';
import { Notification, NotificationBanner } from '../NotificationBanner';
import { OffScreenContentContainer } from '../OffScreenDetector';
import { type TabProps } from '../tabs/FloatingTabs';
import { Tooltip } from '../Tooltip';

export type MetadataItem = Omit<IconTextProps, 'size'>;

export interface ProductPageHeaderProps {
  /** The page title */
  title: string;

  /** The page subtitle - can be a string or React element */
  subtitle?: ReactNode;

  /** A status badge to display on the page header */
  badge?: BadgeProps;

  /** An array of page actions */
  actions?: ActionList;

  /** Breadcrumbs for the page */
  breadcrumbs?: Breadcrumb[];

  /** Metadata items to display below the title */
  metadata?: MetadataItem[];

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** A flag to determine if the header should be sticky */
  sticky?: boolean;

  /** Error notification to display, if it exists */
  errorNotification?: Notification;

  /** A callback to be triggered when the error banner close button is clicked **/
  onErrorDismiss?: () => void;

  /** A boolean to determine whether the page is loading */
  isLoading: boolean;

  /** Optional tabs configuration */
  tabs?: TabProps[];
}

export const ProductPageHeader: React.FC<ProductPageHeaderProps> = ({
  title,
  subtitle,
  badge,
  actions,
  breadcrumbs,
  metadata,
  sticky,
  errorNotification,
  onErrorDismiss,
  testId = 'page-header',
  trackingId = 'page-header',
  isLoading = false,
  tabs,
}): React.ReactElement => {
  const mainActions = !!actions?.length && <Actions actions={actions} />;

  const {
    clearMessage: clearErrorNotification,
    LiveRegion: ErrorNotification,
    setMessage: setErrorNotification,
  } = useLiveRegion();

  useEffect(() => {
    if (!isLoading && errorNotification) {
      setErrorNotification(
        <NotificationBanner
          notification={errorNotification}
          onCloseClick={onErrorDismiss}
        />,
      );
    } else {
      clearErrorNotification();
    }
  }, [
    clearErrorNotification,
    errorNotification,
    isLoading,
    onErrorDismiss,
    setErrorNotification,
  ]);

  return (
    <OffScreenContentContainer>
      {(triggerRef) => (
        <div
          ref={triggerRef}
          data-testid={testId}
          data-trackingid={trackingId}
          className={cx(
            'border-borderMuted bg-bgMain border-b px-4 pt-[18px] sm:px-4 md:px-6 lg:px-8',
            'z-[19]', // this value is deliberate, in order to avoid clipping issues with menus in `@dbt-labs/app-nav`, which uses 'z-20'
            {
              'sticky top-0': sticky,
            },
          )}
        >
          <div className="mb-2 flex flex-col gap-4">
            {!!breadcrumbs && <Breadcrumbs breadcrumbs={breadcrumbs} />}
            <div className="items-left flex flex-col justify-between sm:flex-row md:items-center">
              <div className="min-w-4 truncate">
                <div className="flex flex-wrap items-center gap-x-2 gap-y-1 truncate md:gap-4">
                  <Tooltip displayOnlyWhenTruncated content={title}>
                    {(ref) => (
                      <h1
                        ref={ref}
                        className="text-fgMain font-heading-2 my-px min-w-0 flex-1 truncate"
                        data-testid={`${testId}-title`}
                        data-trackingid={`${trackingId}-title`}
                      >
                        {title}
                      </h1>
                    )}
                  </Tooltip>
                  {badge && <Badge {...badge} size="lg" />}
                </div>
                {subtitle && (
                  <div className="pt-0.5">
                    {typeof subtitle === 'string' ? (
                      <Caption className="text-fgDecorative">{subtitle}</Caption>
                    ) : (
                      subtitle
                    )}
                  </div>
                )}
                {metadata && metadata.length > 0 && (
                  <div className="flex flex-wrap items-center gap-x-4 gap-y-2 pt-2">
                    {metadata.map((item, index) => (
                      <IconText
                        key={index}
                        {...item}
                        size="sm"
                        testId={`${testId}-metadata-${index}`}
                        trackingId={`${trackingId}-metadata-${index}`}
                      />
                    ))}
                  </div>
                )}
              </div>
              <div className="flex items-center justify-end gap-2">{mainActions}</div>
            </div>
            {errorNotification && <ErrorNotification />}
          </div>
          {tabs && (
            <FloatingTabs isBorderless>
              {tabs.map((tab) => {
                return <FloatingTabs.Tab key={tab.id} {...tab} />;
              })}
            </FloatingTabs>
          )}
        </div>
      )}
    </OffScreenContentContainer>
  );
};
