import type { FC, ReactNode } from 'react';
import { FloatingPortal } from '@floating-ui/react';

type PanelProps = {
  children: ReactNode;
  portal: boolean;
};
export const TooltipPanel: FC<PanelProps> = ({ portal, children }) => {
  if (portal) {
    return <FloatingPortal>{children}</FloatingPortal>;
  }
  return children;
};
