import { twMerge } from 'tailwind-merge';

import { ColorSet } from '../../Chart';
import { ChartMeta } from '../../ChartProvider/ChartProvider';
import { InteractionPoint } from '../../InteractionLayer/InteractionLayer';
import { Accessor, Shape } from '../../types';
import { isPlotFocused } from '../../util/plot';
import { Scale, Scales } from '../../util/scales';

export interface BarExtras {
  className?: string;
  isHorizontal?: boolean;
  positionalScale?: Scale<any, any>;
  subPlotIndex?: number;
  testId?: string;
}

export const MAX_BAR_WIDTH = 25;
export const TOOLTIP_BAR_PADDING = 20;

export interface BarDimensions {
  barLength: number;
  barTrunkPosition: number;
  barPosition: number;
  barThickness: number;
  barTipPosition: number;
}
const calculateBarDimensions = (
  item: unknown,
  chartMeta: ChartMeta,
  isHorizontal: boolean,
  lengthScale: Scales,
  positionalScale: Scales,
  positionalAccessor: Accessor<any, any>,
  lengthAccessor: Accessor<any, any>,
): BarDimensions => {
  const positionalValue = positionalAccessor && positionalAccessor(item);
  const lengthValue = lengthAccessor && lengthAccessor(item);

  const positionScaleValue = positionalScale && positionalScale.scale(positionalValue);
  const lengthScaleValue = lengthScale && lengthScale.scale(lengthValue);

  const barPosition = positionScaleValue ?? 0;
  const barTipPosition = lengthScaleValue ?? 0;
  const plotHeight = chartMeta?.plotHeight ?? 0;
  const barTrunkPosition = (isHorizontal ? chartMeta?.margin?.left : plotHeight) || 0;

  const barLength = Math.abs(barTipPosition - barTrunkPosition);

  const barThickness =
    positionalScale.kind === 'category'
      ? positionalScale.scale.bandwidth()
      : MAX_BAR_WIDTH;

  return {
    barLength: barLength ?? 0,
    barThickness: barThickness ?? 0,
    barPosition: barPosition ?? 0,
    barTipPosition: barTipPosition ?? 0,
    barTrunkPosition: barTrunkPosition ?? 0,
  };
};

/** @deprecated */
export const Bar: Shape<BarExtras & { item: unknown }> = ({
  chartMeta,
  xAccessor,
  yAccessor,
  className,
  item,
  positionalScale: passedScale,
  isHorizontal = false,
  getColor,
  plotId,
  subPlotIndex,
  testId,
}) => {
  // position of the bar is dictated by the bar's thickness, set by the scale
  // if we were always using the bandwidth we'd be able to just set x to the scale value
  const positionalScale =
    passedScale ?? (isHorizontal ? chartMeta?.yScale : chartMeta?.xScale);
  const lengthScale = isHorizontal ? chartMeta?.xScale : chartMeta?.yScale;
  const positionalAccessor = isHorizontal ? yAccessor : xAccessor; // which category does it fall into
  const lengthAccessor = isHorizontal ? xAccessor : yAccessor; // How long is the bar?

  testId ??= `${chartMeta?.testId}-bar`;

  if (chartMeta) {
    const { barPosition, barTipPosition, barThickness, barLength } =
      calculateBarDimensions(
        item,
        chartMeta,
        isHorizontal,
        lengthScale!,
        positionalScale!,
        positionalAccessor!,
        lengthAccessor!,
      );

    return (
      <rect
        y={isHorizontal ? barPosition : barTipPosition}
        height={isHorizontal ? barThickness : barLength}
        x={isHorizontal ? chartMeta.margin?.left ?? 0 : barPosition}
        data-testid={testId ?? `${chartMeta?.testId}-bar`}
        className={twMerge(
          'transition-colors',
          createBarClassNames(
            getColor(),
            isPlotFocused(chartMeta?.focusPlotId, plotId, subPlotIndex),
            chartMeta.interactionItem?.item === item,
          ),
          className,
        )}
        stroke="none"
        width={isHorizontal ? barLength : positionalScale?.scale.bandwidth() ?? 0}
      />
    );
  }

  return null;
};

Bar.shapeName = 'Bar';
Bar.getInteractionMeta = ({ chartMeta, plot, item }) => {
  const isHorizontal = plot.extraItemProps.isHorizontal ?? false;
  const positionalScale = isHorizontal ? chartMeta?.yScale : chartMeta?.xScale;
  const lengthScale = isHorizontal ? chartMeta?.xScale : chartMeta?.yScale;
  const positionalAccessor = isHorizontal ? plot.yAccessor : plot.xAccessor; // which category does it fall into
  const lengthAccessor = isHorizontal ? plot.xAccessor : plot.yAccessor; // How big is the bar?

  if (chartMeta) {
    const { barThickness } = calculateBarDimensions(
      item,
      chartMeta,
      isHorizontal,
      lengthScale!,
      positionalScale!,
      positionalAccessor!,
      lengthAccessor!,
    );

    const xTooltipPos = isHorizontal ? TOOLTIP_BAR_PADDING : barThickness / 2;
    const yTooltipPos = isHorizontal ? barThickness / 2 : -TOOLTIP_BAR_PADDING;

    return {
      tooltipX: {
        offset: xTooltipPos,
        at: isHorizontal ? 'left' : 'center',
      },
      tooltipY: {
        offset: yTooltipPos,
        at: isHorizontal ? 'middle' : 'bottom',
      },
    };
  }

  return {};
};

export const createBarClassNames = (
  colorSet: ColorSet,
  focused: boolean,
  interaction: boolean,
) => {
  let extraClasses: string | undefined = '';
  if (focused && interaction) {
    extraClasses = colorSet.fillInteract;
  }

  if (focused && !interaction) {
    extraClasses = colorSet.focused;
  }

  if (!focused) {
    extraClasses = colorSet.unfocused;
  }

  return twMerge(colorSet.fill, extraClasses);
};

Bar.getInteractionPoints = ({ chartMeta, plot, item }): InteractionPoint[] => {
  const isHorizontal = plot.extraItemProps.isHorizontal ?? false;
  const positionalScale = isHorizontal ? chartMeta?.yScale : chartMeta?.xScale;
  const lengthScale = isHorizontal ? chartMeta?.xScale : chartMeta?.yScale;
  const positionalAccessor = isHorizontal ? plot.yAccessor : plot.xAccessor; // which category does it fall into
  const lengthAccessor = isHorizontal ? plot.xAccessor : plot.yAccessor; // How long is the bar?

  if (chartMeta) {
    const { barPosition, barThickness } = calculateBarDimensions(
      item,
      chartMeta,
      isHorizontal,
      lengthScale!,
      positionalScale!,
      positionalAccessor!,
      lengthAccessor!,
    );

    return [
      {
        plotName: plot.name,
        plotId: plot.id,
        fullItem: item,
        shape: plot.shape,
        point: [
          isHorizontal ? chartMeta.plotHeight : barPosition + barThickness / 2,
          isHorizontal ? barPosition + barThickness / 2 : chartMeta.plotHeight,
        ],
      },
    ];
  }

  return [
    {
      plotId: plot.id,
      fullItem: item,
      shape: plot.shape,
      point: [0, 0],
    },
  ];
};

/** @deprecated */
export const Bars: Shape<BarExtras> = (props) => {
  const { data, chartMeta } = props;
  const testIdPrefix = chartMeta?.testId ?? 'chart';
  return (
    <>
      {data?.map<React.ReactNode>((item, idx) => (
        <Bar {...props} item={item} key={idx} testId={`${testIdPrefix}-bar-${idx}`} />
      ))}
    </>
  );
};

Bars.shapeName = 'Bars';
Bars.getInteractionMeta = Bar.getInteractionMeta;
Bars.getInteractionPoints = Bar.getInteractionPoints;
