import { LoadingCell } from './cells/LoadingCell';
import { ColumnDef, DefaultTData } from './types';

export const createLoadingColumns = <
  TData extends DefaultTData,
  TValue extends React.ReactNode,
>(
  columns: ColumnDef<TData, TValue>[],
): ColumnDef<TData, TValue>[] => {
  return columns.map((column) => {
    return {
      ...column,
      Cell: LoadingCell,
    };
  });
};

export const createLoadingRows = <TData extends DefaultTData>(
  rowCount: number = 3,
): TData[] => {
  return Array(rowCount).fill({ isLoadingRow: true }, 0, rowCount);
};

// same defaults from react-table v7
const DEFAULT_WIDTH = 150;
const DEFAULT_MIN_WIDTH = 20;

/**
 * mirrors behavior of v7 to minimize style thrashing while upgrading
 * used by DefaultCell and HeaderCell
 */
export const getColumnStyles = <TData extends DefaultTData, TValue = unknown>(
  columnDef: ColumnDef<TData, TValue>,
) => {
  const minWidth = columnDef.minSize ?? DEFAULT_MIN_WIDTH;
  const width = columnDef.size ?? DEFAULT_WIDTH;
  const maxWidth = columnDef.maxSize ?? undefined;
  return {
    flex: `${width} 0 auto`,
    minWidth,
    width,
    maxWidth,
  };
};

const DEFAULT_ROW_HEIGHT = 40;

type GetVirtualizedTableHeightArgs = {
  numRows: number;
  rowHeight?: number;
  height?: number;
};

/**
 * derive height when not provided
 */
export const getVirtualizedTableHeight = ({
  numRows,
  rowHeight = DEFAULT_ROW_HEIGHT,
  height,
}: GetVirtualizedTableHeightArgs): number => {
  if (height) {
    return height;
  }
  return numRows * rowHeight;
};
