import { useEffect } from 'react';

export interface OnClickOutsideParams {
  /**
   * onClick can only be fired while the target element isOpen
   */
  isOpen: boolean;
  /**
   * The function which will be fired when the user clicks outside
   * or hits the ESC key
   */
  onClick: () => void | undefined;

  /**
   * The element which you want to detect if there have been click outside of
   */
  ref: React.RefObject<HTMLElement | null>;
}

/**
 * https://www.npmjs.com/package/react-onclickoutside recommends
 * just using the below logic for functional components.
 */

/**
 * Fires `onClick` when the user clicks outside or hits ESC while the element isOpen.
 */
export function useOnClickOutside({ isOpen, onClick, ref }: OnClickOutsideParams) {
  useEffect(() => {
    const onClickHandler = (ev: MouseEvent) => {
      if (!ref.current || !isOpen) return;
      if (ref.current.contains(ev.target as Node | null)) return;
      if (onClick) {
        ev.preventDefault();
        onClick();
      }
    };
    const onContextMenu = (ev: MouseEvent) => {
      if (!isOpen || !ref.current) return;
      ev.preventDefault();
      onClick?.();
    };
    const onEscape = (ev: KeyboardEvent) => {
      if (!ref.current || !isOpen) return;
      if (ev.key === 'Escape' && onClick) {
        ev.preventDefault();
        onClick();
      }
    };

    document.addEventListener('click', onClickHandler);
    document.addEventListener('contextmenu', onContextMenu);
    document.addEventListener('keydown', onEscape);

    return () => {
      document.removeEventListener('click', onClickHandler);
      document.addEventListener('contextmenu', onContextMenu);
      document.removeEventListener('keydown', onEscape);
    };
  });
}
