import { memo, MouseEvent as ReactMouseEvent, useMemo, useRef } from 'react';
import classNames from 'classnames';
import { twMerge } from 'tailwind-merge';

import { MenuButton } from '@/sourdough';
import { Button } from '../../Button';
import { useContextMenu } from '../../ContextMenu/ContextMenu';
import { Icon } from '../../Icon/Icon';
import {
  RyeconCaretDown,
  RyeconCaretRight,
  RyeconEllipsisHorizontal,
  RyeconErrorOutline,
  RyeconFile,
  RyeconFolder,
  RyeconFolderOpen,
  RyeconHome,
  RyeconModel,
  RyeconModifiedOutline,
  RyeconNewOutline,
  RyeconRemovedOutline,
  RyeconSeed,
} from '../../ryecons';
import type { Ryecon } from '../../ryecons/types';
import { Sizes } from '../../types';
import { DEFAULT_ITEM_HEIGHT, HEIGHT_TO_FONT_SIZE_MAP } from './constants';
import { FileTreeMenuItems, TreeNodeValues } from './types';
type LabeledRyecon = {
  ryecon: Ryecon;
  label: string;
  className?: string;
};

const ryeconMap: Record<string, LabeledRyecon> = {
  sql: { ryecon: RyeconModel, label: 'Model' },
  py: { ryecon: RyeconModel, label: 'Model' },
  csv: { ryecon: RyeconSeed, label: 'Seed' },
};

const ryeconLookup = (file: string | undefined): LabeledRyecon => {
  const parts = file?.split('.') ?? [];
  const ext = parts[parts.length - 1];

  return ryeconMap[ext] ?? { ryecon: RyeconFile, label: 'File' };
};

function getParentFolder(path: string) {
  const pathParts = path.split('/');
  pathParts.pop();
  return pathParts.pop();
}

export type FileTreeItemProps<TAction extends string> = {
  node: TreeNodeValues;
  isOpen?: boolean;
  activeFilePath?: string | null;
  hideInlineFileActions?: boolean;
  highlightedNode?: string;
  isHighlighted?: boolean;
  isProjectRoot?: boolean;
  isReadOnly?: boolean;
  isNodePathDirty?: boolean;
  hasUnresolvedMergeConflict?: boolean;
  showFolderHint?: boolean;
  showExpandButton?: boolean;
  showExpandButtonOnHover?: boolean;
  gitStatusDisplay?: 'icon' | 'letter';
  onClick?: (
    e: ReactMouseEvent<HTMLButtonElement, MouseEvent>,
    data: TreeNodeValues,
    isExpandButtonClick?: boolean,
  ) => void;
  actions?: FileTreeMenuItems<TAction>;
};

const getNodeRyecon = ({
  node,
  isProjectRoot,
  isOpen,
}: {
  node: TreeNodeValues | undefined;
  isProjectRoot: boolean;
  isOpen: boolean;
}): LabeledRyecon => {
  if (!node) {
    return { ryecon: RyeconFile, label: 'File' };
  }
  if (node.iconOverride) {
    return {
      ryecon: node.iconOverride.ryecon,
      label: node.iconOverride.label || 'Custom icon',
      className: node.iconOverride.className || '',
    };
  }

  if (node.pathType === 'file') {
    return ryeconLookup(node.name);
  }
  if (isProjectRoot) {
    return { ryecon: RyeconHome, label: 'Root directory' };
  }
  return { ryecon: isOpen ? RyeconFolderOpen : RyeconFolder, label: 'Directory' };
};

export const FileTreeItem = memo(
  <TAction extends string>({
    node,
    isOpen = false,
    activeFilePath,
    hideInlineFileActions,
    highlightedNode,
    isHighlighted = false,
    isProjectRoot = false,
    isNodePathDirty = false,
    hasUnresolvedMergeConflict = false,
    showFolderHint = false,
    showExpandButton = false,
    showExpandButtonOnHover = false,
    gitStatusDisplay = 'icon',
    onClick,
    actions,
  }: FileTreeItemProps<TAction>) => {
    const actionMenuRef = useRef<HTMLDivElement>(null);
    /** The root folder is `null` */
    const relativePath: string | null | undefined = node?.relativePath;
    const tooltipText = node?.tooltipText;

    const { menuItems, onMenuItemClick, contextId } = actions || {};
    const hasFileActions = !hideInlineFileActions && menuItems && menuItems.length > 0;
    const hasExtraActions = !!node.actions?.length || !!node.customActionsRenderer;
    const isDirectory = node.pathType === 'directory';

    const isGitAdded = node?.gitStatus === 'added';
    const isGitRenamed = node?.gitStatus === 'renamed';
    const isGitModified = node?.gitStatus === 'modified' || isGitRenamed;
    const isGitDeleted = node?.gitStatus === 'deleted';
    const isGitMergeConflict =
      node?.gitStatus === 'conflict' || node?.gitStatus === 'conflicted';

    const useLetterBadge = gitStatusDisplay === 'letter';

    const hasResolvedMergeConflict = isGitMergeConflict && !hasUnresolvedMergeConflict;
    const isChanged =
      isGitAdded || isGitModified || isGitDeleted || hasResolvedMergeConflict;

    const isDisabled = node?.isGitIgnored || node?.disabled;
    const isActive = relativePath === activeFilePath && !highlightedNode;

    const isCaretVisibleOnHover = showExpandButtonOnHover;
    const isExandButtonEnabled = showExpandButton || showExpandButtonOnHover;

    const contextMenu = useContextMenu({
      menuId: `fileTree|${contextId}|${node.relativePath}`,
    });

    /** `true` if item is active or highlighted */
    const isSelected =
      isActive || isHighlighted || (contextMenu.isOpen && hasFileActions);
    const isDefault =
      !isDisabled && !isSelected && !isChanged && !hasUnresolvedMergeConflict;

    const labeledIcon = getNodeRyecon({ node, isProjectRoot, isOpen });

    const changedLabel: string | undefined = useMemo(() => {
      if (!isChanged) {
        return undefined;
      }

      if (isGitAdded) {
        return 'Added';
      }

      if (isGitRenamed) {
        return 'Renamed';
      }

      if (isGitModified) {
        return 'Modified';
      }

      if (isGitMergeConflict) {
        return 'Merge conflict';
      }

      if (isGitDeleted) {
        return 'Deleted';
      }
    }, [
      isChanged,
      isGitAdded,
      isGitRenamed,
      isGitModified,
      isGitMergeConflict,
      isGitDeleted,
    ]);

    /** Single letter badge for git status (VS Code style) */
    const gitStatusLetter: string | undefined = useMemo(() => {
      if (isGitAdded) return 'A';
      if (isGitRenamed) return 'R';
      if (isGitModified) return 'M';
      if (isGitMergeConflict) return 'C';
      if (isGitDeleted) return 'D';
      return undefined;
    }, [isGitAdded, isGitRenamed, isGitModified, isGitMergeConflict, isGitDeleted]);

    const fontSize = HEIGHT_TO_FONT_SIZE_MAP[node.defaultHeight ?? DEFAULT_ITEM_HEIGHT];

    return (
      <div
        role="treeitem"
        aria-selected={isSelected}
        aria-label={`${node.depth + 1}`}
        aria-setsize={node.treeSize}
        aria-posinset={node.index + 1}
        aria-disabled={node.disabled}
        id={`file-tree-item-${node.relativePath}`}
        className={classNames(
          'text-fgAlt font-label group relative flex w-full items-center justify-between rounded px-1',
          fontSize,
          {
            'text-fgMain': isDefault,
            'text-fgDisabled': !isSelected && isDisabled,
            'text-fgDanger':
              !isSelected && (isGitDeleted || hasUnresolvedMergeConflict),
            'text-fgDangerActive':
              isSelected && (isGitDeleted || hasUnresolvedMergeConflict),
            'text-fgWarning':
              !isSelected && (isGitModified || hasResolvedMergeConflict),
            'text-fgWarningActive':
              isSelected && (isGitModified || hasResolvedMergeConflict),
            'text-fgSuccess': !isSelected && isGitAdded,
            'text-fgSuccessActive': isSelected && isGitAdded,
            'bg-bgMainActive text-fgAltActive': isSelected,
            'hover:bg-bgMainHover': !isSelected,
          },
        )}
      >
        <button
          data-testid="treeitem-button"
          disabled={node.disabled}
          onClick={(e) => onClick?.(e, node)}
          onKeyDown={(e) => {
            // we need to manually focus to get css to show button
            if (e.key === 'Tab') {
              actionMenuRef.current?.focus();
            }
          }}
          onContextMenu={(e) => {
            if (!hasFileActions) return;
            contextMenu.open(e);
            if (!contextMenu.isOpen) {
              e.stopPropagation();
            }
          }}
          className="w-full flex-1 items-center justify-between hover:cursor-pointer"
          aria-expanded={isDirectory ? isOpen : undefined}
          aria-selected={!isDirectory ? isSelected : undefined}
        >
          {isDirectory && <div role="group" aria-owns={node.ariaOwns} />}
          <div
            className="flex grow items-center space-x-1 overflow-hidden py-1"
            title={tooltipText || relativePath || undefined}
          >
            <div className="relative inline-flex items-center">
              {isExandButtonEnabled &&
                isDirectory &&
                (isOpen ? (
                  <Button
                    ryecon={RyeconCaretDown}
                    type="icon-button"
                    size={Sizes.sm}
                    className={classNames('mr-2 px-0 py-px', {
                      'absolute opacity-0 group-hover:opacity-100':
                        isCaretVisibleOnHover,
                    })}
                    onClick={(e) => {
                      onClick?.(
                        e as ReactMouseEvent<HTMLButtonElement, MouseEvent>,
                        node,
                        true,
                      );
                      e.stopPropagation();
                      e.preventDefault();
                    }}
                  />
                ) : (
                  <Button
                    ryecon={RyeconCaretRight}
                    type="icon-button"
                    size={Sizes.sm}
                    className={classNames('mr-2 px-0 py-px', {
                      'absolute opacity-0 group-hover:opacity-100':
                        isCaretVisibleOnHover,
                    })}
                    onClick={(e) => {
                      onClick?.(
                        e as ReactMouseEvent<HTMLButtonElement, MouseEvent>,
                        node,
                        true,
                      );
                      e.stopPropagation();
                      e.preventDefault();
                    }}
                  />
                ))}
              <Icon
                ryecon={labeledIcon.ryecon}
                alt={labeledIcon.label}
                size={Sizes.sm}
                className={classNames(twMerge('py-px', labeledIcon.className), {
                  'absolute opacity-100 group-hover:opacity-0':
                    isCaretVisibleOnHover && isDirectory,
                })}
              />
            </div>
            <div
              className={classNames('amp-mask dd-privacy-mask truncate', {
                italic: isDisabled,
              })}
            >
              <span className={classNames({ 'line-through': isGitDeleted })}>
                {node.name}
              </span>{' '}
              {node.relativePath && showFolderHint && (
                <span className="text-fgMain pl-2">
                  {getParentFolder(node.relativePath)}
                </span>
              )}
            </div>
            {node.info && (
              <div className="flex flex-1 items-end justify-end">
                {node.info.text && (
                  <span className={classNames('text-fgMain font-caption', fontSize)}>
                    {node.info.text}
                  </span>
                )}
                {node.info.icon && (
                  <Icon
                    ryecon={node.info.icon.ryecon}
                    alt={node.info.icon.label}
                    size={Sizes.xs}
                    className="text-fgMain"
                  />
                )}
              </div>
            )}
          </div>
        </button>

        <div className="absolute right-1 flex items-center opacity-100 group-focus-within:opacity-0">
          {isNodePathDirty && (
            <div
              data-testid="file-unsaved"
              className={classNames(
                'text-fgMain font-caption inline-flex w-4 select-none justify-center font-bold',
                {
                  'group-hover:hidden': hasFileActions || hasExtraActions,
                },
              )}
              role="img"
              aria-label="not saved"
              title="not saved"
            >
              •
            </div>
          )}

          {isChanged && (
            <div
              data-testid="file-changed"
              className={classNames(
                'font-caption inline-flex w-4 select-none justify-center',
                {
                  'font-bold': !useLetterBadge,
                  'font-medium': useLetterBadge,
                  'text-fgSuccess': isGitAdded,
                  'text-fgSuccessActive': isSelected && isGitAdded,
                  'text-fgWarning': isGitModified || hasResolvedMergeConflict,
                  'text-fgWarningActive':
                    (isSelected && isGitModified) ||
                    (isSelected && hasResolvedMergeConflict),
                  'text-fgDanger': isGitDeleted || hasUnresolvedMergeConflict,
                  'text-fgDangerActive': isSelected && isGitDeleted,
                  'group-hover:hidden': hasFileActions || hasExtraActions,
                },
              )}
              title={changedLabel}
            >
              {useLetterBadge ? (
                <span aria-label={changedLabel} className="text-inherit">
                  {gitStatusLetter}
                </span>
              ) : (
                <>
                  {isGitAdded && (
                    <Icon
                      ryecon={RyeconNewOutline}
                      size={Sizes.xs}
                      className="text-fgSuccess"
                      alt={changedLabel}
                    />
                  )}
                  {isGitModified && (
                    <Icon
                      ryecon={RyeconModifiedOutline}
                      size={Sizes.xs}
                      className="text-fgWarning"
                      alt={changedLabel}
                    />
                  )}
                  {isGitMergeConflict && (
                    <Icon
                      ryecon={RyeconModifiedOutline}
                      size={Sizes.xs}
                      className="text-fgDanger"
                      alt={changedLabel}
                    />
                  )}
                  {isGitDeleted && (
                    <Icon
                      ryecon={RyeconRemovedOutline}
                      size={Sizes.xs}
                      className="text-fgDanger"
                      alt={changedLabel}
                    />
                  )}
                </>
              )}
            </div>
          )}

          {hasUnresolvedMergeConflict && (
            <div
              data-testid="file-conflict"
              className={classNames('inline-flex select-none', {
                'group-hover:hidden': hasFileActions || hasExtraActions,
              })}
              title="Merge conflict"
            >
              <Icon
                ryecon={RyeconErrorOutline}
                size={Sizes.xs}
                className="text-fgDanger"
                alt="Merge conflict"
              />
            </div>
          )}
        </div>

        <div
          className={classNames(
            'absolute right-0 flex items-center group-focus-within:opacity-100',
            {
              'opacity-0': !node.actionsAlwaysVisible,
              'bg-inherit group-hover:opacity-100': hasExtraActions,
            },
          )}
        >
          {node.customActionsRenderer
            ? node.customActionsRenderer
            : node.actions?.map((action) => (
                <>
                  <MenuButton
                    items={action.items}
                    onClick={action.onMenuItemClick}
                    ryecon={action.ryecon}
                    text={action.text}
                    buttonStyle="tertiary"
                    size={Sizes.sm}
                    {...action.menuButtonProps}
                  />
                </>
              ))}
        </div>

        <div
          ref={actionMenuRef}
          className={classNames(
            'flex items-center opacity-0 group-focus-within:opacity-100',
            {
              'group-hover:opacity-100': hasFileActions,
            },
          )}
        >
          {hasFileActions && (
            <>
              <Button
                testId="file-contextmenu"
                className="font-caption h-6 cursor-pointer items-center rounded"
                type="icon-button"
                onClick={(e) => {
                  e.stopPropagation();
                  contextMenu.open(e);
                }}
                size={Sizes.xs}
                ryecon={RyeconEllipsisHorizontal}
                ariaLabel={`${node.pathType} actions for ${node.name}`}
              />
              <contextMenu.ContextMenu
                shouldPortal={true}
                alignment="right"
                placement="auto"
                items={menuItems}
                onClick={onMenuItemClick}
                scrollRootId="root"
                className="mb-4 mr-2"
              />
            </>
          )}
        </div>
      </div>
    );
  },
);
