import React from 'react';
import { PropsWithChildren } from 'react';
import cx from 'classnames';

import { Point, useChartContext } from '..';

export type TooltipOffset<S> = {
  offset?: number;
  override?: number;
  at?: S;
};

export interface VizTooltipProps {
  /** Id for testing */
  testId?: string;
}

/** @deprecated */
export const VizTooltip: React.FC<PropsWithChildren<VizTooltipProps>> = ({
  children,
  testId,
}) => {
  const context = useChartContext();
  const chartMeta = context?.chartMeta;
  const plots = context?.plots || {};
  if (!chartMeta) {
    return null;
  }
  const {
    setInteractionItem,
    cancelInteraction,
    interactionItem,
    xAccessor,
    yAccessor,
    xScale,
    yScale,
  } = chartMeta;

  const interactionMeta =
    interactionItem?.shape?.getInteractionMeta &&
    interactionItem.shape.getInteractionMeta({
      chartMeta,
      item: interactionItem.item,
      subItem: interactionItem.subItem,
      plot: plots[interactionItem.plotId],
    });

  const xPosition =
    (interactionItem && xScale.scale(xAccessor(interactionItem.item))) ?? 0;
  const xShapeOffset = interactionMeta?.tooltipX?.offset ?? 0;
  const yPosition =
    (interactionItem && yScale.scale(yAccessor(interactionItem.item))) ?? 0;
  const yShapeOffset = interactionMeta?.tooltipY?.offset ?? 0;

  const [tooltipX, tooltipY]: Point = [
    xPosition + xShapeOffset,
    yPosition + yShapeOffset,
  ];

  const positionStyle = {
    left: interactionMeta?.tooltipX?.override ?? tooltipX,
    top: interactionMeta?.tooltipY?.override ?? tooltipY,
  };

  const containerClasses = cx('pointer-events-auto absolute h-px w-px', {
    'pointer-events-none invisible': !interactionItem,
  });

  const tooltipXAt = interactionMeta?.tooltipX?.at ?? 'center';
  const tooltipYAt = interactionMeta?.tooltipY?.at ?? 'middle';

  return (
    <div
      // this is the positioned div for the tooltip
      // also the element we target when detecting
      // if the mouse is still hovered on an item.
      data-interaction-container
      onMouseLeave={() => setInteractionItem(null)}
      onMouseEnter={() => {
        cancelInteraction();
        setInteractionItem(interactionItem);
      }}
      data-testid={`tooltip-${testId}`}
      className={containerClasses}
      style={positionStyle}
    >
      <div
        className={cx('min-h-max min-w-max', {
          '-translate-x-1/2': tooltipXAt === 'center',
          '-translate-y-1/2': tooltipYAt === 'middle',
          '-translate-y-full': tooltipYAt === 'bottom',
          '-translate-x-full': tooltipXAt === 'right',
        })}
      >
        <div className="bg-bgMainHover text-fgMain dark rounded-md px-4 py-2">
          {children}
        </div>
      </div>
    </div>
  );
};
