import { Sizes } from '@/sourdough';
import { Button, type ButtonProps, type ButtonStyleType } from '../Button';
import type { Ryecon } from '../ryecons';
import { ModalAnimationContainer } from './ModalAnimationContainer';
import { ModalContentContainer } from './ModalContentContainer';

/**
 * 'blank' will hide the icon if none is specified.
 */
export type ModalTypes = 'success' | 'alert' | 'blank' | 'info';

export type ModalSize = 'standard' | 'fullScreen';

export type ModalActionProps = {
  text: React.ReactNode;
  onClick(): void;
  type?: ButtonStyleType;
  buttonProps?: Partial<Omit<ButtonProps, 'ryecon'>>;
  url?: string;
  ryecon?: Ryecon;
};

export const ModalAction: React.FC<ModalActionProps> = ({
  text,
  ryecon,
  onClick,
  type = 'primary',
  buttonProps = {},
  url,
}): React.ReactElement => {
  const modalButton = (
    <Button
      className="inline-flex w-full justify-center"
      {...buttonProps}
      onClick={onClick}
      type={type}
      ryecon={ryecon}
      size={Sizes.sm}
    >
      {text}
    </Button>
  );

  return url ? (
    <a href={url} target="_blank" rel="noopener noreferrer">
      {modalButton}
    </a>
  ) : (
    modalButton
  );
};

export type ModalProps = {
  /** Boolean representing whether the modal is open */
  isOpen: boolean;

  /** Content to display in the modal  */
  children: React.ReactNode;

  /** The modal title */
  title: string;

  /** If false, the title will only be available on screen readers */
  showTitle?: boolean;

  /** Alternative to icon - overrides icon when present */
  image?: React.ReactNode;

  /** An onclose handler function */
  onClose?(
    /** @deprecated `isOpen` was always false, and is not needed */
    isOpen?: boolean,
  ): void;

  /** An array of modal actions */
  actions?: ModalActionProps[];

  /** The modal type */
  modalType?: ModalTypes;

  /** The size of the modal */
  size?: ModalSize;

  /** Force enable dark mode. Useful since this element is portaled */
  forceDark?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** If you set this to false, you can allow hidden children to render even when the modal is closed */
  shouldFreezeContents?: boolean;

  /** Default: hidden - visible often needed for menus or dropdowns */
  overflow?: 'hidden' | 'visible';
};

export const Modal: React.FC<ModalProps> = ({
  isOpen,
  children,
  title,
  showTitle,
  image,
  onClose,
  actions,
  modalType,
  size,
  forceDark,
  testId = 'modal',
  trackingId = 'modal',
  shouldFreezeContents,
  overflow = 'hidden',
}): React.ReactElement => {
  // Determine if modal should be fullscreen based on size prop
  return (
    <ModalAnimationContainer
      isOpen={isOpen}
      onClose={onClose}
      shouldFreezeContents={shouldFreezeContents}
      forceDark={forceDark}
      testId={testId}
      trackingId={trackingId}
    >
      {(onClose: () => void) => {
        return (
          <ModalContentContainer
            children={children}
            title={title}
            showTitle={showTitle}
            image={image}
            onClose={onClose}
            actions={actions}
            modalType={modalType}
            modalSize={size}
            forceDark={forceDark}
            overflow={overflow}
          />
        );
      }}
    </ModalAnimationContainer>
  );
};
