import { useFormContext, useWatch } from '@/externals/react-hook-form';
import { HIDDEN_STRING } from '../../../globalConstants';
import type { DropdownOption } from '../../DropdownOptions';
import { Checkbox } from '../Checkbox/Checkbox';
import { Dropdown } from '../Dropdown/Dropdown';
import { Input } from '../Input/Input';
import { Textarea } from '../Textarea/Textarea';
import {
  fieldShouldShow,
  getDependedOnFields,
  optionShouldShow,
} from './helpers/dependencies';

export interface SchemaValidation {
  required?: boolean;
  min_length?: number;
  max_length?: number;
  min?: number;
  max?: number;
  pattern?:
    | 'email'
    | 'hostname'
    | 'fqdn'
    | 'databricks_hostname'
    | 'databricks_http_path';
}

export interface ConditionalDropdownOption extends DropdownOption {
  depends_on?: Record<string, string | number | boolean | (string | number)[]>;
}
export interface SchemaField {
  metadata: {
    field_type: 'text' | 'number' | 'select' | 'checkbox' | 'textarea' | 'hidden';
    label: string;
    description: React.ReactNode;
    encrypt?: boolean;
    options?: ConditionalDropdownOption[];
    validation?: SchemaValidation;
    // Array value represents an "OR" relationship
    // Multiple records represents an "AND" relationship
    depends_on?: Record<string, string | number | boolean | (string | number)[]>;
    // Used with 'select' to determine whether it's a searchable dropdown; defaults to `true`
    is_searchable?: boolean;
    // Allows ui's implementing this to override this value in other areas of the app
    overrideable?: boolean;
    // HTML step attribute for number inputs (e.g., 'any', '0.01', '0.1')
    step?: string;
  };
  value: string | number | boolean | null;
}

export interface FormSchema {
  fields: Record<string, SchemaField>;
  field_order?: string[];
}

export interface SchemaFieldsProps {
  /** The form schema */
  schema?: FormSchema;

  /** A list of fields to hide.
   * By default, schema fields can be conditionally rendered based on the value of other keys, but we sometimes need to
   * gate fields based on other values such as feature flags or account types.
   */
  hiddenFields?: string[];

  /** Override-mode only allows fields that are configured as overrideable to be edited */
  isOverride?: boolean;

  /** A boolean representing whether edit mode is enabled */
  isEdit?: boolean;

  /** Boolean representing whether to show a loading state */
  isLoading?: boolean;
}

export const SchemaFields: React.FC<SchemaFieldsProps> = ({
  schema,
  hiddenFields = [],
  isEdit = false,
  isLoading = false,
  isOverride = false,
}): React.ReactElement => {
  const fieldOrder = schema?.field_order || Object.keys(schema?.fields ?? {});
  const { getValues } = useFormContext();
  const allDependedOnFields = schema ? getDependedOnFields(schema) : [];

  // Watch forces react-hook-form to rerender on specific value changes
  // we use that mechanic to rerender when a depends_on field changes
  // to potentially show/hide additional fields
  useWatch({ name: allDependedOnFields });

  const fields: React.ReactNode[] = fieldOrder
    .filter((fieldKey) => {
      const field = schema?.fields[fieldKey];
      const shouldShow =
        !!field && fieldShouldShow(fieldKey, field, getValues, hiddenFields);
      return shouldShow;
    })
    .map((fieldKey) => {
      const field = schema?.fields[fieldKey];
      if (!field) {
        return null;
      }
      if (['text', 'number', 'password'].includes(field.metadata.field_type)) {
        const type = field.metadata.encrypt ? 'password' : field.metadata.field_type;
        return (
          <Input
            key={fieldKey}
            type={type as 'text' | 'number' | 'password'}
            name={fieldKey}
            id={fieldKey}
            label={field.metadata.label}
            description={field.metadata.description}
            isEdit={isEditOverride(field, isEdit, isOverride)}
            isOptional={!field.metadata.validation?.required}
            skeleton={isLoading}
            step={field.metadata.step}
          >
            {field.metadata.encrypt ? HIDDEN_STRING : field.value || '--'}
          </Input>
        );
      } else if (field.metadata.field_type === 'hidden') {
        const isBooleanField = typeof field.value === 'boolean';
        if (isBooleanField) {
          return (
            <Checkbox
              key={fieldKey}
              name={fieldKey}
              id={fieldKey}
              isHidden
              className="hidden"
              label={field.metadata.label}
              description={field.metadata.description}
              isEdit={isEditOverride(field, isEdit, isOverride)}
              skeleton={isLoading}
            />
          );
        }

        return (
          <Input
            key={fieldKey}
            type="hidden"
            className="hidden"
            name={fieldKey}
            id={fieldKey}
            isEdit={isEditOverride(field, isEdit, isOverride)}
            isOptional={!field.metadata.validation?.required}
            skeleton={isLoading}
          >
            {HIDDEN_STRING}
          </Input>
        );
      } else if (field.metadata.field_type === 'select') {
        const optionsToShow = (field.metadata.options ?? []).filter((option) =>
          optionShouldShow(option, getValues),
        );

        const optionValue = (field.metadata.options ?? []).find(
          (option) => option.value === field.value,
        );
        return (
          <Dropdown
            key={fieldKey}
            name={fieldKey}
            options={optionsToShow}
            isEdit={isEditOverride(field, isEdit, isOverride)}
            isOptional={!field.metadata.validation?.required}
            isSearchable={field.metadata.is_searchable}
            label={field.metadata.label}
            description={field.metadata.description}
            skeleton={isLoading}
          >
            {optionValue?.label || '--'}
          </Dropdown>
        );
      } else if (field.metadata.field_type === 'textarea') {
        return (
          <Textarea
            key={fieldKey}
            name={fieldKey}
            id={fieldKey}
            label={field.metadata.label}
            description={field.metadata.description}
            isEdit={isEditOverride(field, isEdit, isOverride)}
            isOptional={!field.metadata.validation?.required}
            skeleton={isLoading}
          >
            {field.metadata.encrypt ? HIDDEN_STRING : field.value || '--'}
          </Textarea>
        );
      } else if (field.metadata.field_type === 'checkbox') {
        return (
          <Checkbox
            key={fieldKey}
            name={fieldKey}
            id={fieldKey}
            label={field.metadata.label}
            description={field.metadata.description}
            isEdit={isEditOverride(field, isEdit, isOverride)}
            skeleton={isLoading}
          />
        );
      }
      return (
        <Input
          key={fieldKey}
          name={fieldKey}
          id={fieldKey}
          label={field.metadata.label}
          description={field.metadata.description}
          isEdit={isEditOverride(field, isEdit, isOverride)}
          isOptional={!field.metadata.validation?.required}
          skeleton={isLoading}
        >
          {field.value || '--'}
        </Input>
      );
    });

  return <>{fields}</>;
};

const isEditOverride = (field: SchemaField, isEdit: boolean, isOverride: boolean) => {
  if (!isOverride) {
    return isEdit;
  }
  if (isEdit) {
    return field.metadata.overrideable ?? false;
  }
  return false;
};
