import { useMemo } from 'react';
import cx from 'classnames';

import { HelpIcon } from '../../HelpIcon';

export interface FieldProps {
  /** Label for the field */
  label?: React.ReactNode;

  /** Visually hides the label */
  labelIsHidden?: boolean;

  /** Description for the field */
  description?: string;

  /** Content to show in a tooltip when hovering over help icon to the right of the label. Only present if label exists */
  tooltip?: React.ReactNode;

  /** A link to a help page. Will be placed on a help icon to the right of the label. Only present if label exists */
  helpLink?: string;

  onHelpClick?: () => void;

  /** Whether to display "optional" to the right of the label */
  isOptional?: boolean;

  /** Whether the component is in edit mode */
  isEdit?: boolean;

  /** The actual field input */
  children?: React.ReactNode;

  /* The classname(s) for the field wrapper */
  className?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /**  A boolean representing whether the field is disabled */
  isDisabled?: boolean;

  /** An id to use to associate the label with a specific element */
  labelFor?: string;
}

export const Field: React.FC<FieldProps> = ({
  className,
  children,
  label,
  description,
  tooltip,
  helpLink,
  onHelpClick,
  testId,
  trackingId,
  isEdit,
  isOptional,
  isDisabled = false,
  labelIsHidden = false,
  labelFor,
}): React.ReactElement => {
  const shouldHaveStandardStyles = !isDisabled;
  const shouldHaveDisabledStyles = isDisabled;

  const labelContent = useMemo(() => {
    if (!label) {
      return null;
    }

    return labelIsHidden ? (
      <div className="sr-only">
        {label}
        {isOptional && isEdit && ' Optional'}
      </div>
    ) : (
      <div className="mb-0.5 flex w-full items-center justify-between">
        <div className="flex items-center">
          <div
            className={cx('font-label block', {
              'text-fgAlt': shouldHaveStandardStyles,
              'text-fgDisabled': shouldHaveDisabledStyles,
            })}
          >
            {label}
          </div>
          {(Boolean(tooltip) || helpLink) && !onHelpClick && (
            <HelpIcon className="ml-1" tooltipContent={tooltip} linkTo={helpLink} />
          )}
          {onHelpClick && (
            <HelpIcon className="ml-1" tooltipContent={tooltip} onClick={onHelpClick} />
          )}
        </div>
        {isOptional && isEdit && (
          <span className="text-fgDecorative font-label ml-2">Optional</span>
        )}
      </div>
    );
  }, [
    label,
    labelIsHidden,
    tooltip,
    helpLink,
    onHelpClick,
    isOptional,
    isEdit,
    shouldHaveDisabledStyles,
    shouldHaveStandardStyles,
  ]);

  const descriptionContent = useMemo(() => {
    if (!description) {
      return null;
    }

    return (
      <p
        className="text-fgDecorative font-caption mb-2"
        data-testid={`${testId}-description`}
        data-trackingid={`${trackingId}-description`}
      >
        {description}
      </p>
    );
  }, [description, testId, trackingId]);

  const content = useMemo(() => {
    const _children = <div>{children}</div>;

    if (!labelContent) {
      return _children;
    }

    return labelFor ? (
      <div>
        <label className={labelIsHidden ? 'sr-only' : undefined} htmlFor={labelFor}>
          {labelContent}
          {descriptionContent}
        </label>
        {_children}
      </div>
    ) : (
      <label>
        {labelContent}
        {descriptionContent}
        {_children}
      </label>
    );
  }, [children, labelContent, descriptionContent, labelIsHidden, labelFor]);

  return (
    <div className={cx(className)} data-testid={testId} data-trackingid={trackingId}>
      {content}
    </div>
  );
};
