import { ActionList, Actions } from '../Actions';
import { Button } from '../Button';
import { RyeconCaretDown, RyeconCaretUp, RyeconClose } from '../ryecons';
import { Sizes } from '../types';

export interface DrawerActionBarProps {
  /** List of actions to display */
  actions?: ActionList;
  /** Event handler for close button click */
  onClose: () => void;
  /** Event handler for previous button click */
  onPrevious?: () => void;
  /** Event handler for next button click */
  onNext?: () => void;
  /** Whether the previous button is disabled */
  hasPrevious?: boolean;
  /** Whether the next button is disabled */
  hasNext?: boolean;
}

export const DrawerActionBar: React.FC<DrawerActionBarProps> = ({
  actions = [],
  onClose,
  onPrevious,
  onNext,
  hasPrevious = false,
  hasNext = false,
}) => {
  return (
    <div
      className="shadow-rest border-borderMuted flex w-full items-center justify-between border-b px-2 pb-[7px] pt-2"
      role="toolbar"
      aria-label="Drawer navigation"
      tabIndex={0}
    >
      <div className="flex items-center gap-1">
        <Button
          ryecon={RyeconClose}
          type="tertiary"
          size={Sizes.xs}
          onClick={onClose}
          data-testid="close-button"
          tooltip="Close (Esc)"
          tooltipPlacement="bottom"
          ariaLabel="Close drawer (Escape)"
        />
        {(onPrevious || onNext) && (
          <div
            className="border-borderMuted flex h-full items-center gap-0.5 border-l pl-1"
            role="group"
            aria-label="Row navigation"
          >
            {onPrevious && (
              <Button
                ryecon={RyeconCaretUp}
                onClick={onPrevious}
                size={Sizes.xs}
                type="tertiary"
                isDisabled={!hasPrevious}
                text="Prev"
                tooltip="Previous (↑)"
                tooltipPlacement="bottom"
                ariaLabel="Previous (Up arrow)"
              />
            )}
            {onNext && (
              <Button
                ryecon={RyeconCaretDown}
                onClick={onNext}
                size={Sizes.xs}
                type="tertiary"
                isDisabled={!hasNext}
                text="Next"
                tooltip="Next (↓)"
                tooltipPlacement="bottom"
                ariaLabel="Next (Down arrow)"
              />
            )}
          </div>
        )}
      </div>
      <div className="flex gap-2">
        <Actions actions={actions} size={Sizes.xs} />
      </div>
    </div>
  );
};
