import cx from 'classnames';

import { Button } from '../../Button/Button';
import { Icon } from '../../Icon';
import type { Ryecon } from '../../ryecons/types';
import { Sizes } from '../../types';
import { DEFAULT_BUTTON_GROUP_CHILD_CLASSES } from '../ButtonGroup';

type BaseButtonGroupButtonProps = {
  /** Accessible label for the button: optional for backward compatibility, will be required soon */
  label?: string;

  /** The text to display in the button */
  text?: React.ReactNode;

  /** Text to display on hover, like alt-text. The button's title. */
  title?: string;

  ryecon?: Ryecon;

  /** A classname for the icon */
  iconClassName?: string;

  /** The location of the icon */
  iconPlacement?: 'left' | 'right';

  /** An Onclick handler function */
  onClick?(event: React.MouseEvent): void;

  /** Custom button classnames */
  className?: string;

  /** The button size */
  size?: Sizes;

  /** flag to disable the button */
  isDisabled?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;
};

export type ButtonGroupButtonProps = BaseButtonGroupButtonProps;

export const ButtonGroupButton: React.FC<ButtonGroupButtonProps> = ({
  text,
  title,
  label,
  ryecon,
  iconClassName,
  iconPlacement = 'left',
  onClick,
  className,
  size = Sizes.md,
  isDisabled = false,
  testId = 'button-group-button',
  trackingId = 'button-group-button',
}): React.ReactElement => {
  const isIconOnly = !text || text?.toString().length === 0;

  const hasIcon = !!ryecon;
  const buttonIcon = hasIcon && (
    <Icon
      ryecon={ryecon}
      size="sm"
      className={cx('inline', iconClassName)}
      testId={`${testId}-icon`}
    />
  );

  return (
    <Button
      className={cx(
        DEFAULT_BUTTON_GROUP_CHILD_CLASSES,
        className,
        'flex items-center only:w-full',
      )}
      ariaLabel={label}
      buttonType="button"
      variant="group"
      type="secondary"
      size={size}
      testId={testId}
      trackingId={trackingId}
      onClick={onClick}
      isDisabled={isDisabled}
    >
      {iconPlacement === 'left' && buttonIcon}
      {isIconOnly ? (
        ''
      ) : (
        <>
          <span className="truncate" title={title}>
            {text}
          </span>
          {iconPlacement === 'right' && buttonIcon}
        </>
      )}
    </Button>
  );
};
