import cx from 'classnames';

interface CaptionProps {
  /** The text to render */
  children: string;
  /** An optional testId for cypress */
  testId?: string;
  /** class overrides to add to <p> */
  className?: string;
}

export const Caption = ({ children, testId, className = '' }: CaptionProps) => (
  <p className={cx('font-caption', className)} data-testid={testId}>
    {children}
  </p>
);
