import { useMemo } from 'react';
import { useWindowSize } from 'react-use';
import cx from 'classnames';

import { AccordionBody } from '../Accordion/AccordionBody.internal';
import { AccordionIcon } from '../Accordion/AccordionIcon.internal';
import useAccordion from '../Accordion/useAccordion.internal';
import { ActionList, Actions } from '../Actions';
import { InvisibleButton } from '../InvisibleButton';

export interface SubSectionProps {
  /** The header of the subsection */
  header: string;
  /** The tagline / subheader of the subsection. Generally a string, but can also be a component */
  tagline?: React.ReactNode;
  /** A set of actions to display above the main content in the right column */
  actions?: ActionList;
  /** The class of the subsection */
  className?: string;
  /** The content of the right column of the subsection */
  children?: React.ReactNode;
  /** If the subsection be expanded / collapsed */
  isAccordion?: boolean;
  /** If this is a settings page, use different breakpoints to accommodate the narrower content area */
  isSettingsPage?: boolean;
  /** If the subsection accordion should render open by default */
  initialOpen?: boolean;
  /** If the subsection accordion is disabled */
  isDisabled?: boolean;
  /** Callback for when open is toggled */
  onToggleOpen?: (open: boolean) => void;
  /** Test id */
  testId?: string;
  /** Tracking id */
  trackingId?: string;
}

export const SubSection: React.FC<SubSectionProps> = ({
  header,
  tagline,
  actions = [],
  className,
  children,
  isAccordion = false,
  isSettingsPage = false,
  isDisabled = false,
  initialOpen = false,
  onToggleOpen,
  testId,
  trackingId,
}): React.ReactElement => {
  const { width } = useWindowSize();

  const { contentHeight, contentRef, isOpen, toggleOpen } = useAccordion({
    initialOpen,
    onToggleOpen,
  });

  const hasActions = actions.length > 0;

  const breakpointWidth = isSettingsPage ? 1200 : 960;

  const renderBodyActions = hasActions && width >= breakpointWidth;
  const renderHeaderActions = hasActions && width < breakpointWidth;

  const taglineEl = useMemo(() => {
    const isString = typeof tagline === 'string';

    if (isString) {
      return <p className="text-fgDecorative font-caption mt-1">{tagline}</p>;
    }
    return tagline;
  }, [tagline]);

  const actionsEl = (
    <div className="flex flex-shrink-0 items-center justify-end gap-1">
      <Actions actions={actions} />
    </div>
  );

  let headerEl = (
    <div className="flex items-start justify-between">
      <div>
        <h3 className="text-fgMain font-heading-3 leading-6">{header}</h3>
        {!!tagline && taglineEl}
      </div>
      {renderHeaderActions && actionsEl}
    </div>
  );

  let body = (
    <>
      {renderBodyActions && <div className="mb-2">{actionsEl}</div>}
      {children}
    </>
  );

  if (isAccordion) {
    headerEl = (
      <InvisibleButton
        aria-expanded={isOpen}
        disabled={isDisabled}
        onClick={toggleOpen}
        className="mr-0 flex w-full items-center justify-between gap-3 text-left"
      >
        {headerEl}
        <AccordionIcon
          isDisabled={isDisabled}
          isOpen={isOpen}
          className="flex-shrink-0"
        />
      </InvisibleButton>
    );

    body = (
      <AccordionBody isOpen={isOpen} height={contentHeight} ref={contentRef}>
        {body}
      </AccordionBody>
    );
  }

  return (
    <section
      className={cx(className, 'flex w-full flex-col items-start gap-6', {
        'min-[1280px]:flex-row': !isSettingsPage,
        'min-[1440px]:flex-row': isSettingsPage,
      })}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      <div className="w-full flex-shrink-0 sm:w-full md:w-80 lg:w-96">{headerEl}</div>
      <div className="w-full min-w-0 flex-grow space-y-3">{body}</div>
    </section>
  );
};
