import React from 'react';
import { useContext, useEffect, useState } from 'react';

export interface SkeletonContext {
  skeleton: boolean;
  setSkeleton: React.Dispatch<React.SetStateAction<boolean>>;
}

const SkeletonContextContext = React.createContext<SkeletonContext>({
  skeleton: false,
  setSkeleton: () => {},
});

export interface SkeletonContextProviderProps {
  children: React.ReactNode;
  isSkeleton: boolean;
}

export function SkeletonContextProvider({
  children,
  isSkeleton = false,
}: SkeletonContextProviderProps) {
  const [skeleton, setSkeleton] = useState<boolean>(isSkeleton);

  useEffect(() => {
    setSkeleton(isSkeleton);
  }, [isSkeleton]);

  const value = { skeleton, setSkeleton };

  return (
    <SkeletonContextContext.Provider value={value}>
      {children}
    </SkeletonContextContext.Provider>
  );
}

export function useSkeletonContext(): SkeletonContext | undefined {
  const context = useContext(SkeletonContextContext);

  return context;
}
