import { MouseEvent, useCallback } from 'react';

import { Button, ButtonProps } from '../Button';
import { Sizes } from '../types';
type AccordionActionProps = ButtonProps;

const AccordionAction = ({ onClick, ...props }: AccordionActionProps) => {
  const _onClick = useCallback(
    (e: MouseEvent<HTMLButtonElement>) => {
      e.stopPropagation();
      onClick && onClick(e);
    },
    [onClick],
  );

  return <Button {...props} onClick={_onClick} size={Sizes.sm} />;
};

export { AccordionAction };
