import React from 'react';
import { Menu } from '@headlessui/react';
import cx from 'classnames';

import { MenuItems } from '@/sourdough';
import { Badge } from '../Badge';
import { Icon } from '../Icon';
import { Link } from '../Link';
import { LoadingBlock } from '../LoadingBlock/LoadingBlock';
import { RyeconCaretDown, RyeconFile, RyeconFolder, RyeconHome } from '../ryecons';
import { Ryecon } from '../ryecons/types';
import { BreadcrumbsProps } from './types';

const iconMap: Record<string, Ryecon> = {
  home: RyeconHome,
  folder: RyeconFolder,
  file: RyeconFile,
};

const breadcrumbClassNames = {
  base: 'flex items-center gap-1 p-1 border-none rounded-md font-label',
  interactive:
    'cursor-pointer text-fgAlt hover:bg-bgMainHover hover:text-fgAltHover focus:bg-bgMainHover focus:ring-focusBrand focus:ring-offset-2 focus:outline-none active:bg-bgMainActive active:text-fgAltActive',
  nonInteractive: 'text-fgDecorative cursor-default',
};

export const Breadcrumbs: React.FC<BreadcrumbsProps> = ({
  breadcrumbs,
  onItemClick,
  'aria-label': ariaLabel = 'Breadcrumb',
  className,
}) => {
  return (
    <nav aria-label={ariaLabel} className={cx('flex items-center gap-0.5', className)}>
      <ul className="m-0 flex list-none flex-wrap items-center gap-x-0.5 gap-y-0 p-0">
        {breadcrumbs.map((breadcrumb, index) => {
          const isLast = index === breadcrumbs.length - 1;
          const IconComponent = breadcrumb.icon ? iconMap[breadcrumb.icon] : undefined;

          return (
            <li key={breadcrumb.id ?? index} className="flex items-center gap-1">
              {breadcrumb.skeleton ? (
                <>
                  {index > 0 && (
                    <span
                      aria-hidden="true"
                      className="text-fgDisabled font-label"
                      role="presentation"
                    >
                      /
                    </span>
                  )}
                  <LoadingBlock width={125} height={18} />
                </>
              ) : (
                <>
                  {breadcrumb.dropdown ? (
                    <Menu as="div" className="relative">
                      <Menu.Button
                        onClick={() => onItemClick?.(breadcrumb)}
                        aria-current={isLast ? 'page' : undefined}
                        className={cx(
                          breadcrumbClassNames.base,
                          breadcrumbClassNames.interactive,
                        )}
                      >
                        {IconComponent && (
                          <Icon
                            ryecon={IconComponent}
                            size="sm"
                            alt={`${breadcrumb.icon} icon`}
                          />
                        )}
                        {breadcrumb.text}
                        {breadcrumb.badge && (
                          <Badge
                            text={breadcrumb.badge}
                            type={breadcrumb.badgeType || 'info'}
                            size="xxs"
                            className="font-normal"
                          />
                        )}
                        <Icon
                          ryecon={RyeconCaretDown}
                          size="sm"
                          alt="Show more options"
                        />
                      </Menu.Button>
                      <MenuItems
                        items={breadcrumb.dropdown.items}
                        onClick={(item, event) =>
                          breadcrumb.dropdown?.onClick?.(item, event)
                        }
                        className={breadcrumb.dropdown.className}
                      />
                    </Menu>
                  ) : breadcrumb.href ? (
                    <Link
                      isInternal={true}
                      to={breadcrumb.href}
                      onClick={() => onItemClick?.(breadcrumb)}
                      hideUnderline={true}
                      colorVariant="headless"
                      aria-current={isLast ? 'page' : undefined}
                      className={cx(
                        breadcrumbClassNames.base,
                        breadcrumbClassNames.interactive,
                      )}
                    >
                      {IconComponent && (
                        <Icon
                          ryecon={IconComponent}
                          size="sm"
                          alt={`${breadcrumb.icon} icon`}
                        />
                      )}
                      {breadcrumb.text}
                      {breadcrumb.badge && (
                        <Badge
                          text={breadcrumb.badge}
                          type={breadcrumb.badgeType || 'info'}
                          size="xs"
                        />
                      )}
                    </Link>
                  ) : (
                    <span
                      aria-current={isLast ? 'page' : undefined}
                      className={cx(
                        breadcrumbClassNames.base,
                        breadcrumbClassNames.nonInteractive,
                      )}
                    >
                      {IconComponent && (
                        <Icon
                          ryecon={IconComponent}
                          size="sm"
                          alt={`${breadcrumb.icon} icon`}
                        />
                      )}
                      {breadcrumb.text}
                      {breadcrumb.badge && (
                        <Badge
                          text={breadcrumb.badge}
                          type={breadcrumb.badgeType || 'info'}
                          size="xs"
                        />
                      )}
                    </span>
                  )}
                  {!isLast && (
                    <span
                      aria-hidden="true"
                      className="text-fgDisabled font-label"
                      role="presentation"
                    >
                      /
                    </span>
                  )}
                </>
              )}
            </li>
          );
        })}
      </ul>
    </nav>
  );
};
