import {
  type ReactNode,
  useCallback,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from 'react';
import {
  Cell,
  type ColumnDef,
  getCoreRowModel,
  TableOptions,
  useReactTable,
} from '@tanstack/react-table';
import cx from 'classnames';

import { useVirtualTableProps } from '../hooks';
import { EmptyStateRow } from '../subcomponents/EmptyStateRow.internal';
import { HeaderRow } from '../subcomponents/HeaderRow.internal';
import { TableRow } from '../subcomponents/TableRow.internal';
import { CommonTableProps, DefaultTData, Header, SortingState } from '../types';
import type { SortableTableProps } from '../types.internal';
import { createLoadingColumns, createLoadingRows } from '../utils';

import './CompactTable.css';

export type SelectionState = { [key: string]: boolean };

type CompactOnlyProps<TData> = {
  rowHeight: number;
  height: number;
  /** # of rows to load into DOM beyond scroll container */
  overscanCount?: number;
  enableCellSelection?: boolean | ((cell: Cell<TData, unknown>) => boolean);
  cellSelection?: SelectionState;
  onCellClick?: (cell: Cell<TData, unknown>, isSelected: boolean) => void;
  /** # of columns (and their cells) to load into DOM beyond scroll container */
  columnOverscanCount?: number;
  control?: CompactTableControl;
};

export type CompactTableProps<
  TData extends DefaultTData,
  TValue extends React.ReactNode = React.ReactNode,
> = CommonTableProps<TData, TValue> & CompactOnlyProps<TData> & SortableTableProps;

export const CompactTable = <
  TData extends DefaultTData,
  TValue extends React.ReactNode = React.ReactNode,
>({
  columns,
  data,
  emptyStateProps,
  loadingRowCount = 5,
  isLoading = false,
  rowHeight,
  testId = 'compact-table',
  trackingId = 'compact-table',
  className,
  height,
  overscanCount = 25,
  columnOverscanCount = 5,
  enableCellSelection,
  cellSelection,
  onCellClick,
  cellVariant = 'COMPACT',
  isSortable,
  initialSortColumn,
  initialSortDesc,
  onChangeSort,
  control,
}: CompactTableProps<TData, TValue>): React.ReactElement => {
  const memoizedColumns = useMemo(
    () => (isLoading ? createLoadingColumns<TData, TValue>(columns) : columns),
    [columns, isLoading],
  );
  const memoizedData = useMemo<TData[]>(() => {
    if (isLoading) {
      return createLoadingRows(loadingRowCount);
    }
    return data;
  }, [data, isLoading, loadingRowCount]);

  const initialSortId = useMemo(() => {
    if (!isSortable) {
      return '';
    }
    if (initialSortColumn) {
      return initialSortColumn;
    }
    return memoizedColumns[0]?.id ?? '';
  }, [initialSortColumn, memoizedColumns, isSortable]);

  const initialSortingState = useMemo<SortingState>(
    () => (isSortable ? [{ id: initialSortId, desc: initialSortDesc ?? false }] : []),
    [isSortable, initialSortId, initialSortDesc],
  );
  const [sorting, setSorting] = useState<SortingState>(initialSortingState);

  const handleSortingChange = useCallback(
    (getSortBy: any) => {
      if (onChangeSort && isSortable) {
        const newSortBy = getSortBy();
        setSorting(newSortBy); // update internal table `sorting` state
        onChangeSort(newSortBy); // inform caller of change
      }
    },
    [isSortable, onChangeSort],
  );

  // override column defaults so we can update column width manually
  const defaultColumn = {
    minSize: undefined,
    size: undefined,
    maxSize: undefined,
  };

  const tableOptions: TableOptions<TData> = {
    data: memoizedData,
    columns: memoizedColumns,
    defaultColumn,
    getCoreRowModel: getCoreRowModel(),
    // sorting config
    manualSorting: true,
    enableSortingRemoval: false,
    enableSorting: isSortable,
    state: { sorting },
    onSortingChange: handleSortingChange,
  };

  // https://react.dev/reference/eslint-plugin-react-hooks/lints/incompatible-library
  // eslint-disable-next-line react-hooks/incompatible-library
  const tableInstance = useReactTable(tableOptions);
  const { rows } = tableInstance.getRowModel();
  const headers = tableInstance.getFlatHeaders() as Header<TData, TValue>[];

  const tableContainerRef = useRef<HTMLDivElement>(null);

  const {
    virtualRows,
    virtualColumns,
    tableContentHeight,
    virtualPaddingLeft,
    virtualPaddingRight,
    visibleHeaders,
    colIdxOffset,
    columnVirtualizer,
  } = useVirtualTableProps({
    rows,
    columns: memoizedColumns as ColumnDef<TData, ReactNode>[],
    rowHeight,
    overscanCount,
    columnOverscanCount,
    tableContainerRef,
    headers,
  });

  const scrollToColumnIndex = useCallback(
    (index: number, options?: ScrollToOptions) =>
      columnVirtualizer.scrollToIndex(index, options),
    [columnVirtualizer],
  );

  useImperativeHandle(control?.ref, () => ({
    scrollToColumnIndex,
  }));

  const showEmpty = !rows.length && !isLoading;

  // relative for sticky header
  const scrollContainerClasses = cx('relative overflow-auto');
  // z-index required to stay on-top of absolute position rows
  const headerClasses = cx('bg-bgBackground border-borderMuted sticky top-0 z-10 grid');
  // grid helps calculate tbody content height
  const tableClasses = cx('compact-table grid w-full tabular-nums', className);
  // relative for absolute positioned rows
  const tbodyClasses = cx('relative grid');

  return (
    <div
      ref={tableContainerRef}
      style={{
        height,
      }}
      className={scrollContainerClasses}
      data-testid={`${testId}-scroll-container`}
    >
      <table className={tableClasses} data-testid={testId} data-trackingid={trackingId}>
        <thead className={headerClasses} style={{ height: rowHeight }}>
          <HeaderRow<TData, TValue>
            headers={visibleHeaders as Header<TData, TValue>[]}
            testId={testId}
            trackingId={trackingId}
            stickyColumn={undefined}
            colIdxOffset={colIdxOffset}
            virtualPaddingLeft={virtualPaddingLeft}
            virtualPaddingRight={virtualPaddingRight}
            cellVariant={cellVariant}
          />
        </thead>
        <tbody
          style={{
            height: tableContentHeight,
          }}
          className={tbodyClasses}
        >
          {showEmpty ? (
            <EmptyStateRow
              emptyStateProps={emptyStateProps}
              columnCount={columns.length}
              testId={testId}
              trackingId={trackingId}
              height={height - rowHeight}
            />
          ) : (
            virtualRows.map((virtualRow) => {
              const row = rows[virtualRow.index];
              const cells = row.getVisibleCells();

              // only render cells visible within virtual container
              const visibleCells = virtualColumns.map((vc) => cells[vc.index]);

              return (
                <TableRow<TData>
                  key={`row-${virtualRow.index}`}
                  row={row}
                  visibleCells={visibleCells as Cell<TData, ReactNode>[]}
                  virtualPaddingLeft={virtualPaddingLeft}
                  virtualPaddingRight={virtualPaddingRight}
                  colIdxOffset={colIdxOffset}
                  rowIdx={virtualRow.index}
                  isCompact={true}
                  onRowClickLinkGenerator={undefined}
                  testId={testId}
                  trackingId={trackingId}
                  handleRowClick={undefined}
                  isCellClickable={(cell) => {
                    return enableCellSelection instanceof Function
                      ? enableCellSelection(cell)
                      : enableCellSelection ?? !!cellSelection;
                  }}
                  handleCellClick={(cell) => {
                    const isEnabled =
                      enableCellSelection instanceof Function
                        ? enableCellSelection(cell)
                        : enableCellSelection ?? !!cellSelection;
                    if (isEnabled) {
                      onCellClick?.(cell, true);
                    } else {
                      onCellClick?.(cell, false);
                    }
                  }}
                  cellSelection={cellSelection}
                  rowHeight={rowHeight}
                  stickyColumn={undefined}
                  cellVariant={cellVariant}
                  style={{
                    height: rowHeight,
                    display: 'flex',
                    position: 'absolute',
                    transform: `translateY(${virtualRow.start}px)`,
                  }}
                />
              );
            })
          )}
        </tbody>
      </table>
    </div>
  );
};

type ScrollAlignment = 'start' | 'center' | 'end' | 'auto';
type ScrollBehavior = 'auto' | 'smooth';
type ScrollToOptions = {
  align?: ScrollAlignment;
  behavior?: ScrollBehavior;
};

export const useCompactTableControl = () => {
  const ref = useRef<{
    scrollToColumnIndex: (index: number, options?: ScrollToOptions) => void;
  }>(null);

  return useMemo(
    () => ({
      ref,
      scrollToColumnIndex: (index: number, options?: ScrollToOptions) => {
        ref.current?.scrollToColumnIndex(index, options);
      },
    }),
    [ref],
  );
};

export type CompactTableControl = ReturnType<typeof useCompactTableControl>;
