import { useCallback, useEffect, useMemo, useState } from 'react';
import ReactSelect, {
  ActionMeta,
  ClassNamesConfig,
  components,
  ControlProps,
  DropdownIndicatorProps,
  InputActionMeta,
  InputProps,
  MenuProps,
  OptionProps,
  SelectComponentsConfig,
  SingleValue,
  StylesConfig,
} from 'react-select';
import cx from 'classnames';

import { Controller, useFormContext } from '@/externals/react-hook-form';
import { BaseInputProps } from '../../../globalTypes';
import { Icon, useSkeletonContext } from '../../../sourdough';
import { get } from '../../../utils';
import { Avatar } from '../../Avatar';
import {
  type DropdownOption,
  type DropdownOptionGroup,
  getFlattenedDropdownOptions,
} from '../../DropdownOptions';
import { LoadingBlock } from '../../LoadingBlock/LoadingBlock';
import { type Ryecon } from '../../ryecons';
import { RyeconCaretDown, RyeconCheckmark } from '../../ryecons';
import { Field } from '../Field/Field';
import { FormFieldMessage } from '../FormFieldMessage/FormFieldMessage';

import './Dropdown.css';

// Classnames marked with (!) important are overriding internal react-select styling
const dropdownSizes: {
  [k: string]: {
    className: string;
    classNames?: ClassNamesConfig<DropdownOption, false, DropdownOptionGroup>;
  };
} = {
  xs: {
    className: 'min-h-[24px]',
    classNames: {
      control: () => '!min-h-[24px]',
    },
  },
  sm: {
    className: 'min-h-[32px]',
    classNames: {
      control: () => '!min-h-[32px]',
    },
  },
  md: {
    className: 'min-h-[40px]',
    classNames: {
      control: () => '!min-h-[40px]',
    },
  },
};

type CustomMenuButtonProps = {
  text: string;
  onClick: () => void;
  disabled?: boolean;
  ryecon?: Ryecon;
};

export interface BaseDropdownProps {
  /** The Name of the dropdown field **/
  name: string;

  /** An array of options for the dropdown */
  options: (DropdownOption | DropdownOptionGroup)[];

  /** The default value of the form */
  defaultValue?: DropdownOption | null;

  /** Helpful description text for the field */
  description?: React.ReactNode;

  /** Display (View-Only) Content */
  children?: React.ReactNode;

  /** Classname(s) for the wrapping element */
  className?: string;

  /** Classname(s) for the input element */
  inputClassName?: string;

  /** Any onChange handling, allows for extra handling past the default react-hook-form usage */
  onChange?: (selectedOption: DropdownOption) => void;

  customMenuButton?: CustomMenuButtonProps;

  /** Placeholder message when no items are selected */
  placeholder?: string;

  /** If passed, dropdown will be rendered on the specified element. Useful in contexts where a container might have overflow:hidden */
  portalElement?: HTMLElement | null;

  /** Flag to indicate react-select menuPlacement, when omitted it is set to 'auto' */
  shouldOpenBottom?: boolean;

  /** Allow dropdown filtering */
  isSearchable?: boolean;

  /** Custom filtering function to trigger when search terms are entered. Can be used for triggering backend search. */
  onSearch?: (searchTerm: string) => void;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;

  /** vertical height of dropdown input */
  size?: 'xs' | 'sm' | 'md';

  // Styles objects for react select
  reactSelectStyles?: StylesConfig<DropdownOption, false, DropdownOptionGroup>;

  // Component overrides for react select
  reactSelectComponents?: SelectComponentsConfig<
    DropdownOption,
    false,
    DropdownOptionGroup
  >;
}

export type DropdownProps = BaseInputProps & BaseDropdownProps;

interface CustomControlProps
  extends ControlProps<DropdownOption, false, DropdownOptionGroup> {
  shouldUsePlaceholderAvatars?: boolean;
  isSearchable: boolean;
  testId?: string;
}

const Control: React.FC<CustomControlProps> = ({
  shouldUsePlaceholderAvatars,
  children,
  testId,
  ...props
}) => {
  const selectedValue = props.getValue()[0] ?? undefined;
  return (
    <components.Control
      {...props}
      innerProps={{
        ...props.innerProps,
        ...{
          'data-testid': testId,
        },
      }}
    >
      {(!!selectedValue?.avatar || shouldUsePlaceholderAvatars) && (
        <Avatar size="2xs" src={selectedValue?.avatar} className="ml-3" />
      )}
      {!!selectedValue?.startIcon && (
        <Icon
          {...selectedValue.startIcon}
          className={cx('ml-2', selectedValue.startIcon.className)}
        />
      )}
      {children}
    </components.Control>
  );
};

const DropdownIndicator: React.FC<
  DropdownIndicatorProps<DropdownOption, false, DropdownOptionGroup>
> = (props) => (
  <components.DropdownIndicator {...props}>
    <Icon ryecon={RyeconCaretDown} className="text-fgAlt mr-1" size="xs" />
  </components.DropdownIndicator>
);

interface CustomOptionProps
  extends OptionProps<DropdownOption, false, DropdownOptionGroup> {
  shouldUsePlaceholderAvatars?: boolean;
}

const Option: React.FC<CustomOptionProps> = ({
  shouldUsePlaceholderAvatars,
  children,
  ...props
}) => {
  return (
    <components.Option
      {...props}
      className={cx({
        'border-borderMuted border-t': props.data.includeTopDivider,
        'border-borderMuted border-b': props.data.includeBottomDivider,
      })}
    >
      <div
        className="relative"
        data-testid={`dropdown-option-${props.data.value}`}
        data-trackingid={`dropdown-option-${props.data.value}`}
      >
        <div className={cx('flex items-center gap-2', { 'mr-5': props.isSelected })}>
          {(!!props.data.avatar || shouldUsePlaceholderAvatars) && (
            <Avatar size="2xs" src={props.data.avatar} className="shrink-0" />
          )}
          {!!props.data.startIcon && <Icon {...props.data.startIcon} />}
          <span
            className={cx('font-label break-all', {
              'text-fgDisabled': props.data.disabled,
            })}
          >
            {children}
          </span>
          {!!props.data.secondaryLabel && props.data.secondaryLabel}
        </div>
        {!!props.data.description && (
          <div
            className={cx('font-caption', {
              'text-fgDisabled': props.data.disabled,
              'text-fgDecorative': !props.data.disabled,
            })}
          >
            {props.data.description}
          </div>
        )}
        {props.isSelected && (
          <span className="text-fgBrand absolute inset-y-0 right-0 flex items-center">
            <Icon ryecon={RyeconCheckmark} size="xs" aria-hidden="true" />
          </span>
        )}
      </div>
    </components.Option>
  );
};

const CustomMenuButton: React.FC<CustomMenuButtonProps> = ({
  text,
  onClick,
  ryecon,
  disabled,
}) => {
  const buttonClasses = cx(
    'hover:bg-bgMainHover bg-bgMain text-fgMain border-borderMuted font-label mb-1 flex w-full items-center gap-1 rounded-b-md border-t px-3 py-[5px]',
    {
      'text-fgDisabled hover:cursor-not-allowed': disabled,
    },
  );

  const hasIcon = !!ryecon;

  return (
    <button
      type="button"
      onClick={onClick}
      disabled={disabled}
      aria-label={text}
      className={buttonClasses}
    >
      {hasIcon && <Icon ryecon={ryecon} size="xs" className="mr-1" />}
      {text}
    </button>
  );
};
interface CustomMenuProps
  extends MenuProps<DropdownOption, false, DropdownOptionGroup> {
  customMenuButton?: CustomMenuButtonProps;
  closeDropdown: () => void;
}

const Menu: React.FC<CustomMenuProps> = ({ customMenuButton, children, ...props }) => {
  const onCustomButtonClick = () => {
    props.closeDropdown();
    customMenuButton?.onClick();
  };

  return (
    <components.Menu {...props}>
      {children}
      {!!customMenuButton && (
        <CustomMenuButton {...customMenuButton} onClick={onCustomButtonClick} />
      )}
    </components.Menu>
  );
};

type DropdownComponentProps = Pick<
  DropdownProps,
  | 'isEdit'
  | 'options'
  | 'defaultValue'
  | 'onChange'
  | 'customMenuButton'
  | 'isDisabled'
  | 'testId'
  | 'trackingId'
  | 'portalElement'
  | 'shouldOpenBottom'
  | 'className'
  | 'inputClassName'
  | 'isSearchable'
  | 'onSearch'
  | 'children'
  | 'placeholder'
  | 'size'
  | 'reactSelectStyles'
  | 'reactSelectComponents'
>;

export const DropdownComponent: React.FC<DropdownComponentProps> = ({
  isEdit,
  options,
  defaultValue,
  onChange,
  customMenuButton,
  isDisabled = false,
  testId = 'dropdown',
  trackingId = 'dropdown',
  portalElement,
  shouldOpenBottom,
  className,
  inputClassName,
  isSearchable = true,
  onSearch,
  children,
  placeholder,
  size = 'md',
  reactSelectStyles,
  reactSelectComponents,
}) => {
  const [selected, setSelected] = useState<DropdownOption | null>(
    defaultValue || getFlattenedDropdownOptions(options)[0],
  );
  const [menuIsOpen, setMenuIsOpen] = useState(false);

  useEffect(() => {
    setSelected(defaultValue ?? null);
  }, [defaultValue]);

  const shouldUsePlaceholderAvatars = useMemo(() => {
    return getFlattenedDropdownOptions(options).some(({ avatar }) => !!avatar);
  }, [options]);

  const handleChange = (
    newValue: SingleValue<DropdownOption>,
    _: ActionMeta<DropdownOption>,
  ) => {
    setMenuIsOpen(false);
    if (newValue) {
      setSelected(newValue);
      onChange?.(newValue);
    }
  };

  const handleInputChange = (newValue: string, meta: InputActionMeta) => {
    if (meta.action === 'input-change' && onSearch) {
      onSearch(newValue);
    }
  };

  // These components are memoized to prevent a lost focus issue related
  // re-renders of custom components:
  // https://github.com/JedWatson/react-select/issues/3575#issuecomment-1833012025

  const customControlComponent = useCallback(
    (props: Omit<CustomControlProps, 'isSearchable'>) => {
      return (
        <Control
          shouldUsePlaceholderAvatars={shouldUsePlaceholderAvatars}
          isSearchable={isSearchable}
          testId={testId}
          {...props}
        />
      );
    },
    [shouldUsePlaceholderAvatars, isSearchable, testId],
  );

  const customInputComponent = useCallback(
    (props: InputProps<DropdownOption, false, DropdownOptionGroup>) => (
      <components.Input
        {...props}
        inputClassName={cx(props.inputClassName, inputClassName)}
      />
    ),
    [inputClassName],
  );

  const filterOption = useMemo(() => {
    // If a custom onSearch function is provided,
    // ignore react-select's built in frontend filtering.
    // without frontend filtering
    if (onSearch) {
      return () => true;
    }
    return undefined;
  }, [onSearch]);

  return (
    <>
      {!isEdit && (
        <div
          className={cx(
            'bg-bgDisabled text-fgMain font-body-sm flex items-center truncate rounded-md px-3 py-2',
            {
              'min-h-[24px]': size === 'xs',
              'min-h-[32px]': size === 'sm',
              'min-h-[40px]': size === 'md',
            },
            className,
          )}
          data-testid={`${testId}-display`}
          data-trackingid={`${trackingId}-display`}
        >
          <div className="-ml-px mt-px">{children || (defaultValue?.label ?? '')}</div>
        </div>
      )}
      {isEdit && (
        <ReactSelect<DropdownOption, false, DropdownOptionGroup>
          options={options}
          value={selected}
          placeholder={placeholder}
          menuIsOpen={menuIsOpen}
          onMenuOpen={() => setMenuIsOpen(true)}
          onMenuClose={() => setMenuIsOpen(false)}
          onChange={handleChange}
          isDisabled={isDisabled}
          menuPlacement={
            shouldOpenBottom === undefined
              ? 'auto'
              : shouldOpenBottom
                ? 'bottom'
                : 'top'
          }
          hideSelectedOptions={false}
          className={cx('dropdown-container', dropdownSizes[size].className, className)}
          classNamePrefix="dropdown"
          menuPortalTarget={portalElement}
          isSearchable={isSearchable}
          onInputChange={handleInputChange}
          filterOption={filterOption}
          styles={{
            ...reactSelectStyles,
            // @ts-ignore
            menuPortal: (baseStyles, props) => ({
              ...baseStyles,
              zIndex: 100, // Ensure portal always appears above other elements
              ...(reactSelectStyles?.menuPortal?.(baseStyles, props) || {}),
            }),
          }}
          classNames={{
            ...dropdownSizes[size].classNames,
          }}
          isOptionDisabled={(option) => !!option.disabled}
          components={{
            Option: (props) => (
              <Option
                shouldUsePlaceholderAvatars={shouldUsePlaceholderAvatars}
                {...props}
              />
            ),
            Control: customControlComponent,
            DropdownIndicator,
            Input: customInputComponent,
            Menu: (props) => (
              <Menu
                {...props}
                customMenuButton={customMenuButton}
                closeDropdown={() => setMenuIsOpen(false)}
              />
            ),
            ...reactSelectComponents,
          }}
        />
      )}
    </>
  );
};

type DropdownFieldComponentProps = Pick<
  DropdownProps,
  | 'name'
  | 'isEdit'
  | 'isOptional'
  | 'label'
  | 'tooltip'
  | 'helpLink'
  | 'onHelpClick'
  | 'description'
  | 'skeleton'
  | 'error'
  | 'isDisabled'
  | 'testId'
  | 'trackingId'
  | 'className'
  | 'children'
>;

const DropdownFieldComponent: React.FC<DropdownFieldComponentProps> = ({
  name,
  isEdit,
  isOptional,
  label,
  tooltip,
  helpLink,
  onHelpClick,
  description,
  skeleton,
  error,
  isDisabled = false,
  testId = 'dropdown',
  trackingId = 'dropdown',
  className,
  children,
}) => {
  const formSkeleton = useSkeletonContext()?.skeleton;
  const shouldSkeleton = skeleton || formSkeleton;

  const hasError = !!error;

  return (
    <Field
      label={label}
      tooltip={tooltip}
      helpLink={helpLink}
      onHelpClick={onHelpClick}
      className={cx(className, {
        'dropdown-input-error': hasError, // Enables custom classes for error states
      })}
      isDisabled={isDisabled}
      isOptional={isOptional}
      isEdit={isEdit}
      testId={`${testId}-wrapper`}
      trackingId={`${trackingId}-wrapper`}
    >
      {!shouldSkeleton && children}
      {shouldSkeleton && (
        <LoadingBlock loaderClassName="min-h-input w-full rounded-md" />
      )}

      <FormFieldMessage
        name={name}
        description={description}
        errorMessage={error}
        isEdit={isEdit}
        testId={testId}
        trackingId={trackingId}
      />
    </Field>
  );
};

export const Dropdown: React.FC<DropdownProps> = ({
  className,
  ...props
}): React.ReactElement => {
  const { name, defaultValue, onChange: providedOnChange, options, error } = props;

  const formContext = useFormContext();
  const errors = formContext?.formState.errors;
  const errorMessage = get(errors && errors, name)?.message ?? error;

  return (
    <>
      {!!formContext?.control && (
        <Controller
          control={formContext.control}
          name={name}
          render={({ field: { onChange: hookFormChange, value } }) => {
            const selectedOption =
              defaultValue ||
              getFlattenedDropdownOptions(options).find(
                (option) => String(option.value) === String(value),
              );
            return (
              <DropdownFieldComponent
                {...props}
                className={className}
                error={errorMessage}
              >
                <DropdownComponent
                  {...props}
                  defaultValue={selectedOption}
                  onChange={(value) => {
                    if (providedOnChange && value) {
                      providedOnChange(value);
                    }
                    hookFormChange(value.value);
                  }}
                />
              </DropdownFieldComponent>
            );
          }}
        />
      )}
      {!formContext?.control && (
        <DropdownFieldComponent {...props} className={className} error={errorMessage}>
          <DropdownComponent {...props} onChange={providedOnChange} />
        </DropdownFieldComponent>
      )}
    </>
  );
};
