import { Component, ErrorInfo, Fragment, PropsWithChildren } from 'react';
import cx from 'classnames';

import { Disclosure, Transition } from '@/externals/headlessui';
import { Button } from '../Button/Button';
import { Icon } from '../Icon/Icon';
import { RyeconCaretDown, RyeconWarningOutline } from '../ryecons';
import { Sizes } from '../types';

export type ErrorBoundaryProps = {
  /** Suppresses UI-rendered error details, useful in production */
  isProd?: boolean;
  /** add to make "contact support" actionable */
  onContactSupport?: () => void;
  trackError?: (error: Error, errorInfo: ErrorInfo) => void;
};

type ErrorBoundaryState = {
  error: Error | null;
  errorInfo: ErrorInfo | null;
};

export class ErrorBoundary extends Component<PropsWithChildren<ErrorBoundaryProps>> {
  state: ErrorBoundaryState = {
    error: null,
    errorInfo: null,
  };

  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { error: null, errorInfo: null };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    // Catch errors in any components below and re-render with error message
    this.setState({
      error: error,
      errorInfo: errorInfo,
    });
    // You can also log error messages to an error reporting service here
    const { trackError } = this.props;
    trackError?.(error, errorInfo);
  }

  render() {
    const { errorInfo } = this.state;
    const { children, isProd, onContactSupport } = this.props;

    const messageCtaText = 'contact our support team';
    const messageCta =
      onContactSupport && isProd ? (
        <Button
          className="px-0 py-0"
          onClick={onContactSupport}
          size={Sizes.xl}
          testId="error-message-cta"
          type="tertiary"
        >
          {messageCtaText}
        </Button>
      ) : (
        messageCtaText
      );

    if (errorInfo) {
      // Error path
      return (
        <>
          <div className="mt-20 flex flex-col items-center p-20">
            <Icon
              ryecon={RyeconWarningOutline}
              size="4xl"
              className="text-fgDecorative mt-20"
            />
            <h1 className="text-fgMain font-heading-1 mt-7">Something went wrong</h1>
            <p className="text-fgAlt font-body mt-4">
              Please try reloading the page. If the problem persists, {messageCta} for
              help.
            </p>
            {!isProd && (
              <Disclosure>
                {({ open }) => (
                  <div className="w-1/2">
                    <div className="mt-8 flex items-center justify-between gap-4 p-3">
                      <p className="text-fgDecorative font-label-lg">Error details</p>
                      <Disclosure.Button>
                        <Icon
                          ryecon={RyeconCaretDown}
                          size="md"
                          className={cx('text-fgDecorative', {
                            'rotate-180': open,
                          })}
                          testId="expand-error-details"
                          trackingId="expand-error-details"
                        />
                      </Disclosure.Button>
                    </div>
                    <Transition
                      as={Fragment}
                      enter="transition ease-out duration-200"
                      enterFrom="opacity-0 translate-y-1"
                      enterTo="opacity-100 translate-y-0"
                      leave="transition ease-in duration-150"
                      leaveFrom="opacity-100 translate-y-0"
                      leaveTo="opacity-0 translate-y-1"
                    >
                      <div className="bg-bgDangerMuted text-fgDanger font-code max-h-96 overflow-scroll rounded-md px-4 py-3">
                        <div className="mb-4">
                          {this.state.error && this.state.error.toString()}
                        </div>
                        <div className="ml-4">{errorInfo.componentStack}</div>
                      </div>
                    </Transition>
                  </div>
                )}
              </Disclosure>
            )}
          </div>
        </>
      );
    }
    // Normally, just render children
    return <>{children}</>;
  }
}
