import { ScaleBand, scaleBand } from 'd3';
import { twMerge } from 'tailwind-merge';

import { ColorSet } from '../../Chart';
import { Accessor, Shape } from '../../types';
import { calculateXPosition } from '../../util';
import { isPlotFocused } from '../../util/plot';
import { Scale } from '../../util/scales';
import { Bar, BarExtras, createBarClassNames, TOOLTIP_BAR_PADDING } from '../Bar/Bar';

export interface BarGroupExtras extends BarExtras {
  groupValuesAccessor?: Accessor<any, number[]>;
  colors?: ColorSet[];
  testId?: string;
}

const MAX_BAR_WIDTH = 25;

export type BarGroupDatum = { index: number; value: unknown; subPlotName?: string };

/** @deprecated */
export const BarGroup: Shape<BarGroupExtras & { item: unknown }> = (props) => {
  const {
    chartMeta,
    xAccessor,
    yAccessor,
    className,
    item: unknownItem,
    isHorizontal = false,
    groupValuesAccessor,
    plotId,
    getColor,
    testId = 'bargroup',
  } = props;
  // position of the bar is dictated by the bar's width, set by the scale
  // if we were always using the bandwidth we'd be able to just set x to the scale value
  const item = unknownItem as any[];
  // Where do the groups fall on the overall chart
  const positionalScale = isHorizontal ? chartMeta?.yScale : chartMeta?.xScale; // how do we get the value of the item to determine where the bar falls
  const positionalAccessor = isHorizontal ? yAccessor : xAccessor;
  const positionalValue = positionalAccessor ? positionalAccessor(item) : 0;
  // where do we position the group of bars
  const groupPosition = positionalScale?.scale(positionalValue) ?? 0;
  const groupSpace = calculateXPosition(positionalScale, false, MAX_BAR_WIDTH);
  const groupValues: number[] = groupValuesAccessor ? groupValuesAccessor(item) : [];

  const groupScale: Scale<ScaleBand<number>, 'category'> = {
    scale: scaleBand<number>()
      .domain(groupValues.map((_, idx) => idx))
      .paddingInner(0.2)
      .paddingOuter(0)
      .range([0, groupSpace]),
    kind: 'category',
  };

  const groupLabelAccessor: Accessor = (d: any) => d.index;
  const groupSingleValueAccessor: Accessor = (d: any) => d.value;

  return (
    <g
      transform={`translate(${isHorizontal ? 0 : groupPosition},${
        isHorizontal ? groupPosition : 0
      })`}
      height={isHorizontal ? groupSpace : chartMeta?.plotHeight}
      className={className}
      stroke="none"
      data-testid={testId}
    >
      {groupValues.map((value: number, idx: number) => {
        const subItem: BarGroupDatum = {
          value,
          index: idx,
        };

        return (
          <Bar
            key={idx}
            {...props}
            className={twMerge(
              createBarClassNames(
                getColor(idx),
                isPlotFocused(chartMeta?.focusPlotId, plotId, idx),
                chartMeta?.interactionItem?.item === item &&
                  (chartMeta?.interactionItem?.subItem as BarGroupDatum)?.index ===
                    subItem.index,
              ),
              className,
            )}
            item={subItem}
            xAccessor={isHorizontal ? groupSingleValueAccessor : groupLabelAccessor}
            yAccessor={isHorizontal ? groupLabelAccessor : groupSingleValueAccessor}
            positionalScale={groupScale}
            subPlotIndex={idx}
            testId={`${testId}-bar-${idx}`}
          />
        );
      })}
    </g>
  );
};

BarGroup.shapeName = 'BarGroup';
BarGroup.getInteractionMeta = ({ chartMeta, plot, item: _item }) => {
  const isHorizontal = !!plot.extraItemProps?.isHorizontal;
  const positionalScale = isHorizontal ? chartMeta?.yScale : chartMeta?.xScale; // how do we get the value of the item to determine where the bar falls

  // where do we position the group of bars
  const groupSpace = calculateXPosition(positionalScale, false, MAX_BAR_WIDTH);

  if (chartMeta) {
    return isHorizontal
      ? {
          tooltipX: {
            offset: TOOLTIP_BAR_PADDING,
            at: 'left',
          },
          tooltipY: {
            at: 'middle',
            offset: groupSpace / 2,
          },
        }
      : {
          tooltipX: {
            offset: groupSpace / 2,
            at: 'center',
          },
          tooltipY: {
            at: 'bottom',
            offset: -TOOLTIP_BAR_PADDING,
          },
        };
  }

  return {};
};

BarGroup.getInteractionPoints = ({ chartMeta, plot, item }) => {
  const isHorizontal = !!plot.extraItemProps?.isHorizontal;
  const plotHeight = chartMeta?.plotHeight ?? 0;

  const positionalScale = isHorizontal ? chartMeta?.yScale : chartMeta?.xScale; // how do we get the value of the item to determine where the bar falls
  const positionalAccessor = isHorizontal ? plot.yAccessor : plot.xAccessor;
  const positionalValue = positionalAccessor ? positionalAccessor(item) : 0;
  // where do we position the group of bars
  const groupPosition = positionalScale?.scale(positionalValue) ?? 0;
  const groupSpace = calculateXPosition(positionalScale, false, MAX_BAR_WIDTH);
  const groupValuesAccessor = plot.extraItemProps?.groupValuesAccessor;
  const groupValues: number[] = groupValuesAccessor ? groupValuesAccessor(item) : [];

  const groupScale: Scale<ScaleBand<number>, 'category'> = {
    scale: scaleBand<number>()
      .domain(groupValues.map((_, idx) => idx))
      .paddingInner(0.2)
      .paddingOuter(0)
      .range([0, groupSpace]),
    kind: 'category',
  };

  return groupValues.map((value, idx) => ({
    plotName: plot.name,
    plotId: plot.id,
    fullItem: item,
    subItem: {
      value,
      index: idx,
      subPlotName: plot?.name?.[idx],
    },
    shape: plot.shape,
    point: [
      isHorizontal
        ? plotHeight
        : groupPosition +
          (groupScale.scale(idx) ?? 0) +
          groupScale.scale?.bandwidth() / 2,
      isHorizontal
        ? groupPosition +
          (groupScale.scale(idx) ?? 0) +
          groupScale.scale?.bandwidth() / 2
        : plotHeight,
    ],
  }));
};

/** @deprecated */
export const BarGroups: Shape<BarGroupExtras> = (props) => {
  const { data, chartMeta } = props;
  const testIdPrefix = chartMeta?.testId ?? 'chart';
  return (
    <>
      {data?.map<React.ReactNode>((item, idx) => (
        <BarGroup
          {...props}
          item={item}
          key={idx}
          testId={`${testIdPrefix}-bargroup-group-${idx}`}
        />
      ))}
    </>
  );
};

BarGroups.shapeName = 'BarGroups';
BarGroups.getInteractionMeta = BarGroup.getInteractionMeta;
BarGroups.getInteractionPoints = BarGroup.getInteractionPoints;
