import { forwardRef, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useResizeDetector } from 'react-resize-detector';
import { VariableSizeList } from 'react-window';

import type { SourdoughComponent } from '../../globalTypes';
import { Button } from '../Button/Button';
import { DropdownOption } from '../DropdownOptions/DropdownOptions';
import { Dropdown } from '../forms/Dropdown/Dropdown';
import { Input } from '../forms/Input/Input';
import { Toggle } from '../forms/Toggle/Toggle';
import { RyeconCheckmark, RyeconCopy, RyeconDownload } from '../ryecons';
import { Sizes } from '../types';
import { LogLine, LogLineProps, LogLineType } from './LogLine';
import { getDisplayTimestamp, getSanitizedMessage, getTypeList } from './utils';

export type DownloadOption = {
  /** Optional copy button tooltip & accessible label; defaults to "Copy logs" */
  copyButtonLabel?: string;
  /** Optional download button tooltip & accessible label; defaults to "Download logs" */
  downloadButtonLabel?: string;
  /** Optional filename for download */
  downloadFileName?: string;
  /** Enable copy functionality */
  enableCopy: boolean;
  /** Enable download functionality */
  enableDownload: boolean;
  /** Allow additional behavior on downloading */
  onDownload?: () => void;
};

/** Configure controls to render in regular & debug views; each option is independent of the other! */
export interface DownloadConfig {
  logs?: DownloadOption;
  debugLogs?: DownloadOption;
}

export interface LogsProps extends SourdoughComponent {
  /** An array of log lines to display */
  logs: LogLineProps[];

  /** Maximum height of the logs container */
  maxHeight?: number;

  /** Whether to enable virtualization (default: true) */
  virtualized?: boolean;

  /** Optional enable local time tooltips */
  showLocalTime?: boolean;

  /** Optional enable URL linking for log lines */
  enableUrlLinking?: boolean;

  /** Optional enable search functionality */
  enableSearch?: boolean;

  /** Optional enable log filtering and badges */
  enableFiltering?: boolean;

  /** Optional enable debug log toggle */
  enableDebugToggle?: boolean;

  /** Optional debug logs to show on toggle. Otherwise, `logs` of type `debug` are used */
  debugLogs?: LogLineProps[];

  /** Optional config for download functionality */
  downloadConfig?: DownloadConfig;

  /** @deprecated use downloadConfig instead. Optional enable download & copy functionality */
  enableDownload?: boolean;

  /** @deprecated use downloadConfig instead. Optional filename for download */
  downloadFilename?: string;

  /** Optional log types to show as filterable options displayed in order (default: ['success', 'skipped', 'reused', 'error', 'warning', 'info', 'debug']) */
  filterableTypes?: LogLineType[];
}

// Constants for virtualization
const LINE_HEIGHT = 24; // 18px line height + 6px padding
const LIST_HEIGHT_PADDING = 50;
const DEFAULT_MAX_HEIGHT = 400;

const DEFAULT_DOWNLOAD_FILE_NAME = 'logs.txt';

export const Logs = forwardRef<VariableSizeList, LogsProps>(
  (
    {
      logs,
      debugLogs,
      maxHeight = DEFAULT_MAX_HEIGHT,
      virtualized = true,
      showLocalTime = false,
      enableUrlLinking = false,
      enableSearch = false,
      enableFiltering = false,
      enableDebugToggle = false,
      downloadConfig,
      enableDownload = false,
      downloadFilename = 'logs.txt',
      filterableTypes = [
        'success',
        'skipped',
        'reused',
        'error',
        'warning',
        'info',
        'debug',
      ],
      testId = 'logs',
      trackingId = 'logs',
    },
    ref,
  ): React.ReactElement | null => {
    // State for search and filtering
    const [searchTerm, setSearchTerm] = useState('');
    const [showDebugLogs, setShowDebugLogs] = useState(false);
    const [selectedFilter, setSelectedFilter] = useState<DropdownOption | null>(null);
    const [isCopied, setIsCopied] = useState(false);

    const logSource = useMemo(() => {
      // Filter by debug toggle
      if (showDebugLogs) {
        return debugLogs !== undefined ? debugLogs : logs;
      } else if (enableDebugToggle) {
        return logs.filter(
          (log) => !(log.type && getTypeList(log.type).includes('debug')),
        );
      }

      return logs;
    }, [logs, debugLogs, showDebugLogs, enableDebugToggle]);

    // Filter logs based on search term and debug toggle
    const filteredLogs = useMemo(() => {
      let filtered = logSource;

      // Filter by search term
      if (searchTerm) {
        filtered = filtered.filter(
          (log) =>
            log.message.toLowerCase().includes(searchTerm.toLowerCase()) ||
            log.timestamp.toLowerCase().includes(searchTerm.toLowerCase()),
        );
      }

      // Filter by selected filter
      if (selectedFilter && selectedFilter.value !== 'all') {
        filtered = filtered.filter(
          (log) =>
            log.type &&
            getTypeList(log.type).includes(selectedFilter.value as LogLineType),
        );
      }

      return filtered;
    }, [logSource, searchTerm, selectedFilter]);

    // Generate filter options with counts
    const filterOptions = useMemo(() => {
      if (!enableFiltering) return [];

      const counts: Record<LogLineType, number> = {
        success: 0,
        skipped: 0,
        reused: 0,
        error: 0,
        warning: 0,
        info: 0,
        debug: 0,
        summary: 0,
        disabled: 0,
        deprecation: 0,
      };

      // Count all log types
      logSource.forEach((log) => {
        const type = log.type;
        if (type) {
          getTypeList(type).forEach((type) => {
            if (counts.hasOwnProperty(type)) {
              counts[type]++;
            }
          });
        }
      });

      const options: DropdownOption[] = [];

      // Always show "All" option
      options.push({ label: `All`, value: 'all' });

      // Add filter options for each filterable type that has logs
      filterableTypes.forEach((type) => {
        const count = counts[type];
        if (count > 0) {
          options.push({ label: `${type} (${count})`, value: type });
        }
      });

      return options;
    }, [logSource, enableFiltering, filterableTypes]);

    const {
      copyButtonLabel,
      downloadButtonLabel,
      shouldDisplayCopy,
      shouldDisplayDownload,
      fileName,
      onDownload,
    } = useMemo(() => {
      const copyButtonLabel = 'Copy logs';
      const downloadButtonLabel = 'Download logs';

      if (downloadConfig) {
        const configSource = showDebugLogs
          ? downloadConfig.debugLogs
          : downloadConfig.logs;

        return {
          copyButtonLabel: configSource?.copyButtonLabel ?? copyButtonLabel,
          downloadButtonLabel: configSource?.downloadButtonLabel ?? downloadButtonLabel,
          shouldDisplayCopy: !!configSource?.enableCopy,
          shouldDisplayDownload: !!configSource?.enableDownload,
          fileName: configSource?.downloadFileName ?? DEFAULT_DOWNLOAD_FILE_NAME,
          onDownload: configSource?.onDownload,
        };
      }

      // backwards compatible download behavior
      return {
        copyButtonLabel,
        downloadButtonLabel,
        shouldDisplayCopy: !!enableDownload,
        shouldDisplayDownload: !!enableDownload,
        fileName: downloadFilename ?? DEFAULT_DOWNLOAD_FILE_NAME,
      };
    }, [showDebugLogs, downloadConfig, enableDownload, downloadFilename]);

    // If the filter options have changed, the selected option may no longer be valid and needs to be re-evaluated
    useEffect(() => {
      const potentialMatch = filterOptions.find(
        (option) => option.value === selectedFilter?.value,
      );

      if (!potentialMatch) {
        // filter no longer exists
        setSelectedFilter(null);
      } else if (potentialMatch.label !== selectedFilter?.label) {
        // filter has a match and state should be updated
        setSelectedFilter(potentialMatch);
      }

      // otherwise, the selectedFilter is correct and no action is taken
    }, [filterOptions, selectedFilter]);

    // Download functionality
    const getDownloadableContent = useCallback(() => {
      const logContent = filteredLogs
        .map(
          (log) =>
            `${getDisplayTimestamp(log.timestamp)} ${getSanitizedMessage(
              log.message,
              Boolean(log.isHtml || log.isAnsi),
            )}`,
        )
        .join('\n');

      const temporaryElement = document.createElement('div');
      temporaryElement.innerHTML = logContent;
      return temporaryElement.textContent ?? '';
    }, [filteredLogs]);

    // Download functionality
    const handleDownload = useCallback(() => {
      const logContent = getDownloadableContent();

      const blob = new Blob([logContent], { type: 'text/plain' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = fileName;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

      onDownload && onDownload();
    }, [getDownloadableContent, fileName, onDownload]);

    // Copy logs functionality
    const handleCopy = useCallback(() => {
      const logContent = getDownloadableContent();

      navigator.clipboard.writeText(logContent);
      setIsCopied(true);

      setTimeout(() => {
        setIsCopied(false);
      }, 2000);
    }, [getDownloadableContent]);

    // Scroll to log line if URL hash matches
    useEffect(() => {
      if (enableUrlLinking && typeof window !== 'undefined') {
        const hash = window.location.hash;
        if (hash) {
          const targetId = hash.substring(1); // Remove the #
          const targetElement = document.getElementById(targetId);
          if (targetElement) {
            // Small delay to ensure virtualization has rendered
            setTimeout(() => {
              targetElement.scrollIntoView({
                behavior: 'smooth',
                block: 'center',
              });
            }, 100);
          }
        }
      }
    }, [enableUrlLinking, logs.length]);
    const { width, ref: containerRef } = useResizeDetector({
      refreshMode: 'debounce',
      refreshRate: 0,
    });

    const virtualizedListRef = useRef<VariableSizeList>(null);
    // Used to store the computed heights of each row. Virtualized lists don't know their own height
    const rowHeightsCache = useRef<Record<number, number>>({});
    // Track the total cached height in state so we can use it during render
    const [totalCachedHeight, setTotalCachedHeight] = useState(0);

    // Used by the row to store the height it should be after rendering
    const setRowHeight = (index: number, size: number) => {
      rowHeightsCache.current = { ...rowHeightsCache.current, [index]: size };
      setTotalCachedHeight(
        Object.values(rowHeightsCache.current).reduce((sum, value) => sum + value, 0),
      );
      virtualizedListRef.current?.resetAfterIndex(index);
    };

    // Reset cached heights when filtered logs change
    useEffect(() => {
      rowHeightsCache.current = {};
      setTotalCachedHeight(0);
    }, [filteredLogs]);

    // If we don't already know the height of the current row, use the default
    const getRowHeight = (index: number) => {
      return Math.max(LINE_HEIGHT, rowHeightsCache.current[index] ?? 0);
    };

    // Calculate list height
    const listHeight = useMemo(() => {
      if (!virtualized) {
        return 'auto';
      }

      const calculatedHeight =
        Math.max(filteredLogs.length * LINE_HEIGHT, totalCachedHeight) +
        LIST_HEIGHT_PADDING;

      // Don't go over max height
      return Math.min(calculatedHeight, maxHeight);
    }, [filteredLogs.length, maxHeight, virtualized, totalCachedHeight]);

    if (!logs.length) {
      return null;
    }

    // Render header with controls if any are enabled
    const renderHeader = () => {
      const hasControls =
        enableSearch ||
        enableFiltering ||
        enableDebugToggle ||
        shouldDisplayCopy ||
        shouldDisplayDownload;

      if (!hasControls) return null;

      return (
        <div className="mb-4 flex flex-1 items-center justify-between">
          <div className="flex flex-wrap items-center gap-2">
            {/* Search input */}
            {enableSearch && (
              <Input
                name="log-search"
                placeholder="Search logs..."
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                }}
                testId={`${testId}-search`}
                trackingId={`${trackingId}-search`}
                isEdit={true}
                sizeVariant="xs"
                labelIsHidden={true}
              />
            )}

            {/* Filter dropdown */}
            {enableFiltering && filterOptions.length > 0 && (
              <Dropdown
                className="capitalize"
                name="log-filter"
                options={filterOptions}
                placeholder="Filter logs"
                defaultValue={selectedFilter}
                onChange={(option) => setSelectedFilter(option)}
                testId={`${testId}-filter`}
                trackingId={`${trackingId}-filter`}
                isEdit={true}
                size="xs"
                reactSelectStyles={{
                  menu: (provided) => ({
                    ...provided,
                    minWidth: '160px',
                    width: 'auto',
                  }),
                }}
              />
            )}

            {/* Debug toggle */}
            {enableDebugToggle && (
              <Toggle
                testId={`${testId}-debug-toggle`}
                name="debug-toggle"
                label="Debug logs"
                defaultEnabled={showDebugLogs}
                onChange={(enabled) => setShowDebugLogs(enabled)}
                isEdit
              />
            )}
          </div>

          <div className="flex flex-wrap items-center gap-4">
            {/* Download and copy buttons */}
            {(shouldDisplayCopy || shouldDisplayDownload) && (
              <div className="flex items-center gap-2">
                {shouldDisplayCopy && (
                  <Button
                    onClick={handleCopy}
                    type="secondary"
                    isDisabled={isCopied}
                    ryecon={isCopied ? RyeconCheckmark : RyeconCopy}
                    testId={`${testId}-copy`}
                    size={Sizes.xs}
                    tooltip={copyButtonLabel}
                  />
                )}
                {shouldDisplayDownload && (
                  <Button
                    onClick={handleDownload}
                    type="secondary"
                    ryecon={RyeconDownload}
                    testId={`${testId}-download`}
                    size={Sizes.xs}
                    tooltip={downloadButtonLabel}
                  />
                )}
              </div>
            )}
          </div>
        </div>
      );
    };

    if (!virtualized) {
      return (
        <div data-testid={testId} data-trackingid={trackingId} ref={containerRef}>
          {renderHeader()}
          <div className="font-mono text-sm">
            {filteredLogs.map((log, index) => (
              <LogLine
                key={`${log.timestamp}-${index}`}
                {...log}
                showLocalTime={showLocalTime}
                lineId={enableUrlLinking ? `${testId}-line-${index}` : undefined}
                testId={`${testId}-line-${index}`}
                trackingId={`${trackingId}-line-${index}`}
              />
            ))}
          </div>
        </div>
      );
    }

    return (
      <div data-testid={testId} data-trackingid={trackingId} ref={containerRef}>
        {renderHeader()}
        <div className="font-mono text-sm">
          <VariableSizeList
            className="overflow-y-scroll"
            height={listHeight}
            itemCount={filteredLogs.length}
            itemSize={(index) => getRowHeight(index)}
            itemData={filteredLogs}
            width={width ?? 0}
            ref={ref || virtualizedListRef}
          >
            {({ data, index, style }) => (
              <VirtualizedLogLine
                style={style}
                index={index}
                logLine={data[index]}
                setRowHeight={setRowHeight}
                skipRowHeight={width == null} // Don't measure row height until we know the list width
                showLocalTime={showLocalTime}
                enableUrlLinking={enableUrlLinking}
                testId={`${testId}-line-${index}`}
                trackingId={`${trackingId}-line-${index}`}
              />
            )}
          </VariableSizeList>
        </div>
      </div>
    );
  },
);

// Virtualized log line component that handles height measurement
interface VirtualizedLogLineProps {
  style: React.CSSProperties;
  index: number;
  logLine: LogLineProps;
  setRowHeight: (index: number, size: number) => void;
  skipRowHeight: boolean;
  showLocalTime?: boolean;
  enableUrlLinking?: boolean;
  testId?: string;
  trackingId?: string;
}

// Helper function to get element height with fallback strategies
const getElementHeight = (
  rowElement: HTMLDivElement | null,
  logLineElement: HTMLDivElement | null,
): number => {
  if (!rowElement) {
    return LINE_HEIGHT;
  }

  // Use the LogLine ref if available, otherwise fallback to querying
  const elementToMeasure = logLineElement || rowElement.querySelector('[data-testid]');

  if (elementToMeasure) {
    return Math.max(
      elementToMeasure.scrollHeight,
      elementToMeasure.clientHeight,
      LINE_HEIGHT,
    );
  }

  // Fallback to container height
  return Math.max(rowElement.clientHeight, LINE_HEIGHT);
};

const VirtualizedLogLine: React.FC<VirtualizedLogLineProps> = ({
  style,
  index,
  logLine,
  setRowHeight,
  skipRowHeight,
  showLocalTime = false,
  enableUrlLinking = false,
  testId,
  trackingId,
}) => {
  const rowRef = useRef<HTMLDivElement>(null);
  const logLineRef = useRef<HTMLDivElement>(null);

  const setHeight = useCallback(() => {
    if (rowRef.current && !skipRowHeight) {
      const actualHeight = getElementHeight(rowRef.current, logLineRef.current);
      setRowHeight(index, actualHeight);
    }
  }, [index, skipRowHeight, setRowHeight]);

  // If the row ever changes size, update the height
  useResizeDetector({
    targetRef: rowRef,
    onResize: setHeight,
  });

  // Set initial height and recalculate when content changes
  useEffect(() => {
    const timer = setTimeout(() => {
      setHeight();
    }, 0);
    return () => clearTimeout(timer);
  }, [logLine.message, setHeight]); // Recalculate when content changes

  return (
    <div style={style} ref={rowRef}>
      <div className="w-full" ref={logLineRef}>
        <LogLine
          {...logLine}
          showLocalTime={showLocalTime}
          lineId={enableUrlLinking ? testId : undefined}
          testId={testId}
          trackingId={trackingId}
        />
      </div>
    </div>
  );
};
