import { stack } from 'd3';
import { twMerge } from 'tailwind-merge';

import { ColorSet } from '../../Chart';
import { ChartMeta } from '../../ChartProvider/ChartProvider';
import { InteractionPoint } from '../../InteractionLayer/InteractionLayer';
import { Accessor, Shape } from '../../types';
import { calculateXPosition, isPlotFocused } from '../../util';
import { Bar, BarExtras, createBarClassNames, TOOLTIP_BAR_PADDING } from '../Bar';

export interface BarStackExtras extends BarExtras {
  groupValuesAccessor?: Accessor<any, number[]>;
  colors?: ColorSet[];
  testId?: string;
}

const MAX_BAR_WIDTH = 25;

export type BarStackDatum = { index: number; value: unknown };

const getStackedData = (groupValues: number[]) => {
  // ex. go from groupValues = [10, 20] to stackedData = [[0, 10], [10, 30]]]
  const shapedData = groupValues.reduce<Record<string, number>>((acc, curr, idx) => {
    acc[idx.toString()] = curr;
    return acc;
  }, {});
  const stackKeys = Object.keys(shapedData);
  return stack()
    .keys(stackKeys)([shapedData])
    .map((value) => value[0]);
};

const getXPositionStart = (chartMeta: ChartMeta, valueStart: number) => {
  const posStart = chartMeta.xScale?.scale(valueStart as any) || 0;
  return posStart - (chartMeta.margin?.left || 0);
};

const getYPositionStart = (chartMeta: ChartMeta, valueStart: number) => {
  const posStart = chartMeta.yScale?.scale(valueStart as any) || 0;
  return -((chartMeta.plotHeight || 0) - posStart);
};

/** @deprecated */
export const BarStack: Shape<BarStackExtras & { item: unknown }> = (props) => {
  const {
    chartMeta,
    xAccessor,
    yAccessor,
    className,
    item: unknownItem,
    isHorizontal = false,
    groupValuesAccessor,
    testId = 'barstack',
    getColor,
    plotId,
  } = props;
  // position of the bar is dictated by the bar's width, set by the scale
  // if we were always using the bandwidth we'd be able to just set x to the scale value
  const item = unknownItem as any[];
  // Where do the groups fall on the overall chart
  const positionalScale = isHorizontal ? chartMeta?.yScale : chartMeta?.xScale; // how do we get the value of the item to determine where the bar falls
  const positionalAccessor = isHorizontal ? yAccessor : xAccessor;
  const positionalValue = positionalAccessor ? positionalAccessor(item) : 0;
  // where do we position the group of bars
  const groupPosition = positionalScale?.scale(positionalValue) ?? 0;
  const groupValues: number[] = groupValuesAccessor ? groupValuesAccessor(item) : [];
  const stackedData = getStackedData(groupValues);

  const groupLabelAccessor: Accessor = (d: any) => d.index;
  const groupSingleValueAccessor: Accessor = (d: any) => d.value;

  return (
    <g
      transform={`translate(${isHorizontal ? 0 : groupPosition},${
        isHorizontal ? groupPosition : 0
      })`}
      height={isHorizontal ? 0 : chartMeta?.plotHeight}
      className={className}
      stroke="none"
      data-testid={testId}
    >
      {stackedData.map((value: number[], idx: number) => {
        const [valueStart, valueEnd] = value;
        const height = valueEnd - valueStart;

        const subItem: BarStackDatum = {
          value: height,
          index: idx,
        };

        let transform;
        if (chartMeta) {
          if (isHorizontal) {
            transform = `translate(${getXPositionStart(chartMeta, valueStart)}, 0)`;
          } else {
            transform = `translate(0,${getYPositionStart(chartMeta, valueStart)})`;
          }
        }

        return (
          <g key={idx} transform={transform}>
            <Bar
              key={idx}
              {...props}
              className={twMerge(
                'transition-colors',
                createBarClassNames(
                  getColor(idx),
                  isPlotFocused(chartMeta?.focusPlotId, plotId, idx),
                  chartMeta?.interactionItem?.item === item &&
                    (chartMeta?.interactionItem?.subItem as BarStackDatum)?.index ===
                      subItem.index,
                ),
                className,
              )}
              item={subItem}
              xAccessor={isHorizontal ? groupSingleValueAccessor : groupLabelAccessor}
              yAccessor={isHorizontal ? groupLabelAccessor : groupSingleValueAccessor}
              testId={`${testId}-bar-${idx}`}
              subPlotIndex={idx}
            />
          </g>
        );
      })}
    </g>
  );
};

BarStack.shapeName = 'BarStack';

BarStack.getInteractionMeta = ({ chartMeta, plot, item, subItem }) => {
  const isHorizontal = !!plot.extraItemProps?.isHorizontal;

  const groupValuesAccessor = plot.extraItemProps?.groupValuesAccessor;

  // Where do the groups fall on the overall chart
  const positionalScale = isHorizontal ? chartMeta?.yScale : chartMeta?.xScale;
  const groupValues: number[] = groupValuesAccessor ? groupValuesAccessor(item) : [];
  const stackedData = getStackedData(groupValues);

  // where do we position the group of bars
  const groupSpace = calculateXPosition(positionalScale, false, MAX_BAR_WIDTH);

  // @ts-ignore
  const subIndex: number = subItem?.index;

  const [barPositionalStart, barPositionalEnd] = stackedData[subIndex];

  const xCenterBar = (barPositionalEnd - barPositionalStart) / 2;

  if (chartMeta) {
    return isHorizontal
      ? {
          tooltipX: {
            at: 'left',
            override:
              chartMeta.xScale?.scale((barPositionalStart + xCenterBar) as any) ?? 0,
          },
          tooltipY: {
            at: 'top',
            offset: groupSpace / 2,
          },
        }
      : {
          tooltipX: {
            offset: groupSpace / 2,
            at: 'center',
          },
          tooltipY: {
            at: 'bottom',
            override:
              chartMeta?.plotHeight +
              getYPositionStart(chartMeta, barPositionalEnd) -
              TOOLTIP_BAR_PADDING,
          },
        };
  }

  return {};
};

const MAX_VORONOI_DISTANCE = 70;

BarStack.getInteractionPoints = ({ chartMeta, plot, item }) => {
  const isHorizontal = !!plot.extraItemProps?.isHorizontal;

  const positionalScale = isHorizontal ? chartMeta?.yScale : chartMeta?.xScale; // how do we get the value of the item to determine where the bar falls
  const positionalAccessor = isHorizontal ? plot.yAccessor : plot.xAccessor;
  const positionalValue = positionalAccessor ? positionalAccessor(item) : 0;
  // where do we position the group of bars
  const groupPosition = positionalScale?.scale(positionalValue) ?? 0;
  const groupValuesAccessor = plot.extraItemProps?.groupValuesAccessor;
  const groupValues: number[] = groupValuesAccessor ? groupValuesAccessor(item) : [];
  const stackedData = getStackedData(groupValues);

  const barThickness =
    positionalScale?.kind === 'category'
      ? positionalScale?.scale.bandwidth()
      : MAX_BAR_WIDTH;

  const xScale = (value: number) => chartMeta?.xScale.scale(value as any) || 0;
  const yScale = (value: number) => chartMeta?.yScale.scale(value as any) || 0;

  return stackedData.flatMap((value: number[], idx: number) => {
    const [posStart, posEnd] = value;
    const interactionPoint = {
      plotName: plot.name,
      plotId: plot.id,
      fullItem: item,
      shape: plot.shape,
      subItem: {
        value: groupValues[idx],
        index: idx,
        subPlotName: plot?.name?.[idx],
      },
    };

    const a = isHorizontal ? xScale(posStart) : yScale(posStart);
    const b = isHorizontal ? xScale(posEnd) : yScale(posEnd);

    const numPoints = 2 + Math.floor(Math.abs(b - a) / MAX_VORONOI_DISTANCE);

    const result: InteractionPoint[] = [];
    for (let i = 0; i < numPoints; i++) {
      const pos = posStart + (posEnd - posStart) * (i / (numPoints - 1));
      result.push({
        ...interactionPoint,
        point: isHorizontal
          ? [xScale(pos) + (i === 0 ? -1 : 1), groupPosition + barThickness / 2]
          : [groupPosition + barThickness / 2, yScale(pos) + (i === 0 ? -1 : 1)],
      });
    }
    if (idx === stackedData.length - 1) {
      result.push({
        ...interactionPoint,
        point: isHorizontal
          ? [chartMeta?.plotWidth ?? 0, groupPosition + barThickness / 2]
          : [groupPosition + barThickness / 2, 0],
      });
    }
    return result;
  });
};

/** @deprecated */
export const BarStacks: Shape<BarStackExtras> = (props) => {
  const { data, chartMeta } = props;
  const testIdPrefix = chartMeta?.testId ?? 'chart';
  return (
    <>
      {data?.map<React.ReactNode>((item, idx) => (
        <BarStack
          {...props}
          item={item}
          key={idx}
          testId={`${testIdPrefix}-barstack-group-${idx}`}
        />
      ))}
    </>
  );
};

BarStacks.shapeName = 'BarStacks';
BarStacks.getInteractionMeta = BarStack.getInteractionMeta;
BarStacks.getInteractionPoints = BarStack.getInteractionPoints;
