import { FC } from 'react';
import cx from 'classnames';

import { MetricTile, MetricTileProps } from './MetricTile';

export type MetricTileGroupProps = {
  /** an accessible label; use if the group has no visible heading */
  ariaLabel?: string;
  metricTiles: Array<MetricTileProps>;
  testId?: string;
};

export const MetricTileGroup: FC<MetricTileGroupProps> = ({
  ariaLabel,
  metricTiles,
  testId,
}) => {
  const tileCount = metricTiles.length;
  const classNames = cx('grid gap-4', {
    'grid-cols-1': tileCount <= 1,
    'grid-cols-2': tileCount === 2,
    'grid-cols-3': tileCount === 3,
    'grid-cols-4': tileCount === 4 || tileCount === 7 || tileCount === 8,
    'grid-cols-5':
      tileCount === 5 ||
      (tileCount >= 9 && (tileCount % 5 === 0 || tileCount % 6 === 1)),
    'grid-cols-6':
      tileCount === 6 || (tileCount > 9 && (tileCount % 5 > 0 || tileCount % 6 !== 1)),
  });

  return (
    <ul aria-label={ariaLabel} className={classNames} data-testid={testId}>
      {metricTiles.map((tileProps) => (
        <li key={tileProps.title}>
          <MetricTile {...tileProps} />
        </li>
      ))}
    </ul>
  );
};
