import { useCallback, useEffect, useMemo, useState } from 'react';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

import {
  Resolver,
  ResolverOptions,
  useForm,
  UseFormProps,
  UseFormReturn,
} from '@/externals/react-hook-form';
import { generateSchemaValidation } from '../components/forms/SchemaFields/helpers/validation';
import type { FormSchema } from '../components/forms/SchemaFields/SchemaFields';

export interface SchemaConfig {
  schema: FormSchema;
  isOverride?: boolean;
}

export interface SchemaContext {
  schema: z.Schema<any, any>;
  schemaFields: SchemaConfig[];
}

// Merge together the generated schema (part of context) from SchemaFields and combine it
// with the overall zod schema
const schemaResolver: Resolver = async (
  values: any,
  context: any,
  _: ResolverOptions<any>,
) => {
  const extraSchema = context.schemaFields.reduce(
    (acc: z.Schema<any, any>, config: SchemaConfig) =>
      acc.and(
        generateSchemaValidation(config.schema, () => values, [], config.isOverride),
      ),
    z.object({}),
  );

  return zodResolver(context.schema.and(extraSchema))(
    values,
    {},
    { fields: {}, shouldUseNativeValidation: false },
  );
};

export const useZodForm = (
  schema: z.Schema<any, any>,
  formConfig?: UseFormProps,
  formSchema?: FormSchema | SchemaConfig | SchemaConfig[],

  /**
   * A list of fields to hide.
   * By default, schema fields can be conditionally rendered based on the value of other keys, but we sometimes need to
   * gate fields based on other values such as feature flags or account types.
   */
  hiddenSchemaFields?: string[],
): UseFormReturn<any, any> => {
  const resolver = formSchema ? schemaResolver : zodResolver(schema);
  const config = formConfig ?? {};
  return useForm({
    ...config,
    context: {
      schema,
      schemaFields: normalizeSchemaFields(formSchema),
      hiddenSchemaFields: hiddenSchemaFields,
    },
    resolver: resolver,
  });
};

const normalizeSchemaFields = (schema?: FormSchema | SchemaConfig | SchemaConfig[]) => {
  if (schema) {
    if (Object.keys(schema).includes('fields')) {
      // We have a classic schema, convert to a config and return as an array
      return [{ schema, isOverride: false }];
    }
    return Array.isArray(schema) ? schema : [schema];
  }
};

export interface UseAsyncFormValuesArgs {
  defaultValues?: any;
  isLoading: boolean;
  formMethods: UseFormReturn;
  extraValues?: Record<string, any>;
}

const defaultExtraValues = {};

// Fills in default form values after the query returns values
export const useAsyncFormValues = ({
  defaultValues,
  formMethods,
  extraValues,
  isLoading,
}: UseAsyncFormValuesArgs) => {
  const defaultedExtraValues = extraValues || defaultExtraValues;
  useEffect(() => {
    if (!isLoading && defaultValues) {
      formMethods.reset({
        ...formMethods.getValues(),
        ...{
          ...defaultValues,
          ...defaultedExtraValues,
        },
      });
    }
  }, [
    isLoading,
    defaultValues,
    formMethods,
    formMethods.reset,
    formMethods.getValues,
    defaultedExtraValues,
  ]);
};

export const useSuccessState = () => {
  const [showSuccessState, setShowSuccessState] = useState(false);

  const triggerSuccessState = useCallback(() => {
    setShowSuccessState(true);

    setTimeout(() => {
      setShowSuccessState(false);
    }, 3000);
  }, []);

  return useMemo(() => {
    return { showSuccessState, triggerSuccessState };
  }, [showSuccessState, triggerSuccessState]);
};

interface FormStateConfig {
  initialEdit?: boolean;
}
// Handles common form state for you
export const useFormState = (config?: FormStateConfig) => {
  const [isEdit, setIsEdit] = useState<boolean>(config?.initialEdit ?? false);
  const [isSaving, setIsSaving] = useState<boolean>(false);
  const [isDeleting, setIsDeleting] = useState<boolean>(false);

  const [hasMutationError, setHasMutationError] = useState<boolean>(false);
  const [customServerErrors, setCustomServerErrors] = useState<{ [key: string]: any }>(
    {},
  );

  const { showSuccessState, triggerSuccessState } = useSuccessState();

  return useMemo(() => {
    return {
      isEdit,
      setIsEdit,
      isSaving,
      setIsSaving,
      hasMutationError,
      setHasMutationError,
      customServerErrors,
      setCustomServerErrors,
      showSuccessState,
      triggerSuccessState,
      isDeleting,
      setIsDeleting,
    };
  }, [
    customServerErrors,
    hasMutationError,
    isDeleting,
    isEdit,
    isSaving,
    showSuccessState,
    triggerSuccessState,
  ]);
};
