/**
 * Determine if the particular plot or sub plot is focused.
 * If there is nothing focused, then all plots are considered focused.
 * @deprecated
 */
export const isPlotFocused = (
  focusPlotId: string | undefined,
  plotId: string,
  subPlotId: number = 0,
) => {
  return focusPlotId === undefined || focusPlotId === plotId + subPlotId;
};

/**
 * Merge plot and sub plot id into a single unique id
 * @deprecated
 */
export const createFullPlotId = (plotId: string, subPlotId: number = 0) => {
  return plotId + subPlotId;
};
