import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import cx from 'classnames';

import { Disclosure, Transition } from '@/externals/headlessui';
import { Icon } from '../Icon';
import { LoadingBlock } from '../LoadingBlock/LoadingBlock';
import { RyeconCaretDown } from '../ryecons';

export interface SidebarSection {
  /** The title of the sidebar section */
  title: string;

  /** An array of items to display */
  subItems: (SidebarItem | SidebarAccordion)[];

  /** The high level route under which items will be added (e.g. `/settings/accounts/${accountId}` or `/profile` ) */
  route: string;

  /** Optionaly hide the sidebar section if user does not have access */
  canAccess?: boolean;
}

export interface SidebarAccordion {
  /** The title of the sidebar accordion */
  title: string;

  /** An array of items to display in the accordion*/
  subItems: SidebarItem[];

  /** Optionaly hide the sidebar section if user does not have access */
  canAccess?: boolean;
}

export interface SidebarItem {
  /** The name of the sidebar item */
  title: string;

  /** The id of the element to scroll to. If provided, click will scroll to section */
  itemId?: string;

  /** A route to link to, for separate pages within scrollable sections. Takes precedence over scrolling */
  route?: string;

  /** An onclick handler. If provided, click will trigger onClick. Takes precedence over scroll */
  onClick?: () => void;

  /** A boolean representing whether to include a divider above this item */
  includeTopDivider?: boolean;

  /** Optionaly hide the sidebar section if user does not have access */
  canAccess?: boolean;
}

/**
 * @deprecated Use Sidenav instead
 */
export interface SidebarProps {
  /** An array of sidebar sections */
  sidebarSections: SidebarSection[];

  /** The content to render to the right of the sidebar. */
  children: React.ReactNode;

  /** Boolean to determine whether to display a loading state */
  isLoading?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

const getRouteForActiveItem = (sections: SidebarSection[], activeItem: string) => {
  const section = sections.find((section) => {
    return section.subItems.some((item) => {
      if (isAccordion(item)) {
        return item.subItems.some((subItem) => subItem.itemId === activeItem);
      }
      return item.itemId === activeItem || item.route === activeItem;
    });
  });

  return section ? section.route : null;
};

/**
 * @deprecated Use Sidenav instead
 */
export const Sidebar: React.FC<SidebarProps> = ({
  sidebarSections,
  children,
  isLoading,
  testId = 'sidebar',
  trackingId = 'sidebar',
}): React.ReactElement => {
  const [isAutoScrolling, setIsAutoScrolling] = useState(false);
  const [isScrolling, setIsScrolling] = useState(false);
  const [isLoaded, setIsLoaded] = useState(false);

  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [scrollContainer, setScrollContainer] = useState<HTMLDivElement | Window>(
    window,
  );

  // Update scroll container when ref is set
  useEffect(() => {
    setScrollContainer(scrollContainerRef.current ?? window);
  }, []);

  const location = useLocation();

  // Default active item should be the hash in the URL, the route in the URL, or the first item in the active list
  const defaultActiveItem = useMemo(() => {
    let activeItem = '';

    const activeSection = sidebarSections.find((section) =>
      location.pathname.startsWith(section.route),
    );

    const flattenedItems =
      activeSection?.subItems.flatMap((item) => {
        return isAccordion(item) ? item.subItems : item;
      }) ?? [];
    const activeRoute = flattenedItems
      .filter((subItem) => {
        if (!isAccordion(subItem) && subItem.route) {
          // routes could be routed to with a trailing /, make sure we handle that case
          // routes will also build on eachother in some way
          // ex. /settings/profile and /settings/profile/credentials
          return location.pathname.startsWith(subItem.route);
        }

        return false;
      })
      // find the longest match, this should be the most specific
      // this could potentially be wrong, but this will also be very temporary as
      // we're migrating away from onClick for routes with this component
      .reduce<SidebarItem | undefined>((bestMatch, currentItem) => {
        if (!isAccordion(currentItem) && currentItem.route) {
          if (bestMatch && !isAccordion(bestMatch) && bestMatch.route) {
            return bestMatch.route.length >= currentItem?.route.length
              ? bestMatch
              : currentItem;
          }
          return currentItem;
        }
        return bestMatch;
      }, undefined);

    if (activeRoute && activeRoute.route) {
      activeItem = activeRoute.route;
    }

    // All else fails, default to the first in the active section
    const firstItem = activeSection?.subItems.filter(
      (section) => section.canAccess ?? true,
    )[0];
    if (firstItem && !activeItem) {
      if (isAccordion(firstItem)) {
        activeItem = firstItem.subItems[0].itemId ?? '';
      } else {
        activeItem = (firstItem.itemId || firstItem.route) ?? '';
      }
    }

    return activeItem;
  }, [sidebarSections, location.pathname]);

  const [activeNavItem, setActiveNavItem] = useState<string>('');
  const [previousActiveRoute, setPreviousActiveRoute] = useState<string>('');

  // Set active item after load is complete
  useEffect(() => {
    if (!isLoading && !isLoaded) {
      setIsLoaded(true);
      const hasHash = location.hash.length > 0;

      setActiveNavItem(hasHash ? getIdFromHash(location.hash) : defaultActiveItem);
    }
  }, [isLoading, location, defaultActiveItem, isLoaded]);

  // We need to keep track of when auto scroll is taking place so that the intersection observer
  // handling manual scroll events can ignore those intersections.
  // When no scroll event has triggered in 100ms, we can assume the auto scroll has finished
  // and flip the scrolling flags off
  useEffect(() => {
    let handle: number;
    const onScroll = () => {
      setIsScrolling(true);
      if (handle) {
        window.clearTimeout(handle);
      }
      handle = window.setTimeout(() => {
        setIsAutoScrolling(false);
        setIsScrolling(false);
      }, 100);
    };

    scrollContainer.addEventListener('scroll', onScroll);

    return () => {
      scrollContainer.removeEventListener('scroll', onScroll);
    };
  }, [scrollContainer]);

  const handleNavItemClick = useCallback(
    (elementId: string, isNewPage?: boolean) => {
      // We need to be able to differentiate between auto scrolling (on sidebar click) and manual scrolling
      setIsAutoScrolling(true);

      const scrollToItem = () => {
        const elementToScrollTo = document.getElementById(elementId);

        if (elementToScrollTo) {
          let topPos = elementToScrollTo?.offsetTop;

          // If this is the first element (within 100px of the top), then just scroll all the way to the top
          if (topPos < 100) {
            topPos = 0;
          }

          scrollContainer.scrollTo({
            top: topPos,
            behavior: 'smooth',
          });
        }
      };

      setActiveNavItem(elementId);

      // If we're switching to a new route, reset the scroll position and give a short delay before
      // triggering the scroll handler to give time for react to render the new page
      if (isNewPage) {
        setPreviousActiveRoute(getRouteForActiveItem(sidebarSections, elementId) ?? '');
        scrollContainer.scrollTo(0, 0);
        window.setTimeout(scrollToItem, 200);
      } else {
        scrollToItem();
      }
    },
    [scrollContainer, sidebarSections],
  );

  // If the user manually navigated to a new route, reset the scroll position
  // (e.g. If the user clicks the profile settings cog while on account settings)
  useEffect(() => {
    if (location.pathname !== previousActiveRoute) {
      setActiveNavItem(
        location.hash.length > 0 ? getIdFromHash(location.hash) : defaultActiveItem,
      );
      scrollContainer.scrollTo(0, 0);
    }
  }, [
    previousActiveRoute,
    scrollContainer,
    location.hash,
    defaultActiveItem,
    location.pathname,
  ]);

  // Trigger scroll event on initial page load and when hash changes
  useEffect(() => {
    const hashElementId = getIdFromHash(location.hash);
    if (!isLoading && hashElementId) {
      handleNavItemClick(hashElementId, true);
    }
  }, [handleNavItemClick, isLoading, location.hash]);

  const allItemIds = useMemo(() => {
    return sidebarSections
      .flatMap((section) => section.subItems)
      .reduce((acc, item) => {
        let hashLinks: string[] = [];
        if (isAccordion(item)) {
          const subItemHashLinks = item.subItems
            .filter((subItem) => subItem.itemId)
            .map((subItem) => subItem.itemId ?? '');
          hashLinks = [...subItemHashLinks];
        } else if (item.itemId) {
          hashLinks = [item.itemId ?? ''];
        }
        return [...acc, ...hashLinks];
      }, [] as string[]);
  }, [sidebarSections]);

  // When manually scrolling the page, change the active element when a new element intersects with the half way point
  useEffect(() => {
    if (isAutoScrolling || !isScrolling) {
      return;
    }

    const options: IntersectionObserverInit = {
      rootMargin: '-50% 0% -50% 0%', // Creates a horizontal line in the middle of the page
    };

    const onIntersect = (entries: IntersectionObserverEntry[]) =>
      entries.forEach((entry: IntersectionObserverEntry) => {
        const itemId = entry.target.id;
        if (entry.isIntersecting && !(activeNavItem === itemId)) {
          setActiveNavItem(itemId);
        }
      });

    const observer = new IntersectionObserver(onIntersect, options);

    allItemIds.forEach((id) => {
      const element = document.getElementById(id);
      if (element) {
        observer.observe(element);
      }
    });

    return () => observer.disconnect();
  }, [allItemIds, isAutoScrolling, isScrolling, activeNavItem]);

  return (
    <div className="flex">
      <nav
        className="h-full max-h-dvh w-auto flex-none gap-1 space-y-1 overflow-auto pl-1 pt-12 md:w-60 md:pl-3 lg:pl-6"
        data-testid={testId}
        data-trackingid={trackingId}
        aria-label="Sidebar"
      >
        {isLoading && (
          <div className="space-y-1">
            <h3 className="text-fgAlt p-2 text-base font-medium">Settings</h3>
            <LoadingBlock width={200} height={35} loaderClassName="rounded-md" />
            <LoadingBlock width={200} height={35} loaderClassName="rounded-md" />
            <LoadingBlock width={200} height={35} loaderClassName="rounded-md" />
            <LoadingBlock width={200} height={35} loaderClassName="rounded-md" />
            <LoadingBlock width={200} height={35} loaderClassName="rounded-md" />
          </div>
        )}
        {!isLoading && (
          <div className="space-y-6">
            {sidebarSections.map((section) => {
              if (section.canAccess === false) {
                return null;
              }

              return (
                <SidebarSectionComponent
                  key={section.title}
                  activeNavItem={activeNavItem}
                  handleNavItemClick={handleNavItemClick}
                  testId={testId}
                  trackingId={trackingId}
                  {...section}
                />
              );
            })}
          </div>
        )}
      </nav>
      <div
        className="h-screen max-h-dvh flex-grow overflow-auto px-1 py-12 md:px-3 lg:px-6"
        ref={scrollContainerRef}
        data-testid={`${testId}-content`}
        data-trackingid={`${trackingId}-content`}
      >
        {children}
      </div>
    </div>
  );
};

interface SidebarSectionProps extends SidebarSection {
  activeNavItem: string;
  handleNavItemClick: (elementId: string, waitForLoad?: boolean) => void;
  testId: string;
  trackingId: string;
}

const SidebarSectionComponent: React.FC<SidebarSectionProps> = ({
  title,
  subItems,
  route,
  activeNavItem,
  handleNavItemClick,
  testId,
  trackingId,
}) => {
  return (
    <div>
      <h3 className="text-fgAlt p-2 text-base font-medium">{title}</h3>
      <div className="space-y-1">
        {subItems.map((item) => {
          if (item.canAccess === false) {
            return null;
          }
          if (isAccordion(item)) {
            return (
              <SidebarAccordionComponent
                key={item.title}
                title={item.title}
                subItems={item.subItems}
                route={route}
                activeNavItem={activeNavItem}
                handleNavItemClick={handleNavItemClick}
                testId={testId}
                trackingId={trackingId}
              />
            );
          }
          return (
            <SidebarItemComponent
              key={item.title}
              route={item.route}
              activeNavItem={activeNavItem}
              handleNavItemClick={handleNavItemClick}
              isTopLevel
              topLevelRoute={route}
              {...item}
              testId={testId}
              trackingId={trackingId}
            />
          );
        })}
      </div>
    </div>
  );
};

interface SidebarAccordionProps extends SidebarAccordion {
  route: string;
  activeNavItem: string;
  handleNavItemClick: (elementId: string, waitForLoad?: boolean) => void;
  testId: string;
  trackingId: string;
}

const SidebarAccordionComponent: React.FC<SidebarAccordionProps> = ({
  title,
  subItems,
  route,
  activeNavItem,
  handleNavItemClick,
  testId,
  trackingId,
}) => {
  const isActive = subItems.some((subItem) => subItem.itemId === activeNavItem);

  return (
    <Disclosure defaultOpen={true} as="div" key={title} className="space-y-1">
      {({ open: isExpanded }) => {
        const iconClasses = cx(
          'm-2 h-5 w-5 flex-shrink-0 transform transition-transform duration-150 ease-in-out',
          {
            '-rotate-180': !isExpanded,
            'text-fgAlt': !isActive,
            'text-fgBrand': isActive,
          },
        );
        return (
          <>
            <Disclosure.Button
              className={cx(
                'hover:bg-bgMainHover flex w-full items-center justify-between rounded-md p-2 text-left text-sm',
                {
                  'text-fgBrand bg-bgMainHover font-medium': isActive,
                  'text-fgDecorative hover:text-fgAltHover font-normal': !isActive,
                },
              )}
              data-testid={`${testId}-accordion`}
              data-trackingid={`${trackingId}-accordion`}
            >
              {title}
              <Icon ryecon={RyeconCaretDown} size="xs" className={iconClasses} />
            </Disclosure.Button>
            <Transition
              enter="transition duration-100 ease-out"
              enterFrom="opacity-0"
              enterTo="opacity-100"
              leave="transition duration-55 ease-out"
              leaveFrom="opacity-100"
              leaveTo="opacity-0"
            >
              <Disclosure.Panel className="ml-2 space-y-1">
                {subItems.map((subItem) => {
                  if (subItem.canAccess === false) {
                    return null;
                  }
                  return (
                    <SidebarItemComponent
                      key={subItem.title}
                      activeNavItem={activeNavItem}
                      handleNavItemClick={handleNavItemClick}
                      topLevelRoute={route}
                      testId={testId}
                      trackingId={trackingId}
                      {...subItem}
                    />
                  );
                })}
              </Disclosure.Panel>
            </Transition>
          </>
        );
      }}
    </Disclosure>
  );
};

interface SidebarItemProps extends SidebarItem {
  isTopLevel?: boolean;
  topLevelRoute?: string;
  handleNavItemClick: (elementId: string, waitForLoad?: boolean) => void;
  activeNavItem: string;
  testId: string;
  trackingId: string;
}

const getNavClasses = (isActive: boolean, isTopLevel: boolean) => {
  return cx(
    'hover:bg-bgMainHover flex flex-grow cursor-pointer items-center rounded-md p-2 text-sm',
    {
      'ml-2': !isTopLevel,
      'text-fgAlt hover:text-fgAltHover font-normal': !isActive,
      'text-fgBrand bg-bgMainHover font-medium': isActive,
    },
  );
};

const SidebarItemComponent: React.FC<SidebarItemProps> = ({
  topLevelRoute = '',
  title,
  itemId = '',
  includeTopDivider,
  isTopLevel = false,
  handleNavItemClick,
  onClick,
  activeNavItem,
  testId,
  trackingId,
  route,
}) => {
  const location = useLocation();
  const navigate = useNavigate();

  const handleClick = () => {
    if (onClick) {
      onClick();
    } else {
      navigate(topLevelRoute);
      const isNewPath = location.pathname !== topLevelRoute;
      handleNavItemClick(itemId, isNewPath);
    }
  };

  const navClasses = getNavClasses(
    itemId === activeNavItem || route === activeNavItem,
    isTopLevel,
  );

  return (
    <div
      data-testid={isTopLevel ? 'sidebar-item' : 'sidebar-subitem'}
      data-trackingid={isTopLevel ? 'sidebar-item' : 'sidebar-subitem'}
      className="flex flex-col"
    >
      {includeTopDivider && (
        <div
          className="bg-bgDisabled mb-1 h-px w-full"
          data-testid={`${testId}-divider`}
          data-trackingid={`${trackingId}-divider`}
        />
      )}
      {!route && (
        <button
          type="button"
          className={navClasses}
          onClick={handleClick}
          data-testid="sidebar-item-hash"
        >
          {title}
        </button>
      )}
      {!!route && (
        <Link className={navClasses} to={route} data-testid="sidebar-item-link">
          {title}
        </Link>
      )}
    </div>
  );
};

const isAccordion = (
  item: SidebarItem | SidebarAccordion,
): item is SidebarAccordion => {
  return (item as SidebarAccordion).subItems !== undefined;
};

const getIdFromHash = (hashLink: string): string => {
  return hashLink.replace('#', '');
};
