import {
  type ElementType,
  type FC,
  type HTMLAttributes,
  PropsWithChildren,
} from 'react';

type WithVirtualPaddingProps = {
  /** used for column virtualization */
  virtualPaddingLeft?: number;
  /** used for column virtualization */
  virtualPaddingRight?: number;
  as: 'td' | 'th';
};

/**
 * when padding is provided, will add a td | th with a minWidth to fill out the remaining
 * horizontal scroll space within the scroll container
 * uses minWidth to play well with safari
 */
export const WithVirtualPadding: FC<PropsWithChildren<WithVirtualPaddingProps>> = ({
  children,
  virtualPaddingLeft,
  virtualPaddingRight,
  as,
}) => {
  const CellTag: ElementType<HTMLAttributes<HTMLElement>> = as;
  return (
    <>
      {virtualPaddingLeft ? (
        // fake empty column to the left for virtualization scroll padding
        <CellTag style={{ display: 'flex', minWidth: virtualPaddingLeft }} />
      ) : null}
      {children}
      {virtualPaddingRight ? (
        // fake empty column to the right for virtualization scroll padding
        <CellTag style={{ display: 'flex', minWidth: virtualPaddingRight }} />
      ) : null}
    </>
  );
};
