import type { PaginationFooterProps } from '../../PaginationFooter/PaginationFooter';
import { LoadMore } from '../../PaginationFooter/subcomponents/LoadMore.internal';

type LoadMoreRowProps = {
  columnCount: number;
  paginationProps?: PaginationFooterProps;
  style?: React.CSSProperties;
};
export const LoadMoreRow = ({
  columnCount,
  paginationProps,
  style,
}: LoadMoreRowProps) => {
  if (!paginationProps || !paginationProps.onLoadMore) {
    return null;
  }

  return (
    <tr style={style} className="bg-bgMain flex w-full">
      <td
        className="border-borderMuted flex w-full items-center border-b bg-inherit px-5"
        colSpan={columnCount}
      >
        <LoadMore {...paginationProps} />
      </td>
    </tr>
  );
};
