import { type ReactNode, useRef } from 'react';
import cx from 'classnames';

import { Button } from '../../Button/Button';
import { PaginationFooter } from '../../PaginationFooter/PaginationFooter';
import { RyeconPlus } from '../../ryecons';
import { useVirtualTableProps } from '../hooks';
import type { Cell, ColumnDef, DefaultTData, Header, Row } from '../types';
import type { InternalTableProps } from '../types.internal';
import { getVirtualizedTableHeight } from '../utils';
import { EmptyStateRow } from './EmptyStateRow.internal';
import { HeaderRow } from './HeaderRow.internal';
import { LoadMoreRow } from './LoadMoreRow';
import { TableRow } from './TableRow.internal';

type VirtualTableProps<
  TData extends DefaultTData,
  TValue extends React.ReactNode,
> = InternalTableProps<TData, TValue> & {
  rowHeight: number;
};

/**
 * Internal table that handles virtualized use cases.
 * Similar to CompactTable but with the same feature set as Table.
 * We may be able to deprecate CompactTable in the future if this is sufficiently flexible.
 *
 * Note: this is not exported so it cannot be used directly by consumers
 */
export const VirtualTable = <
  TData extends DefaultTData,
  TValue extends React.ReactNode = React.ReactNode,
>({
  columns,
  rows,
  headers,
  emptyStateProps,
  rowHeight,
  paginationProps,
  handleRowClick,
  onRowClickLinkGenerator,
  rowLinkIsInternal = true,
  stickyColumn,
  testId = 'table',
  trackingId = 'table',
  onAddRow,
  addRowLabel = 'Add row',
  isAddButtonDisabled = false,
  height,
  cellVariant = 'DEFAULT',
  className,
  showEmpty,
  showPaginationFooter,
  tableContainerRef,
  onCellClick,
  isCellClickable,
}: VirtualTableProps<TData, TValue>) => {
  const headerRowRef = useRef<HTMLTableRowElement | null>(null);

  const {
    virtualRows,
    virtualColumns,
    tableContentHeight,
    virtualPaddingLeft,
    virtualPaddingRight,
    visibleHeaders,
    colIdxOffset,
  } = useVirtualTableProps({
    rows: rows as Row<TData>[],
    columns: columns as ColumnDef<TData, ReactNode>[],
    rowHeight,
    overscanCount: 50,
    columnOverscanCount: 50,
    tableContainerRef,
    headers,
  });

  // relative for sticky header
  const scrollContainerClasses = cx('relative overflow-auto');
  // z-index required to stay on-top of absolute position rows
  const headerClasses = cx('bg-bgBackground border-borderMuted sticky top-0 z-10 grid');
  // grid helps calculate tbody content height
  const tableClasses = cx('grid w-full', className);
  // relative for absolute positioned rows
  const tbodyClasses = cx('relative grid');

  const rowElems = virtualRows.map((virtualRow) => {
    const row = rows[virtualRow.index];
    const cells = row.getVisibleCells();

    // only render cells visible within virtual container
    const visibleCells = virtualColumns.map((vc) => cells[vc.index]);
    return (
      <TableRow<TData>
        key={`row-${virtualRow.index}`}
        row={row}
        visibleCells={visibleCells as Cell<TData, ReactNode>[]}
        rowIdx={virtualRow.index}
        isCompact={false}
        onRowClickLinkGenerator={onRowClickLinkGenerator}
        isCellClickable={isCellClickable}
        handleCellClick={onCellClick}
        rowLinkIsInternal={rowLinkIsInternal}
        stickyColumn={stickyColumn}
        testId={testId}
        trackingId={trackingId}
        rowHeight={rowHeight}
        handleRowClick={handleRowClick}
        cellVariant={cellVariant}
        virtualPaddingLeft={virtualPaddingLeft}
        virtualPaddingRight={virtualPaddingRight}
        colIdxOffset={colIdxOffset}
        style={{
          height: rowHeight,
          display: 'flex',
          position: 'absolute',
          transform: `translateY(${virtualRow.start}px)`,
        }}
      />
    );
  });

  const virtualTableHeight = getVirtualizedTableHeight({
    numRows: rows.length,
    rowHeight,
    height,
  });

  return (
    <>
      <div
        ref={tableContainerRef}
        style={{
          height: virtualTableHeight,
        }}
        className={scrollContainerClasses}
        data-testid={`${testId}-scroll-container`}
      >
        <table
          className={tableClasses}
          data-testid={testId}
          data-trackingid={trackingId}
        >
          <thead className={headerClasses}>
            <HeaderRow<TData, TValue>
              headers={visibleHeaders as Header<TData, TValue>[]}
              stickyColumn={stickyColumn}
              testId={testId}
              trackingId={trackingId}
              rowRef={headerRowRef}
              colIdxOffset={colIdxOffset}
              virtualPaddingLeft={virtualPaddingLeft}
              virtualPaddingRight={virtualPaddingRight}
              cellVariant={cellVariant}
            />
          </thead>
          <tbody
            style={{
              height: tableContentHeight,
            }}
            className={tbodyClasses}
          >
            {showEmpty ? (
              <EmptyStateRow
                emptyStateProps={emptyStateProps}
                columnCount={columns.length}
                testId={testId}
                trackingId={trackingId}
                height={height && rowHeight ? height - rowHeight : undefined}
              />
            ) : (
              <>
                {rowElems}
                {!!paginationProps?.onLoadMore && (
                  <LoadMoreRow
                    columnCount={columns.length}
                    paginationProps={paginationProps}
                    style={{
                      height: rowHeight,
                      display: 'flex',
                      position: 'absolute',
                      transform: `translateY(${virtualRows[virtualRows.length - 1]
                        ?.end}px)`,
                    }}
                  />
                )}
              </>
            )}
          </tbody>
        </table>
      </div>
      {showPaginationFooter && paginationProps?.onLoadMore && (
        <PaginationFooter {...paginationProps} shouldShowLoadMore={false} />
      )}
      {!!onAddRow && (
        <div className={cx({ 'pt-6': !showPaginationFooter })}>
          <Button
            type="secondary"
            ryecon={RyeconPlus}
            onClick={onAddRow}
            testId={`${testId}-add-row`}
            trackingId={`${trackingId}-add-row`}
            isDisabled={isAddButtonDisabled}
          >
            {addRowLabel}
          </Button>
        </div>
      )}
    </>
  );
};
