import { FC, forwardRef } from 'react';
import { Allotment, AllotmentHandle, AllotmentProps } from 'allotment';
import cx from 'classnames';

import 'allotment/dist/style.css';
import styles from './SplitWindow.module.css';

export const SplitWindow: FC<AllotmentProps> = forwardRef<
  AllotmentHandle,
  AllotmentProps
>(({ children, vertical = false, proportionalLayout = true, ...defaultProps }, ref) => (
  <Allotment
    ref={ref}
    vertical={vertical}
    proportionalLayout={proportionalLayout}
    className={cx(styles.splitWindow, defaultProps.className)}
    {...defaultProps}
  >
    {children}
  </Allotment>
));

export const SplitPanel: FC<React.ComponentProps<typeof Allotment.Pane>> = ({
  children,
  ...props
}) => <Allotment.Pane {...props}>{children}</Allotment.Pane>;

SplitWindow.displayName = 'SplitWindow';
