import { Cell } from '@tanstack/react-table';
import cx from 'classnames';

import { Link } from '../../Link/Link';
import { DefaultCell } from '../cells/DefaultCell';
import type { TableProps } from '../Table/types';
import { DefaultRowProps, DefaultTData } from '../types';
import { CommonRowProps, InternalRowProps } from '../types.internal';
import { WithVirtualPadding } from './WithVirtualPadding.internal';

type TableRowProps<TData> = InternalRowProps<TData> &
  CommonRowProps<TData> & {
    rowHeight: TableProps['rowHeight'];
    isCellClickable?: (cell: Cell<TData, unknown>) => boolean;
    handleCellClick?: (cell: Cell<TData, unknown>) => void;
    cellSelection?: { [key: string]: boolean };
  };

export const TableRow = <TData extends DefaultTData = DefaultRowProps>({
  row,
  rowIdx,
  rowHeight,
  onRowClickLinkGenerator,
  rowLinkIsInternal = true,
  stickyColumn,
  testId,
  trackingId,
  handleRowClick,
  handleCellClick,
  cellSelection,
  isCellClickable,
  cellVariant,
  style = {},
  // virtual grid props
  virtualPaddingLeft,
  virtualPaddingRight,
  visibleCells,
  colIdxOffset,
}: TableRowProps<TData>) => {
  const isLinkRow = !!onRowClickLinkGenerator && !row.original.isLoadingRow;
  const isClickable = !!handleRowClick || !!onRowClickLinkGenerator;
  const clickableClasses = cx({
    'active:bg-bgMainActive cursor-pointer': isClickable && !handleCellClick,
  });
  const hasSelectedCell = row.getAllCells().some((cell) => !!cellSelection?.[cell.id]);

  const showSelectedState = row.getIsSelected() || hasSelectedCell;
  const rowClasses = cx(
    'font-body-sm flex w-full',
    {
      'bg-bgMain': !showSelectedState || !row.getIsSelected(),
      'hover:bg-bgMainHover': !handleCellClick,
      'bg-bgMainActive': showSelectedState,
    },
    clickableClasses,
  );

  const commonProps = {
    style: {
      height: rowHeight,
      ...style,
    },
    className: rowClasses,
    'data-testid': `${testId}-row-${rowIdx}`,
    'data-trackingid': `${trackingId}-row-${rowIdx}`,
    'data-selected': row.getIsSelected(),
  };

  const linkClasses = 'flex w-full text-current';

  const cells = visibleCells.map((cell, idx) => (
    <DefaultCell
      row={row}
      cell={cell}
      index={idx + colIdxOffset}
      stickyColumn={stickyColumn}
      testId={testId}
      trackingId={trackingId}
      key={idx + colIdxOffset}
      handleCellClick={handleCellClick}
      selected={!!cellSelection?.[cell.id]}
      isClickable={!!isCellClickable?.(cell)}
      cellVariant={cellVariant}
    />
  ));

  if (isLinkRow) {
    return (
      <tr key={rowIdx} {...commonProps}>
        <Link
          to={onRowClickLinkGenerator(row.original)}
          isInternal={rowLinkIsInternal}
          hideUnderline
          className={linkClasses}
        >
          <WithVirtualPadding
            virtualPaddingLeft={virtualPaddingLeft}
            virtualPaddingRight={virtualPaddingRight}
            as="td"
          >
            {cells}
          </WithVirtualPadding>
        </Link>
      </tr>
    );
  }

  return (
    <tr
      key={rowIdx}
      {...commonProps}
      onClick={(e) => handleRowClick && handleRowClick(e, row.original)}
    >
      <WithVirtualPadding
        virtualPaddingLeft={virtualPaddingLeft}
        virtualPaddingRight={virtualPaddingRight}
        as="td"
      >
        {cells}
      </WithVirtualPadding>
    </tr>
  );
};
