import cx from 'classnames';

import { numberToCommaSeperatedString } from '../../utils/numberToCommaSeperatedString';
import { Button } from '../Button';
import {
  RyeconCaretLeft,
  RyeconCaretRight,
  RyeconCaretsLeft,
  RyeconCaretsRight,
} from '../ryecons';
import { Sizes } from '../types';
import PaginationCount from './PaginationCount.internal';
import PaginationRowsPerPageSelector from './PaginationRowsPerPageSelector.internal';
import usePaginationInternal from './usePagination.internal';

export interface PaginationProps {
  /** The currently selected page.  currentPage is 0 index.  Ex: Page 1 would be passed as currentPage={0} */
  currentPage: number;

  /**
   * onPageChange handler.  Ideally you should use the usePagination hook that will return an onPageChange handler.
   */
  onPageChange: (page: number) => void;

  /**
   * onRowsPerPageChange handler.  Pass this if you want to enable the rowsPerPage dropdown.
   * If you don't want the rowsPerPage dropdown, leave this prop empty.
   *
   * Ideally you should use the usePagination hook that will return an onRowsPerPageChange handler.
   */
  onRowsPerPageChange?: (rows: number) => void;

  /**
   * The total number of rows that the pagination component is handling. totalRows is 0 index.  Ex: If there are 14 rows, pass 13 (rowsArray.length)
   */
  totalRows: number;

  /**
   * The number of rows per page to display
   */
  rowsPerPage?: number;
}

const ENABLED_CARET_COLOR = 'text-fgDecorative hover:text-fgAltHover';
const DISABLED_CARET_COLOR = 'text-fgDisabled';

const Pagination = (props: PaginationProps) => {
  const {
    backButtonDisabled,
    currentPage,
    doPageBack,
    doPageForward,
    goToPage,
    nextButtonDisabled,
    pageNumbersToShow,
    totalPages,
  } = usePaginationInternal(props);

  return totalPages > 1 ? (
    <div className="align-center flex w-full justify-between" data-testid="pagination">
      <div className="align-center flex h-full gap-2">
        {totalPages > 5 && (
          <Button
            testId="first-page-btn"
            type="tertiary"
            iconClassname={
              backButtonDisabled ? DISABLED_CARET_COLOR : ENABLED_CARET_COLOR
            }
            ryecon={RyeconCaretsLeft}
            size={Sizes.sm}
            isDisabled={currentPage === 0}
            onClick={goToPage(0)}
            ariaLabel="go to first page"
          />
        )}
        <Button
          testId="back-btn"
          type="tertiary"
          iconClassname={
            backButtonDisabled ? DISABLED_CARET_COLOR : ENABLED_CARET_COLOR
          }
          ryecon={RyeconCaretLeft}
          size={Sizes.sm}
          isDisabled={currentPage === 0}
          onClick={doPageBack}
          ariaLabel="go to current page"
        />
        {pageNumbersToShow.map((page: number) => {
          const isActive = page === currentPage;
          return (
            <Button
              testId={`page-btn-${page}`}
              key={page}
              onClick={goToPage(page)}
              type={isActive ? 'pagination-active' : 'pagination'}
              size={Sizes.sm}
            >
              <p
                className={cx(
                  isActive ? 'text-fgInverse' : 'text-fgAlt',
                  'leading-none',
                  'font-label',
                )}
              >
                {numberToCommaSeperatedString(page + 1)}
              </p>
            </Button>
          );
        })}
        <Button
          testId="next-btn"
          type="tertiary"
          iconClassname={
            nextButtonDisabled ? DISABLED_CARET_COLOR : ENABLED_CARET_COLOR
          }
          ryecon={RyeconCaretRight}
          size={Sizes.sm}
          isDisabled={currentPage === totalPages - 1}
          onClick={doPageForward}
          ariaLabel="go to next page"
        />
        {totalPages > 5 && (
          <Button
            testId="last-page-btn"
            type="tertiary"
            iconClassname={
              nextButtonDisabled ? DISABLED_CARET_COLOR : ENABLED_CARET_COLOR
            }
            ryecon={RyeconCaretsRight}
            size={Sizes.sm}
            isDisabled={currentPage === totalPages - 1}
            onClick={goToPage(totalPages - 1)}
            ariaLabel="go to last page"
          />
        )}
        <PaginationCount
          currentPage={currentPage}
          rowsPerPage={props.rowsPerPage || 10}
          totalRows={props.totalRows}
        />
      </div>
      {props.onRowsPerPageChange && (
        <PaginationRowsPerPageSelector
          onChange={props.onRowsPerPageChange}
          rowsPerPage={props.rowsPerPage || 10}
        />
      )}
    </div>
  ) : null;
};

export { Pagination };
