import { useState } from 'react';
import cx from 'classnames';

import { UseFormReturn } from '@/externals/react-hook-form';
import { ActionList, Actions, getDefaultActions } from '../Actions';
import { Button } from '../Button';
import { Modal } from '../Modal';
import { RyeconSpinner, RyeconTrashBin } from '../ryecons';
import { Sizes } from '../types';

export interface DefaultActionsConfig {
  /** Whether the panel is in edit mode */
  isEdit: boolean;

  /** Whether the user has permission to access the actions */
  hasPermission: boolean;

  /** Callback for edit click */
  onEdit: () => void;

  /** Whether a mutation is currently in progress. */
  isSaving?: boolean;

  /** Whether to disable all buttons */
  isDisabled?: boolean;

  /** Whether a deletion is currently underway */
  isDeleting?: boolean;

  /** Callback for cancel click */
  onCancel: () => void;

  /** Callback for save click */
  onSubmit: (data: any) => void;

  /** Callback for delete confirmation. Delete button will not show unless defined */
  onDelete?: () => void;

  /** Custom delete button text */
  deleteText?: string;

  /** Custom content for the delete confirmation modal */
  deletionModalDescription?: React.ReactNode;

  /** Custom delete confirmation text */
  confirmDeleteText?: string;

  /** The formMethods from useZodForm */
  formMethods: UseFormReturn;

  /** Whether to display the success button. Usually triggered temporarily after save completes */
  showSuccessState?: boolean;
}

export interface SidePanelActionBarProps {
  /** Configuration for default set of actions (edit, save, cancel, delete) */
  defaultActionConfig?: DefaultActionsConfig;

  /** Custom set of actions. Will override all other options. */
  customActions?: ActionList;
}

export const SidePanelActionBar: React.FC<SidePanelActionBarProps> = ({
  defaultActionConfig,
  customActions,
}) => {
  const [isDeletionModalOpen, setIsDeletionModalOpen] = useState(false);

  const defaultActions = defaultActionConfig
    ? getDefaultActions({
        isEdit: defaultActionConfig.isEdit,
        isDisabled: defaultActionConfig.isDisabled || defaultActionConfig.isDeleting,
        isSaving: defaultActionConfig.isSaving,
        canEdit: defaultActionConfig.hasPermission,
        onEdit: defaultActionConfig.onEdit,
        onCancel: () => {
          setIsDeletionModalOpen(false);
          defaultActionConfig.onCancel();
        },
        onSubmit: defaultActionConfig.onSubmit,
        formMethods: defaultActionConfig.formMethods,
        size: Sizes.sm,
        showSuccessState: defaultActionConfig.showSuccessState,
      })
    : [];

  const actions = customActions ?? defaultActions;

  const displayDelete = !!defaultActionConfig?.onDelete && defaultActionConfig?.isEdit;

  return (
    <div
      className={cx('shadow-top border-borderMuted flex w-full border-t px-6 py-3', {
        'justify-between': !!displayDelete,
        'justify-end': !displayDelete,
      })}
    >
      {displayDelete && (
        <>
          <Button
            type="error"
            isDisabled={
              !defaultActionConfig?.hasPermission ||
              defaultActionConfig.isDeleting ||
              defaultActionConfig.isDisabled
            }
            onClick={() => setIsDeletionModalOpen(true)}
            ryecon={defaultActionConfig.isDeleting ? RyeconSpinner : RyeconTrashBin}
            iconClassname={defaultActionConfig.isDeleting ? 'animate-spin' : ''}
            text={
              defaultActionConfig.isDeleting
                ? 'Deleting'
                : defaultActionConfig?.deleteText ?? 'Delete'
            }
            size={Sizes.sm}
          />
          <Modal
            title={defaultActionConfig?.confirmDeleteText ?? 'Confirm delete'}
            isOpen={isDeletionModalOpen}
            onClose={() => setIsDeletionModalOpen(false)}
            modalType="alert"
            actions={[
              {
                text: 'Cancel',
                type: 'secondary',
                onClick: () => setIsDeletionModalOpen(false),
              },
              {
                text: defaultActionConfig?.confirmDeleteText ?? 'Confirm delete',
                type: 'error',
                onClick: () => {
                  defaultActionConfig.onDelete!();
                  setIsDeletionModalOpen(false);
                },
              },
            ]}
          >
            {!defaultActionConfig.deletionModalDescription && (
              <p className="font-body">
                Are you sure you want to delete this item? This action cannot be undone!
              </p>
            )}
            {!!defaultActionConfig.deletionModalDescription &&
              defaultActionConfig.deletionModalDescription}
          </Modal>
        </>
      )}
      <div className="flex gap-2">
        <Actions actions={actions} />
      </div>
    </div>
  );
};
