import { useMemo } from 'react';
import cx from 'classnames';

import { IconText } from '../elements/IconText/IconText';
import { LoadingBlock } from '../LoadingBlock/LoadingBlock';
import type { SizeType } from '../types';
import {
  Item,
  ItemPart,
  type StructuredContentProps,
  type StructuredItemPart,
} from './types';

const LOADING_DIMENSIONS = { width: 80, height: 15 };

const isStringItemPart = (part: ItemPart): part is string => typeof part === 'string';
const isStructuredItemPart = (part: ItemPart): part is StructuredItemPart => {
  if (!part) {
    return false;
  }
  return typeof part === 'object' && 'text' in part;
};

type ColumnProps = {
  part: ItemPart;
  isLoading: boolean;
  internalSize?: SizeType;
  internalClassName?: string;
  internalTextClassName?: string;
};
const Column = ({
  part,
  isLoading,
  internalSize,
  internalClassName,
  internalTextClassName,
}: ColumnProps) => {
  const baseProps = {
    size: internalSize,
    skeleton: isLoading,
    loadingDimensions: LOADING_DIMENSIONS,
    className: internalClassName,
    textClassname: internalTextClassName,
  };

  if (!isStructuredItemPart(part) || isStringItemPart(part)) {
    return <IconText {...baseProps} text={part} />;
  }

  const { badge, className, ...rest } = part;

  return (
    <>
      <IconText
        {...baseProps}
        {...rest}
        className={cx(internalClassName, className)}
        textClassname={cx(internalTextClassName, className)}
      />
      {!isLoading && badge}
    </>
  );
};

type RowProps = {
  item: Item;
  isLoading: boolean;
  testId: string;
};
const Row = ({ item, isLoading, testId }: RowProps) => {
  const wrapperClassName = cx('flex min-w-0 items-center gap-x-2 truncate');
  return (
    <div
      className="font-body-sm flex w-full flex-1 items-start justify-between gap-x-8"
      data-testid={`${testId}-item`}
    >
      <div className={wrapperClassName}>
        <Column
          part={item.start}
          isLoading={isLoading}
          internalTextClassName="text-fgAlt font-body-sm"
        />
      </div>
      {item.end && (
        <div className={wrapperClassName}>
          <Column
            part={item.end}
            isLoading={isLoading}
            internalClassName="text-right truncate"
            internalTextClassName="text-fgMain truncate font-body-sm"
          />
        </div>
      )}
    </div>
  );
};

export const StructuredContent = ({
  header,
  description,
  items = [],
  footerItems = [],
  isLoading = false,
  testId = 'popover-structured-content',
}: StructuredContentProps) => {
  const _items = useMemo(
    () =>
      isLoading
        ? Array.from(new Array(2), () => ({
            start: <LoadingBlock {...LOADING_DIMENSIONS} />,
            end: <LoadingBlock {...LOADING_DIMENSIONS} />,
          }))
        : items,
    [isLoading, items],
  );

  const _footerItems = isLoading
    ? [
        {
          start: <LoadingBlock {...LOADING_DIMENSIONS} />,
        },
      ]
    : footerItems;
  const hasFooter = _footerItems.length > 0;

  return (
    <div className="flex w-full flex-col gap-y-1" data-testid={testId}>
      {/* header */}
      <div className="flex flex-col gap-y-0">
        <h3
          className="font-heading-3 flex items-center"
          data-testid={`${testId}-header`}
        >
          <Column
            part={header}
            isLoading={isLoading}
            internalSize="lg"
            internalTextClassName="text-fgAlt"
          />
        </h3>

        {/* description. always render <p> to keep column-gap spacing */}
        {!isLoading && (
          <p
            className="text-fgDecorative font-caption"
            data-testid={`${testId}-description`}
          >
            {description}
          </p>
        )}
      </div>

      {_items.map((item, i) => (
        <Row key={i} item={item} isLoading={isLoading} testId={testId} />
      ))}

      {hasFooter && (
        <div data-testid={`${testId}-footer`} className="flex flex-col gap-y-1">
          <hr className="border-borderMuted my-2" />
          {_footerItems.map((item, i) => (
            <Row key={i} item={item} isLoading={isLoading} testId={testId} />
          ))}
        </div>
      )}
    </div>
  );
};
