import { PropsWithChildren } from 'react';
import { twMerge } from 'tailwind-merge';

import { ChartMeta, useChartContext } from '../ChartProvider/ChartProvider';

const domainPathProps = { className: 'hidden' };
export const BASE_AXIS_PROPS = {
  labelTextProps: { className: 'fill-fgDecorative' },
  domainPathProps,
  tickLineProps: domainPathProps,
};

/**
 * Minimum number of pixels between ticks
 */
export const MIN_X_AXIS_TICK_SPACING = 6;

/**
 * The number of pixels between the axis label and the axis
 */
export const Y_AXIS_LABEL_OFFSET = 10;

/**
 * numTicks is only used to determine x-axis spacing
 */
export const getTickWidth = (
  axis: 'x' | 'y',
  chartMeta: ChartMeta | null | undefined,
  numTicks: number | undefined = 1,
) => {
  const plotWidth = chartMeta?.plotWidth ?? 0;
  if (axis === 'y') return (chartMeta?.margin.left ?? 0) - Y_AXIS_LABEL_OFFSET;
  return plotWidth / (numTicks + 1) - MIN_X_AXIS_TICK_SPACING;
};

/**
 * Allows you to control how tight or loose ticks are spaced.
 * The number of ticks is dynamically determined based on the
 * size of the {@link BaseAxis}.
 *
 * * `sparse` - There are 3 ticks
 * * number indicates how many pixels between each tick
 */
export type TickSpacing = number | 'sparse';

export interface AxisProps {
  axis: 'x' | 'y';
  /**
   * A class name to apply to the axis, for styling the label
   */
  className?: string;
  /**
   * A label for the axis
   */
  label?: string;
  /**
   * If true, will enable truncation of the axis labels
   */
  enableTruncation?: boolean;
  /**
   * Id for testing, will be prefixed by the type (x or y) of axis
   */
  testId?: string;
}

/** @deprecated */
export const BaseAxis: React.FC<PropsWithChildren<AxisProps>> = ({
  axis,
  label,
  className,
  children,
  testId = 'axis',
}) => {
  const { chartMeta } = useChartContext() ?? {};
  const isXAxis = axis === 'x';
  const xGTranslate = isXAxis ? 0 : chartMeta?.margin?.left;
  const yGTranslate = isXAxis ? chartMeta?.plotHeight : 0;

  const xLineTranslate = chartMeta?.margin.left;
  const yLineTranslate = isXAxis ? chartMeta?.plotHeight : chartMeta?.margin?.top;

  const width = chartMeta?.plotWidth ?? 0;
  const height = chartMeta?.plotHeight ?? 0;
  const left = chartMeta?.margin?.left ?? 0;
  const top = chartMeta?.margin?.top ?? 0;

  const lineLength = isXAxis ? width - left : height - top;

  const yOffset = height + top;

  return (
    <>
      <rect
        x={xLineTranslate}
        y={yLineTranslate}
        height={isXAxis ? 1 : lineLength}
        className="fill-borderMuted"
        width={isXAxis ? lineLength : 1}
      />
      <g
        data-testid={`${isXAxis ? 'x' : 'y'}-${testId}`}
        className={twMerge(className, 'relative')}
        transform={`translate(${xGTranslate},${yGTranslate})`}
      >
        {children}
        {label && isXAxis && (
          <text
            textAnchor="middle"
            x={(chartMeta?.plotWidth || 0) / 2}
            y={chartMeta?.margin.bottom || 0}
            height={yOffset / 2}
            className="fill-fgMain"
            alignmentBaseline="text-before-edge"
            data-testid="x-axis-label"
          >
            {label}
          </text>
        )}
        {label && !isXAxis && (
          <text
            textAnchor="middle"
            dy=".75em"
            width={chartMeta?.plotHeight || 0}
            x={-(chartMeta?.plotHeight || 0) / 2}
            y={-(chartMeta?.margin.left || 0)}
            className="fill-fgMain bottom-0 -rotate-90"
            data-testid="y-axis-label"
          >
            {label}
          </text>
        )}
      </g>
    </>
  );
};
