import cx from 'classnames';

import { ButtonGroupButton } from './buttonGroupSubComponents/ButtonGroupButton.internal';
import { ButtonGroupCheckbox } from './buttonGroupSubComponents/ButtonGroupCheckbox.internal';
import { ButtonGroupDropdown } from './buttonGroupSubComponents/ButtonGroupDropdown.internal';
import { ButtonGroupMenu } from './buttonGroupSubComponents/ButtonGroupMenu.internal';

export interface ButtonGroupProps {
  /** Child button components. Should be a set of any combination of ButtonGroup sub components */
  children: React.ReactNode;

  /** Custom classnames for the ButtonGroup wrapper */
  className?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;
}

export interface ButtonGroupSubComponents {
  Button: typeof ButtonGroupButton;
  Checkbox: typeof ButtonGroupCheckbox;
  Dropdown: typeof ButtonGroupDropdown;
  Menu: typeof ButtonGroupMenu;
}

export const ButtonGroup: React.FC<ButtonGroupProps> & ButtonGroupSubComponents = ({
  className,
  children,
  testId = 'button-group',
  trackingId = 'button-group',
}): React.ReactElement => {
  return (
    <div
      className={cx(
        // 'sourdough-button-group' is a hook to allow more complex
        // components to have correct borders
        'sourdough-button-group text-fgAlt relative inline-flex rounded-md',
        className,
      )}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      {children}
    </div>
  );
};

export const DEFAULT_BUTTON_GROUP_CHILD_CLASSES =
  'first:rounded-l-md last:rounded-r-md -ml-px first:ml-0 focus:z-10';

ButtonGroup.Button = ButtonGroupButton;
ButtonGroup.Checkbox = ButtonGroupCheckbox;
ButtonGroup.Dropdown = ButtonGroupDropdown;
ButtonGroup.Menu = ButtonGroupMenu;
