/* eslint-disable no-console */
import { useCallback, useEffect, useMemo, useState } from 'react';

export type TriggerLocation = 'top' | 'bottom';

export type Position = {
  x: number;
  y: number;
};

export function getScrollParent(element: HTMLElement) {
  let style = getComputedStyle(element);

  const excludeStaticParent = style.position === 'absolute';
  const overflowRx = /(auto|scroll)/;

  if (style.position === 'fixed') return document.documentElement;

  for (let parent: HTMLElement | null = element; (parent = parent.parentElement); ) {
    style = getComputedStyle(parent);
    if (excludeStaticParent && style.position === 'static') {
      continue;
    }
    if (overflowRx.test(style.overflow + style.overflowY + style.overflowX)) {
      return parent;
    }
  }

  return document.documentElement;
}

export interface UseContainerPlacementProps {
  enabled?: boolean;
  debug?: boolean;

  /**
   * If specified, we will use the element with this ID as the scroll parent
   * instead of automatically trying to detect it
   */
  scrollRootId?: string;

  /**
   * Align with the left or right edge of the trigger element.
   * Defaults left.
   */
  alignment?: 'auto' | 'left' | 'right';

  /**
   * Render above or below the trigger item.
   * Defaults below.
   */
  placement?: 'auto' | 'top' | 'bottom';

  /**
   * Calculates the elementPosition as if the element were
   * not portaled.
   */
  relativeToPortal?: boolean;
  /**
   * If specified, you will get an {@link Position} relative
   * to the parent container, otherwise you will get a
   * {@link TriggerLocation} which is relative to the triggering
   * item.
   */
  targetPosition?: Position;
}

type Directable = {
  triggerAt: TriggerLocation;
  elementPosition: undefined;
};

type Positionable = {
  triggerAt: TriggerLocation | undefined;
  /**
   * This position is relative to the parent container, and is
   * guaranteed to position the target element in the container
   * if it fits.
   */
  elementPosition: Position;
};

export type UseContainerPlacementReturn = {
  /**
   * A required ref which should be placed on whichever element
   * is triggering the menu to pop up, so that we can place
   * the menu relative to it.
   */
  triggerRef: React.RefCallback<HTMLElement | null>;
  /**
   * An optional ref which should be placed outside the portaled
   * elements to retain reference to the portaled item.
   *
   * If unspecified, we just default to the triggerRef.
   */
  menuRef: React.RefCallback<HTMLElement | null>;
  horizontalAlignment: 'left' | 'right';
  update(): void;
} & (Directable | Positionable);

export const useContainerPlacement: (
  props?: UseContainerPlacementProps,
) => UseContainerPlacementReturn = (props) => {
  const enabled = props?.enabled ?? true;
  const debug = (props?.debug ?? false) && enabled;
  const position = props?.targetPosition;
  const alignment = props?.alignment ?? 'left';
  const placement = props?.placement ?? 'below';
  const relativeToPortal = (props?.relativeToPortal ?? false) || !!position;
  const scrollRootId = props?.scrollRootId;
  const [horizontalAlignment, updateHorizontalAlignment] = useState<'left' | 'right'>(
    'left',
  );
  const [triggerAt, setTriggerAt] = useState<TriggerLocation>('bottom');
  const [triggerEl, setTriggerEl] = useState<HTMLElement | null>(null);
  const [menuEl, setMenuEl] = useState<HTMLElement | null>(null);
  const [elementPosition, updateElementPosition] = useState<Position | undefined>(
    undefined,
  );

  const update = useCallback(() => {
    if (!triggerEl || !triggerEl.offsetParent || !enabled) return null;

    const menuElement = menuEl || triggerEl;

    const scrollParent =
      (scrollRootId ? document.getElementById(scrollRootId) : null) ??
      getScrollParent(triggerEl);
    const scrollParentRect = scrollParent.getBoundingClientRect(); // scroll height

    const menuHeight = fullHeight(menuElement);
    const menuWidth = fullWidth(menuElement);
    if (menuWidth === 0 || menuHeight === 0) return;
    const {
      bottom: containerBottom,
      right: containerRight,
      left: containerLeft,
      top: containerTop,
    } = relativeToPortal
      ? triggerEl.getBoundingClientRect()
      : triggerEl.offsetParent.getBoundingClientRect();

    const viewHeight = relativeToPortal
      ? window.innerHeight
      : scrollParent.clientHeight;
    const viewWidth = relativeToPortal ? window.innerWidth : scrollParent.clientWidth;
    const scrollY = relativeToPortal ? 0 : containerBottom - viewHeight;
    const scrollX = relativeToPortal ? 0 : containerRight - viewWidth;

    const spaceAbove = relativeToPortal
      ? containerTop
      : viewHeight - (containerTop - scrollParentRect.bottom);
    const spaceBelow = relativeToPortal
      ? viewHeight - containerBottom
      : viewHeight - (containerBottom - scrollParentRect.top);
    const newTriggerAt =
      placement === 'top'
        ? spaceAbove >= menuHeight
          ? 'top'
          : 'bottom'
        : spaceBelow >= menuHeight
          ? 'bottom'
          : 'top';

    const isAbsolutelyPositioned = position || relativeToPortal;
    if (isAbsolutelyPositioned) {
      let targetPosition = position;

      if (!targetPosition) {
        targetPosition = {
          x: alignment === 'left' ? containerLeft : containerRight - menuWidth,
          y: newTriggerAt === 'top' ? containerTop - menuHeight : containerBottom,
        };
      }

      if (debug) {
        console.log(`useContainerPlacement| Absolute Positioning`);
        console.log(
          `useContainerPlacement| Target Position (x: ${targetPosition.x}, y: ${targetPosition.y})`,
        );
        console.log(
          `useContainerPlacement| Menu Dimensions (w: ${menuWidth}, h: ${menuHeight})`,
        );
        console.log(
          `useContainerPlacement| Container Position (x: ${containerLeft}, y: ${containerTop})`,
        );
        console.log(
          `useContainerPlacement| Input Placement (Vertical: ${newTriggerAt}, Align: ${alignment})`,
        );
      }

      const spaceAbove = targetPosition.y;
      const spaceOnLeft = targetPosition.x;
      const spaceBelow = viewHeight - targetPosition.y + menuHeight - scrollY;
      const spaceOnRight = viewWidth - targetPosition.x + menuWidth - scrollX;

      const verticalTriggerAt =
        spaceBelow >= menuHeight
          ? 'bottom'
          : spaceAbove > spaceBelow
            ? 'top'
            : 'bottom';
      const horizontalTriggerAt =
        alignment === 'auto'
          ? spaceOnRight >= menuWidth
            ? 'left'
            : spaceOnLeft > spaceOnRight
              ? 'right'
              : 'left'
          : alignment;
      const didForceRightAlign =
        alignment === 'auto' && horizontalTriggerAt === 'right';

      const maxXPosition = viewWidth - menuWidth;
      const maxYPosition = viewHeight - menuHeight;

      /**
       * This is the logic which ensures the final position of the element
       * is within the parent container and does not overflow (provided there
       * is enough space)
       */
      const calculatedOffset = {
        x: Math.min(
          Math.max(0, targetPosition.x - (didForceRightAlign ? menuWidth : 0)),
          maxXPosition,
        ),
        y: Math.min(
          Math.max(
            0,
            targetPosition.y - (verticalTriggerAt === 'top' ? menuHeight : 0),
          ),
          maxYPosition,
        ),
      };
      updateElementPosition(calculatedOffset);
      setTriggerAt(verticalTriggerAt);
      updateHorizontalAlignment(horizontalTriggerAt);
      if (debug) {
        console.log('useContainerPlacement|', {
          calculatedOffset,
          verticalTriggerAt,
          horizontalTriggerAt,
        });
      }
    } else {
      const newAlignment = alignment === 'auto' ? 'left' : alignment;
      updateElementPosition(undefined);
      setTriggerAt(newTriggerAt);
      updateHorizontalAlignment(newAlignment);

      if (debug) {
        console.log(`useContainerPlacement| Relative Positioning`);
        console.log(
          `useContainerPlacement| Menu Dimensions (w: ${menuWidth}, h: ${menuHeight})`,
        );
        console.log(
          `useContainerPlacement| Container Position (x: ${containerLeft}, y: ${containerTop})`,
        );
        console.log(
          `useContainerPlacement| Input Placement (Vertical: ${newTriggerAt}, Align: ${alignment})`,
        );
        console.log('useContainerPlacement|', { newTriggerAt, newAlignment });
      }
    }
  }, [
    triggerEl,
    enabled,
    menuEl,
    scrollRootId,
    placement,
    position,
    relativeToPortal,
    debug,
    alignment,
  ]);

  useEffect(() => {
    if (menuEl && triggerEl) {
      update();
    }
  }, [menuEl, triggerEl, update]);

  const triggerRef: React.RefCallback<HTMLUListElement> = useCallback(
    (ref) => {
      if (debug) {
        console.log('useContainerPlacement| triggerRef callback', ref);
      }
      setTriggerEl(ref!);
    },
    [debug, setTriggerEl],
  );

  const menuRef: React.RefCallback<HTMLUListElement> = useCallback(
    (ref) => {
      if (debug) {
        console.log('useContainerPlacement| menuRef callback', ref);
      }
      setMenuEl(ref!);
    },
    [debug, setMenuEl],
  );

  const result = useMemo(() => {
    if (elementPosition) {
      return {
        triggerRef,
        menuRef,
        triggerAt: relativeToPortal ? triggerAt : undefined,
        update,
        horizontalAlignment,
        elementPosition,
      };
    }
    return {
      triggerRef,
      menuRef,
      triggerAt,
      update,
      horizontalAlignment,
      elementPosition: undefined,
    };
  }, [
    elementPosition,
    triggerRef,
    menuRef,
    triggerAt,
    update,
    relativeToPortal,
    horizontalAlignment,
  ]);

  return result;
};

function fullWidth(el: HTMLElement) {
  const width = el.offsetWidth;
  const style = getComputedStyle(el);

  return width + parseInt(style.marginLeft) + parseInt(style.marginRight);
}

function fullHeight(el: HTMLElement) {
  const height = el.offsetHeight;
  const style = getComputedStyle(el);

  return height + parseInt(style.marginTop) + parseInt(style.marginBottom);
}
