import cx from 'classnames';

import { Pill } from './Pill';
import type { PillListProps } from './types';

const wrapperClasses = 'flex flex-wrap gap-2';

/**
 * helper list component that handles a set of pills
 */
export const PillList = ({
  pills,
  className,
  testId = 'pill-list',
  trackingId = 'pill-list',
  ...rest
}: PillListProps) => {
  return (
    <div
      className={cx(wrapperClasses, className)}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      {pills.map(({ id, value }) => (
        <Pill
          {...rest}
          key={id}
          id={id}
          value={value}
          testId={`${testId}-pill`}
          trackingId={`${trackingId}-pill`}
        />
      ))}
    </div>
  );
};
