import { DBT_THEME_USER_PREF_KEY, Theme, type ThemeClass } from './ThemeProvider';

// just used for debugging purposes
type ThemeDetermination = 'app-override' | 'user-pref' | 'system' | 'default';

export const getThemeClass = (theme: Theme): ThemeClass => {
  if (theme === 'system') {
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  }
  return theme;
};

/**
 * determine the initial theme to use when the component is mounted
 */
export const getInitialTheme = (
  theme?: Theme,
  supportsSystemPreference?: boolean,
  shouldStoreLocally?: boolean,
): { initialTheme: Theme; mode: ThemeDetermination } => {
  if (theme) {
    return { initialTheme: theme, mode: 'app-override' };
  }

  const userPref = localStorage.getItem(DBT_THEME_USER_PREF_KEY);
  if (userPref && shouldStoreLocally) {
    return { initialTheme: userPref as Theme, mode: 'user-pref' };
  }

  if (supportsSystemPreference) {
    return { initialTheme: getThemeClass('system'), mode: 'system' };
  }

  return { initialTheme: 'light', mode: 'default' };
};
