class AccordionTestClass {
  // Selectors and cy.gets
  wrapperSelector = (accordionIndex: number | string) =>
    `[data-testid=accordion-${accordionIndex}]`;
  wrapper(accordionIndex: number | string) {
    return cy.get(this.wrapperSelector(accordionIndex));
  }

  headerSelector = (accordionIndex: number | string) =>
    `${this.wrapperSelector(accordionIndex)} [data-testid=accordion-header]`;
  header(accordionIndex: number | string) {
    return cy.get(this.headerSelector(accordionIndex));
  }

  openToggleSelector = (accordionIndex: number | string) =>
    `${this.wrapperSelector(accordionIndex)} [data-testid=accordion-open-toggle]`;
  openToggle(accordionIndex: number | string) {
    return cy.get(this.openToggleSelector(accordionIndex));
  }

  titleSelector = (accordionIndex: number | string) =>
    `${this.wrapperSelector(accordionIndex)} [data-testid=accordion-title]`;
  title(accordionIndex: number | string) {
    return cy.get(this.titleSelector(accordionIndex));
  }

  iconSelector = (accordionIndex: number | string) =>
    `${this.wrapperSelector(accordionIndex)} [data-testid=accordion-icon] svg`;
  icon(accordionIndex: number | string) {
    return cy.get(this.iconSelector(accordionIndex));
  }

  actionsSelector = (accordionIndex: number | string) =>
    `${this.wrapperSelector(accordionIndex)} [data-testid=accordion-actions]`;
  actions(accordionIndex: number | string) {
    return cy.get(this.actionsSelector(accordionIndex));
  }

  contentSelector = (accordionIndex: number | string) =>
    `${this.wrapperSelector(accordionIndex)} [data-testid=accordion-content]`;
  content(accordionIndex: number | string) {
    return cy.get(this.contentSelector(accordionIndex));
  }
}

const AccordionTestConfig = new AccordionTestClass();

export { AccordionTestConfig };
