import { useEffect, useMemo } from 'react';
import { UseFormReturn } from 'react-hook-form';

import { useLiveRegion } from '../../../hooks';
import { getValidationError } from '../../../utils';
import { ActionList, getDefaultActions } from '../../Actions';
import { Form, SubmitFunction } from '../../forms';
import { Notification, NotificationBanner } from '../../NotificationBanner';
import { BasicLayout, BasicLayoutProps } from '../BasicLayout';

const VALIDATION_ERROR_NOTIFICATION: Notification = {
  header:
    'Your changes could not be saved! Please ensure all required fields are filled out, and then try again.',
  id: 'validation-error',
  type: 'error',
};

export interface FormLayoutProps extends Omit<BasicLayoutProps, 'actions'> {
  /** A boolean to determine whether the page has successfully loaded */
  isSuccess: boolean;

  /** A boolean to determine whether the page is loading */
  isLoading?: boolean;

  /** A callback to be triggered when the error banner close button is clicked */
  onErrorDismiss?: () => void;

  /** The methods from useZodForm or useForm */
  formMethods: UseFormReturn;

  /** Data from a react-query call */
  defaultValues?: any;

  /** Custom actions to replace the default edit/save/cancel */
  actions?: ActionList;

  /** A flag to indicate whether to show a feedback button - usually for pendo */
  feedbackButton?: boolean;

  /** Layout width control - standard (default), narrow, or full */
  layoutWidth?: 'standard' | 'narrow' | 'full';

  /** Overall form state, determines which set of default buttons to show */
  isEdit?: boolean;

  /** Whether the user has permission to edit the form */
  canEdit?: boolean;

  /** Event handler for edit button click */
  onEdit(): void;

  /** Event handler for cancel button click */
  onCancel(): void;

  /** Event handler for form submit/save */
  onSubmit: SubmitFunction;

  /** Whether a mutation is currently in progress. */
  isSaving?: boolean;

  /** Whether to disable all form editing buttons*/
  isDisabled?: boolean;

  /** Whether to disable the save button */
  disableSave?: boolean;

  /** Optional tooltip for cancel action */
  cancelTooltip?: string;

  /** Optional tooltip for save action */
  saveTooltip?: string;

  /** Optional tooltip for edit action */
  editTooltip?: string;

  /** Whether to display the success button. Usually triggered temporarily after save completes */
  showSuccessState?: boolean;

  /** The contents of the page */
  children?: React.ReactNode;
}

export const FormLayout: React.FC<FormLayoutProps> = ({
  breadcrumbs,
  title,
  children,
  errorNotification,
  onErrorDismiss,
  isLoading,
  isSuccess,
  isEdit,
  canEdit,
  isDisabled,
  cancelTooltip,
  saveTooltip,
  editTooltip,
  isSaving,
  disableSave,
  onSubmit,
  onEdit,
  onCancel,
  showSuccessState,
  defaultValues,
  formMethods,
  actions,
  layoutWidth = 'standard',
  ...restProps
}): React.ReactElement => {
  const hasValidationError = getValidationError(formMethods);

  const { clearMessage: clearErrorNotification, setMessage: setErrorNotification } =
    useLiveRegion();

  useEffect(() => {
    if (hasValidationError) {
      setErrorNotification(
        <NotificationBanner
          className="mb-6"
          notification={VALIDATION_ERROR_NOTIFICATION}
        />,
      );
    } else {
      clearErrorNotification();
    }
  }, [
    clearErrorNotification,
    errorNotification,
    hasValidationError,
    onErrorDismiss,
    setErrorNotification,
  ]);

  const normalizedActions: ActionList = useMemo(() => {
    const defaults = getDefaultActions({
      isEdit: isEdit ?? false,
      canEdit,
      onCancel,
      onSubmit,
      onEdit,
      formMethods,
      isSaving,
      disableSave,
      cancelTooltip,
      saveTooltip,
      editTooltip,
      isDisabled,
      showSuccessState,
    });

    return actions || defaults;
  }, [
    isEdit,
    canEdit,
    onCancel,
    onSubmit,
    onEdit,
    formMethods,
    isSaving,
    disableSave,
    cancelTooltip,
    saveTooltip,
    editTooltip,
    isDisabled,
    showSuccessState,
    actions,
  ]);

  const memoBreadcrumbs = useMemo(() => breadcrumbs, [breadcrumbs]);

  return (
    <Form
      formMethods={formMethods}
      defaultValues={defaultValues}
      isLoading={isLoading}
      onSubmit={onSubmit}
    >
      <BasicLayout
        title={title}
        actions={normalizedActions}
        breadcrumbs={memoBreadcrumbs}
        isLoading={isLoading}
        errorNotification={errorNotification}
        onErrorDismiss={onErrorDismiss}
        layoutWidth={layoutWidth}
        {...restProps}
      >
        {(isSuccess || isLoading) && <div>{children}</div>}
      </BasicLayout>
    </Form>
  );
};
