import { FormProvider, UseFormReturn } from '@/externals/react-hook-form';
import { SkeletonContextProvider } from '../../../context';
import { useAsyncFormValues } from '../../../hooks/form';

export type SubmitFunction<T = any> = (data: T) => void;

export interface FormProps {
  formMethods: UseFormReturn;
  onSubmit: SubmitFunction;
  defaultValues?: any;
  isLoading?: boolean;
  children?: React.ReactNode;
}

export const Form: React.FC<FormProps> = ({
  formMethods,
  onSubmit,
  children,
  defaultValues,
  isLoading = false,
}): React.ReactElement => {
  useAsyncFormValues({ defaultValues, formMethods, isLoading });
  return (
    <FormProvider {...formMethods}>
      <form onSubmit={formMethods.handleSubmit(onSubmit)}>
        <button type="submit" className="hidden" />
        <SkeletonContextProvider isSkeleton={isLoading}>
          {children}
        </SkeletonContextProvider>
      </form>
    </FormProvider>
  );
};
