import cx from 'classnames';

import { Button, Sizes } from '../..';
import { Checkbox } from '../../forms/Checkbox';
import { DEFAULT_BUTTON_GROUP_CHILD_CLASSES } from '../ButtonGroup';

export interface ButtonGroupCheckboxProps {
  /** Custom checkbox classnames */
  className?: string;

  /** Boolean representing that the checkbox should start checked. */
  defaultChecked?: boolean;

  /** onChange handler. */
  onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;
}

export const ButtonGroupCheckbox: React.FC<ButtonGroupCheckboxProps> = ({
  className,
  onChange,
  defaultChecked,
  testId = 'button-group-checkbox',
  trackingId = 'button-group-checkbox',
}): React.ReactElement => {
  return (
    <Button
      className={cx(DEFAULT_BUTTON_GROUP_CHILD_CLASSES, className)}
      testId={testId}
      trackingId={trackingId}
      type="secondary"
      variant="group"
      size={Sizes.xs}
    >
      <Checkbox
        name="button-group-checkbox"
        onChange={onChange}
        className={className}
        defaultChecked={defaultChecked}
        isEdit
        inputClassName="mt-0"
      />
    </Button>
  );
};
