import { useCallback, useId } from 'react';
import type { Placement } from '@floating-ui/react';
import cx from 'classnames';

import { Icon, type Ryecon } from '..';
import { Tooltip } from '../Tooltip';
import { Sizes, SizeType } from '../types';

export type ButtonType = 'button' | 'submit';
export type ButtonVariant = 'default' | 'group';

interface InternalButtonStyleProps {
  /** Whether the button has custom rounding. Affects sizing */
  isRounded?: boolean;
}

interface InternalButtonProps extends InternalButtonStyleProps {
  /** Optional ref */
  innerRef?: React.Ref<unknown>;
}

type BaseButtonStyleProps = {
  /** The button size */
  size?: Sizes;

  variant?: ButtonVariant;
};

export type BaseButtonProps = BaseButtonStyleProps & {
  /** Accessible label for the button: optional for backward compatibility, will be required soon */
  ariaLabel?: string;

  /** The text to display in button */
  text?: React.ReactNode;

  ryecon?: Ryecon;

  /** The location of the icon */
  iconPlacement?: 'left' | 'right';

  /** Class to apply to icon (e.g. animate-spin) */
  iconClassname?: string;

  /** The button functionality type */
  buttonType?: ButtonType;

  /** Custom button classnames */
  className?: string;

  /** An Onclick handler function */
  onClick?(event: React.MouseEvent): void;

  /** A boolean representing whether the button is disabled */
  isDisabled?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** An optional tooltip */
  tooltip?: React.ReactNode;

  /** Use a portal to render. Defaults to true */
  tooltipPortal?: boolean;

  /**
   * Controls where a tooltip is placed in relation to the target.
   * If not provided, tooltip will default to `autoPlacement`
   */
  tooltipPlacement?: Placement;

  children?: React.ReactNode;

  role?: string;

  id?: string;

  tabIndex?: number;

  /** Standard ARIA prop so that headless UI can pass this value down */
  'aria-expanded'?: boolean;

  /** Internal-only escape hatch for MenuButton, since they always have children for the down-arrow icon */
  isIconOnly?: boolean;

  type?: string;
};

const getRoundedClassNames = (
  size: Sizes,
  isRounded?: boolean,
  isIconOnly?: boolean,
  variant?: ButtonVariant,
) => {
  return {
    /* @deprecated This component is deprecated. Use a Tertiary Button instead. */
    rounded: size === Sizes.sm && !isRounded && !isIconOnly && variant !== 'group',
    'rounded-md':
      (size === Sizes.sm && !isRounded && isIconOnly && variant !== 'group') ||
      (!isRounded && variant !== 'group'),
  };
};

export const baseButtonClassNames = ({
  isIconOnly,
  isRounded,
  size = Sizes.md,
  variant = 'default',
}: InternalButtonStyleProps & BaseButtonStyleProps & { isIconOnly?: boolean }) => {
  const sharedClasses =
    'items-center border focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 transition-colors gap-2 text-nowrap';

  const displayClasses = cx({
    'inline-flex': variant !== 'group',
    flex: variant === 'group',
  });

  const roundingClasses = getRoundedClassNames(size, isRounded, isIconOnly, variant);

  const xsClasses = cx('font-label', {
    'px-1.5 py-[3px]': !isIconOnly,
    'p-[5px]': isIconOnly,
  });
  const smClasses = cx('font-label', {
    'px-2 py-[7px]': !isIconOnly,
    'p-[8px]': isIconOnly,
  });
  const mdClasses = cx('font-label-lg', {
    'min-h-input px-2.5 py-[9px]': !isIconOnly,
    'p-[11px]': isIconOnly,
  });
  const lgClasses = cx('font-label-lg', {
    'px-3 py-[13px]': !isIconOnly,
    'p-[15px]': isIconOnly,
  });

  return cx(sharedClasses, displayClasses, roundingClasses, {
    [xsClasses]: size === Sizes.xs,
    [smClasses]: size === Sizes.sm,
    [mdClasses]: size === Sizes.md,
    [lgClasses]: size === Sizes.lg,
  });
};

const NoiseFilter = () => {
  const uuid = useId();
  const filterId = `noise-${uuid}`;
  return (
    <svg
      className="pointer-events-none absolute inset-0 h-full w-full rounded-md bg-origin-border opacity-90 mix-blend-soft-light"
      width="100%"
      height="100%"
    >
      <filter id={filterId}>
        <feTurbulence
          type="fractalNoise"
          baseFrequency="0.8"
          numOctaves="4"
          stitchTiles="stitch"
        />
        <feColorMatrix type="saturate" values="0" />
      </filter>
      <rect width="100%" height="100%" filter={`url(#${filterId})`} />
    </svg>
  );
};

export const BaseButton: React.FC<BaseButtonProps & InternalButtonProps> = ({
  text,
  ariaLabel,
  ryecon,
  iconPlacement = 'left',
  iconClassname,
  isRounded,
  className,
  size = Sizes.md,
  onClick,
  isDisabled,
  children,
  innerRef,
  buttonType = 'button',
  role,
  testId = 'button',
  trackingId = 'button',
  tooltip = null,
  tooltipPortal,
  tooltipPlacement,
  variant,
  id,
  tabIndex,
  'aria-expanded': ariaExpanded,
  isIconOnly: isIconOnlyProp,
  type,
  ...props
}) => {
  const isIconOnly = !(text || children) || !!isIconOnlyProp;

  const handleClick = useCallback(
    (e: React.MouseEvent) => {
      if (onClick && !isDisabled) {
        onClick(e);
      }
    },
    [onClick, isDisabled],
  );

  const classNames = cx(
    baseButtonClassNames({
      isIconOnly,
      isRounded,
      size,
      variant,
    }),
    'relative',
    className,
  );

  const iconSizes: Record<string, SizeType> = {
    xs: 'xs',
    sm: 'sm',
    md: 'md',
    lg: 'md',
  };

  const showIcon = !!ryecon;
  const buttonIcon = showIcon && (
    <Icon
      ryecon={ryecon}
      size={iconSizes[String(size)]}
      className={cx(iconClassname, {
        'w-4': isIconOnly,
      })}
    />
  );

  const button = (
    <button
      ref={innerRef as React.ForwardedRef<HTMLButtonElement>}
      type={buttonType}
      className={classNames}
      onClick={handleClick}
      disabled={isDisabled || undefined}
      data-testid={testId}
      data-trackingid={trackingId}
      role={role}
      aria-expanded={ariaExpanded}
      aria-label={ariaLabel}
      id={id}
      tabIndex={tabIndex}
      {...props}
    >
      {iconPlacement === 'left' && buttonIcon}
      {text || children}
      {iconPlacement === 'right' && buttonIcon}
      {type === 'brand' && <NoiseFilter />}
    </button>
  );

  if (tooltip) {
    const placementProps = tooltipPlacement
      ? { placement: tooltipPlacement }
      : { autoPlacement: true };
    return (
      <Tooltip
        childrenAreInteractive={!isDisabled}
        content={tooltip}
        portal={tooltipPortal}
        className={cx(
          'inline-flex',
          {
            'w-full': classNames.includes('w-full'),
          },
          getRoundedClassNames(size, isRounded, isIconOnly, variant),
        )}
        {...placementProps}
      >
        {button}
      </Tooltip>
    );
  }
  return button;
};
