import { Axis, Orient } from 'd3-axis-for-react';

import { useChartContext } from '../../ChartProvider/ChartProvider';
import { CategoryAxisScale } from '../../util/scales';
import { generateAxisTextFormatter } from '../../util/truncate';
import { AxisProps, BASE_AXIS_PROPS, BaseAxis, getTickWidth } from '../BaseAxis';

/** @deprecated */
export const CategoryAxis: React.FC<AxisProps> = ({
  axis = 'x',
  enableTruncation = true,
  testId = 'category-axis',
  ...props
}) => {
  const { chartMeta } = useChartContext() ?? {};
  const axisScale = chartMeta?.[`${axis}Scale`] as CategoryAxisScale;

  const numTicks = axisScale.scale.domain().length;
  const tickWidth = getTickWidth(axis, chartMeta, numTicks);

  const allowTruncation = enableTruncation;

  return (
    <BaseAxis testId={testId} {...props} axis={axis}>
      <Axis
        scale={axisScale.scale}
        tickTextProps={{ overflow: 'hidden' }}
        tickFormat={generateAxisTextFormatter(allowTruncation, tickWidth)}
        tickSizeOuter={0}
        orient={axis === 'x' ? Orient.bottom : Orient.left}
        {...BASE_AXIS_PROPS}
      />
    </BaseAxis>
  );
};
