import cx from 'classnames';

import { Badge, BadgeType } from '../../Badge/Badge';
import { Icon } from '../../Icon/Icon';
import type { Ryecon } from '../../ryecons';
import { Tooltip } from '../../Tooltip/Tooltip';
import { type SizeType } from '../../types';

interface CellText {
  text: React.ReactNode;
  iconConfig?: {
    ryecon: Ryecon;
    size?: SizeType;
    className?: string;
  };
  link?: string;
  className?: string;
  hideTruncationTooltip?: boolean;
}

interface CellBadge {
  text: string;
  type: BadgeType;
}

const isBadge = (item: CellBadge | CellText): item is CellBadge => {
  return (item as CellBadge).type !== undefined;
};

interface TextCellProps {
  title: CellText;
  supportingText?: CellText | CellBadge;
}

// TODO: If this `<a>` setup where we need to enable stop event propagation becomes common,
// we should make that its own component.
export const TextCell: React.FC<TextCellProps> = ({ title, supportingText }) => {
  return (
    <div className="truncate text-ellipsis">
      <div className={cx('text-fgMain items-center gap-2 truncate', title.className)}>
        {!!title.iconConfig && (
          <Icon
            ryecon={title.iconConfig.ryecon}
            className={title.iconConfig.className}
            size={title.iconConfig.size ?? 'xs'}
          />
        )}
        <Tooltip
          displayOnlyWhenTruncated
          content={title.text}
          hidden={title.hideTruncationTooltip}
          autoPlacement
          portal
        >
          {(ref) => (
            <p ref={ref} className="truncate">
              {!!title.link && <a href={title.link}>{title.text}</a>}
              {!title.link && title.text}
            </p>
          )}
        </Tooltip>
      </div>
      {supportingText && (
        <>
          {isBadge(supportingText) && (
            <Badge
              text={supportingText.text}
              type={supportingText.type}
              size="sm"
              className="mt-0.5"
            />
          )}
          {!isBadge(supportingText) && (
            <div
              className={cx(
                'text text-fgAlt items-center gap-1 truncate',
                supportingText.className,
              )}
            >
              {!!supportingText.iconConfig && (
                <Icon
                  ryecon={supportingText.iconConfig.ryecon}
                  className={supportingText.iconConfig.className}
                  size={supportingText.iconConfig?.size ?? 'xs'}
                />
              )}
              <Tooltip
                placement="bottom"
                displayOnlyWhenTruncated
                content={supportingText.text}
                hidden={supportingText.hideTruncationTooltip}
                portal
              >
                {(ref) => (
                  <p ref={ref} className="truncate">
                    {!!supportingText.link && (
                      <a
                        href={supportingText.link}
                        onClick={(e) => e.stopPropagation()}
                      >
                        {supportingText.text}
                      </a>
                    )}
                    {!supportingText.link && supportingText.text}
                  </p>
                )}
              </Tooltip>
            </div>
          )}
        </>
      )}
    </div>
  );
};
