import { TREE_ROOT_ID } from '../constants';
import { InternalFileTreeItemType } from '../types';

export const getDropPathDefault = (
  node: InternalFileTreeItemType,
  rootNodeName: string,
) => {
  const {
    data: { relativePath, pathType },
    text,
  } = node;

  if (pathType === 'directory') {
    return relativePath || rootNodeName;
  }

  const isRootNode = relativePath === null;
  const isInRootNode = relativePath === text;

  return isRootNode
    ? TREE_ROOT_ID
    : isInRootNode
      ? rootNodeName
      : `${relativePath.split('/').slice(0, -1).join('/')}`;
};
