import { useCallback } from 'react';

import { useLiveRegion } from '../../hooks/useLiveRegion';
import { DropdownButton } from '../DropdownButton';
import type { DropdownOption } from '../DropdownOptions/DropdownOptions';
import { LoadMore } from './subcomponents/LoadMore.internal';

export interface PaginationFooterProps {
  /** Handler for the loadMore Event */
  onLoadMore(): void;

  /** Flag to indicate a new page is loading */
  isPageLoading?: boolean;

  /** A flag to indicate there are more pages, shows and hides the load more button. */
  hasMorePages?: boolean;

  /** Optional options for custom page sizes */
  pageOptions?: DropdownOption[];

  /** A label for the page options dropdown */
  pageOptionsLabel?: string;

  /** Default selected Page Count Option - dictates viewport size/shown rows, not batch size. */
  selectedPageCount?: DropdownOption;

  /** A label for the `Load More` button when `isLoading` is `true` */
  loadingLabel?: string;

  /** A label for the `Load More` button when `isLoading` is `false` */
  loadMoreLabel?: string;

  /** A label for the `Load More` button when there are no more pages */
  noMorePagesLabel?: string;

  /** A label for displaying current and total pages */
  pageDisplayLabel?: string;

  /** A callback to handle changes to the page options dropdown */
  onPageOptionChange?(itemCount: number): void;

  /** A flag to hide the load more button */
  shouldShowLoadMore?: boolean;
}

// TODO: (when rebuilding the table) Rename this page options to view options
// page options don't actually dictate batch size, it's all about viewport size.

export const DEFAULT_PAGE_OPTIONS: DropdownOption[] = [
  { label: '5 Rows', value: 5 },
  { label: '10 Rows', value: 10 },
  { label: '25 Rows', value: 25 },
  { label: '50 Rows', value: 50 },
];

export const PaginationFooter: React.FC<PaginationFooterProps> = ({
  hasMorePages,
  pageOptionsLabel = 'Show:',
  pageOptions = DEFAULT_PAGE_OPTIONS,
  onLoadMore,
  isPageLoading,
  loadMoreLabel = 'Load more...',
  loadingLabel = 'Loading...',
  noMorePagesLabel = 'No more pages',
  onPageOptionChange,
  selectedPageCount = DEFAULT_PAGE_OPTIONS[0],
  pageDisplayLabel = '',
  shouldShowLoadMore = true,
}): React.ReactElement => {
  const { LiveRegion, setMessage } = useLiveRegion({
    display: 'sr-only',
  });
  const handleOptionChange = useCallback(
    ({ value }: { value: string | number }) => {
      if (!onPageOptionChange) {
        return;
      }

      onPageOptionChange(value as number);
      setMessage(`Showing ${value} items.`);
    },
    [onPageOptionChange, setMessage],
  );

  return (
    <div className="font-label flex flex-wrap items-center py-5">
      {!!pageDisplayLabel && (
        <div className="flex-none" aria-live="polite" role="status">
          {pageDisplayLabel}
        </div>
      )}

      <div className="mx-4 flex flex-grow items-center">
        {shouldShowLoadMore && (
          <LoadMore
            hasMorePages={hasMorePages}
            onLoadMore={onLoadMore}
            isPageLoading={isPageLoading}
            loadingLabel={loadingLabel}
            noMorePagesLabel={noMorePagesLabel}
            loadMoreLabel={loadMoreLabel}
          />
        )}
      </div>
      {onPageOptionChange && (
        <DropdownButton
          name={pageOptionsLabel}
          defaultOption={selectedPageCount}
          options={pageOptions}
          onChange={handleOptionChange}
        />
      )}
      <LiveRegion />
    </div>
  );
};
