import AnsiToHtml from 'ansi-to-html';
import DOMPurify from 'dompurify';

const formatter = new AnsiToHtml({
  // xterm number 256 color reference: https://ss64.com/bash/syntax-colors.html
  colors: {
    1: 'var(--fgDanger)',
    2: 'var(--fgSuccess)',
    3: 'var(--fgWarning)',
    4: 'var(--fgInfo)',
  },
  escapeXML: true,
});

export const ansiToHtml = (
  input: string,
  onError?: (error: unknown) => void,
): string => {
  let output = input;

  try {
    output = formatter.toHtml(input);
  } catch (e) {
    onError && onError(e);
  }

  return DOMPurify.sanitize(output, {
    USE_PROFILES: { html: true },
  });
};
