import cx from 'classnames';

import { useSkeletonContext } from '../../../context';
import type { LoadingDimensions } from '../../../globalTypes';
import { getIconProps } from '../../Icon/helpers';
import { isIconProps } from '../../Icon/helpers.internal';
import { Icon } from '../../Icon/Icon';
import { StatusIconVariant } from '../../Icon/types';
import { LoadingBlock } from '../../LoadingBlock/LoadingBlock';
import { Ryecon } from '../../ryecons/types';
import { SizeType } from '../../types';

const defaultDimensions = { width: 100, height: 15 };

export type IconTextProps = {
  /** in case the icon provides contextual information not in the associated text */
  iconAlt?: string;
  statusIconVariant?: StatusIconVariant;
  ryecon?: Ryecon;
  iconWrapperClassname?: string;
  iconClassname?: string;
  textClassname?: string;
  testId?: string;
  trackingId?: string;
  text?: React.ReactNode;
  children?: React.ReactNode;
  skeleton?: boolean;
  loadingDimensions?: LoadingDimensions;
  className?: string;
  size?: SizeType;
  iconColor?: string;
};

export const IconText: React.FC<IconTextProps> = ({
  iconAlt,
  statusIconVariant,
  ryecon,
  iconClassname,
  iconWrapperClassname,
  textClassname,
  testId = 'icon-text',
  trackingId = 'icon-text',
  className,
  skeleton,
  text,
  children,
  loadingDimensions = {},
  size = 'md',
  iconColor,
}) => {
  const textClasses = cx({
    'font-body-sm': size === 'sm' || size === 'xs',
    'font-body': size === 'md',
    'font-body-lg': size === 'lg',
  });

  const iconSize: SizeType = cx({
    xs: size === 'xs',
    sm: size === 'sm',
    md: size === 'lg' || size === 'md',
  }) as SizeType;

  const iconPadding = cx({
    'mr-1': size === 'sm' || size === 'xs',
    'mr-2': size === 'md' || size === 'lg',
  });

  const { width, height }: LoadingDimensions = {
    ...defaultDimensions,
    ...loadingDimensions,
  };
  const globalSkeleton = useSkeletonContext()?.skeleton;
  const showSkeleton = skeleton || globalSkeleton;

  const iconProps = getIconProps(
    {
      alt: iconAlt,
      iconColor,
      testId: `${testId}-icon`,
      trackingId: `${trackingId}-icon`,
      size: iconSize,
      className: cx(iconClassname, iconPadding),
    },
    { statusIconVariant, ryecon },
  );

  return (
    <div
      className={cx('text-fgDecorative inline-flex items-center', className)}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      {isIconProps(iconProps) && (
        <div className={cx(iconWrapperClassname, 'inline-flex items-center')}>
          <Icon {...iconProps} />
        </div>
      )}
      <div
        data-trackingid={`${trackingId}-text`}
        data-testid={`${testId}-text`}
        className={cx(textClasses, textClassname)}
      >
        {showSkeleton ? (
          <LoadingBlock width={width} height={height} />
        ) : (
          text || children
        )}
      </div>
    </div>
  );
};
