import { forwardRef, type ForwardRefExoticComponent } from 'react';
import cx from 'classnames';

import { RyeconCaretRight } from '../ryecons';
import { BaseButton, BaseButtonProps } from './BaseButton.internal';

export type AuthenticationButtonStyleType =
  | 'primary'
  | 'accent'
  | 'third-party'
  | 'signup';

export type AuthenticationButtonProps = BaseButtonProps & {
  /** The button style type */
  type?: AuthenticationButtonStyleType;
};

export const AuthenticationButton: ForwardRefExoticComponent<AuthenticationButtonProps> =
  forwardRef(
    (
      {
        type = 'primary',
        isDisabled,
        className,
        variant,
        iconPlacement = 'right',
        ryecon,
        children,
        ...props
      },
      ref,
    ) => {
      const defaultRyecon = type !== 'signup' ? RyeconCaretRight : undefined;
      const iconProps = { ryecon: ryecon ?? defaultRyecon };

      const secondaryStyles =
        'text-fgMain bg-bgMain border-1 border-borderMain hover:border-borderMainHover hover:bg-bgMainHover active:bg-bgMainActive focus-visible:ring-focusBrand focus-visible:ring-offset-bgMain shadow-rest border-1 border-borderMain';

      const styleClasses = cx(
        {
          'flex w-full items-center justify-center':
            type === 'primary' || type === 'accent' || type === 'third-party',

          // Main styles
          'bg-bgBrand hover:bg-bgBrandHover focus-visible:ring-focusBrand active:bg-bgBrandActive text-fgWhite shadow-rest border-transparent':
            type === 'primary' && !isDisabled,

          // Accent styles
          'bg-bgBrandAlt text-fgWhite hover:bg-bgBrandAltHover focus-visible:ring-focusBrand active:bg-bgBrandAltActive shadow-rest border-transparent':
            type === 'accent' && !isDisabled,

          // Third party login styles
          [secondaryStyles]:
            (type === 'third-party' || type === 'signup') && !isDisabled,

          // General disabled styles
          'bg-bgDisabled text-fgDisabled cursor-not-allowed': isDisabled,
        },
        className,
      );

      return (
        <BaseButton
          innerRef={ref}
          isDisabled={isDisabled}
          variant={variant}
          className={styleClasses}
          {...iconProps}
          iconPlacement={iconPlacement}
          {...props}
        >
          {children}
        </BaseButton>
      );
    },
  );
