import { usePillSubComponentContext } from '../context';
import { Pill } from '../Pill';
import type { PillBaseProps } from '../types';

type ListSubProps = PillBaseProps;

/**
 * helper list component that handles a set of pills
 */
export function ListSub({
  testId = 'pill-list',
  trackingId = 'pill-list',
  ...rest
}: ListSubProps) {
  const { pills } = usePillSubComponentContext();
  return pills.map(({ id, value }) => (
    <Pill
      {...rest}
      key={id}
      id={id}
      value={value}
      testId={`${testId}-pill`}
      trackingId={`${trackingId}-pill`}
    />
  ));
}
