import { Link } from 'react-router-dom';

import { Button } from '../Button';
import { Icon } from '../Icon/Icon';
import { RyeconHelp, RyeconPlus } from '../ryecons';
import type { Ryecon } from '../ryecons/types';
import { Sizes } from '../types';

export type EmptyStateProps = {
  /** The header text */
  header?: string;

  ryecon?: Ryecon;

  /** A url for entity creation */
  createHref?: string;

  /** A helper text string */
  helpText?: string;

  /** The button text string */
  buttonText?: string;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;
};

export const EmptyState: React.FC<EmptyStateProps> = ({
  header = "There's nothing here.",
  ryecon = RyeconHelp,
  createHref,
  buttonText = 'Create one!',
  helpText,
  testId = 'empty-state',
  trackingId = 'empty-state',
}): React.ReactElement => {
  return (
    <div className="text-center" data-testid={testId} data-trackingid={trackingId}>
      <Icon ryecon={ryecon} size="2xl" className="text-fgDecorative m-auto block" />
      <h4
        className="text-fgAlt font-heading-4 mt-2"
        data-testid={`${testId}-header`}
        data-trackingid={`${trackingId}-header`}
      >
        {header}
      </h4>
      {!!helpText && (
        <p
          className="text-fgDecorative font-body mt-1"
          data-testid={`${testId}-help`}
          data-trackingid={`${trackingId}-help`}
        >
          {helpText}
        </p>
      )}
      {!!createHref && (
        <div className="mt-6">
          <Link to={createHref}>
            <Button
              type="primary"
              size={Sizes.sm}
              text={
                <>
                  <Icon ryecon={RyeconPlus} aria-hidden="true" />
                  {buttonText}
                </>
              }
              testId={`${testId}-create`}
              trackingId={`${trackingId}-create`}
            />
          </Link>
        </div>
      )}
    </div>
  );
};
