import type { FC } from 'react';

import { PopoverContext } from '../context';
import type { HeadlessPopoverProps } from '../types';
import { usePopover } from '../usePopover';
import { HeadlessContent } from './HeadlessContent';
import { HeadlessTrigger } from './HeadlessTrigger';

/**
 * Wrapper component to setup context provider to children components
 * Should be used in conjunction with HeadlessTrigger + HeadlessContent
 * Example:
 *
 * <HeadlessPopover>
 *   <HeadlessPopover.Trigger>Element to trigger popover</HeadlessPopover.Trigger>
 *   <HeadlessPopover.Content testId={testId} trackingId={trackingId}>Content to show in floating element</HeadlessPopover.Content>
 * </HeadlessPopover>
 */

type SubComponents = {
  Trigger: typeof HeadlessTrigger;
  Content: typeof HeadlessContent;
};
export const HeadlessPopover: FC<HeadlessPopoverProps> & SubComponents = ({
  children,
  ...rest
}) => {
  // sane defaults added in usePopover
  const config = usePopover({ ...rest });
  return <PopoverContext.Provider value={config}>{children}</PopoverContext.Provider>;
};

HeadlessPopover.Trigger = HeadlessTrigger;
HeadlessPopover.Content = HeadlessContent;
