import { ItemHeights } from './types';

export const TREE_ROOT_ID = 'root';

export const DROP_ITEM_TYPE = 'fileTreeItem';

// The default will be equivalent to a text-sm font size
export const DEFAULT_ITEM_HEIGHT = 28;

export const FONT_SIZE_TO_HEIGHT_MAP: Record<string, number> = {
  'text-xs': 24,
  'text-sm': 28,
  'text-base': 32,
  'text-lg': 36,
  'text-xl': 40,
};

export const HEIGHT_TO_FONT_SIZE_MAP: Record<number, string> = Object.entries(
  FONT_SIZE_TO_HEIGHT_MAP,
).reduce(
  (acc, [key, value]) => ({
    ...acc,
    [value]: key,
  }),
  {},
);

export const parseItemHeights = (itemHeights?: ItemHeights) => {
  return {
    file: itemHeights?.file || DEFAULT_ITEM_HEIGHT,
    directory: itemHeights?.directory || DEFAULT_ITEM_HEIGHT,
    'load-more': itemHeights?.loadMore || DEFAULT_ITEM_HEIGHT,
    loading: itemHeights?.loading || DEFAULT_ITEM_HEIGHT,
    empty: itemHeights?.empty || DEFAULT_ITEM_HEIGHT,
    root: itemHeights?.root || DEFAULT_ITEM_HEIGHT,
  };
};
