import {
  type CompositionEventHandler,
  type KeyboardEvent,
  useCallback,
  useRef,
} from 'react';

type IMEGuardedHandler<T extends HTMLElement> = (event: KeyboardEvent<T>) => void;

/**
 * Tracks IME composition state and provides a guard for keyboard event
 * handlers. When an IME (Input Method Editor) is active — e.g. for
 * Japanese, Chinese, or Korean text entry — pressing Enter confirms the
 * character conversion rather than triggering an action like form
 * submission. This hook encapsulates the dual-check pattern needed to
 * reliably detect composition across browsers:
 *
 *  1. A synchronous ref updated via `onCompositionStart` / `onCompositionEnd`
 *     (handles Chrome, where `keydown` fires *before* `compositionend`).
 *  2. The native `event.nativeEvent.isComposing` property
 *     (handles Firefox and other browsers with different event ordering).
 *
 * Usage:
 * ```tsx
 * const { onCompositionStart, onCompositionEnd, withIMEGuard } = useIMEComposition();
 *
 * const onKeyDown = withIMEGuard((event) => {
 *   if (event.key === 'Enter' && !event.shiftKey) {
 *     event.preventDefault();
 *     onSubmit();
 *   }
 * });
 *
 * <textarea
 *   onKeyDown={onKeyDown}
 *   onCompositionStart={onCompositionStart}
 *   onCompositionEnd={onCompositionEnd}
 * />
 * ```
 */
export const useIMEComposition = <T extends HTMLElement = HTMLElement>() => {
  const isComposingRef = useRef(false);

  const onCompositionStart = useCallback<CompositionEventHandler<T>>(() => {
    isComposingRef.current = true;
  }, []);

  const onCompositionEnd = useCallback<CompositionEventHandler<T>>(() => {
    isComposingRef.current = false;
  }, []);

  /**
   * Wraps a keyboard event handler so it is skipped entirely while an
   * IME composition session is active.
   */
  const withIMEGuard = useCallback(
    (handler: IMEGuardedHandler<T>): IMEGuardedHandler<T> =>
      (event: KeyboardEvent<T>) => {
        if (isComposingRef.current || event.nativeEvent.isComposing) {
          return;
        }
        handler(event);
      },
    [],
  );

  return {
    isComposingRef,
    onCompositionStart,
    onCompositionEnd,
    withIMEGuard,
  } as const;
};
