import cx from 'classnames';

import { Accordion, AccordionProps } from './Accordion';

export type AccordionPropsWithID = AccordionProps & {
  id: number | string;
};

export interface AccordionsProps {
  /** An array of AccordionProps.  Each item in the array will be rendered as an Accordion. */
  accordions: AccordionPropsWithID[];
  /** Adds border and rounding to the list */
  isBorder?: boolean;
}

const AccordionList = ({ accordions, isBorder }: AccordionsProps) => {
  const borderClasses = 'rounded-md border border-borderMuted overflow-clip';
  const commonClasses = 'divide-y divide-borderMuted border-y border-borderMuted';
  const className = cx(commonClasses, { [borderClasses]: isBorder });
  return (
    <div className={className}>
      {accordions.map((accordion, i) => (
        <Accordion {...accordion} testId={`accordion-${i}`} key={accordion.id} />
      ))}
    </div>
  );
};

export { AccordionList };
