import cx from 'classnames';

import { MenuButton, type MenuButtonProps } from '../../MenuButton';
import { Sizes } from '../../types';

import './ButtonGroupMenu.css';

export interface ButtonGroupMenuProps extends Omit<MenuButtonProps, 'onClick'> {
  onClick?: MenuButtonProps['onClick'];
}

export const ButtonGroupMenu: React.FC<Omit<ButtonGroupMenuProps, 'size'>> = ({
  testId = 'button-group-menu',
  trackingId = 'button-group-menu',
  ...props
}): React.ReactElement => {
  const onClick = props.onClick ?? (() => null);
  return (
    <MenuButton
      onClick={onClick}
      buttonVariant="group"
      testId={testId}
      trackingId={trackingId}
      size={Sizes.sm}
      {...props}
      wrapperClassName={cx('sourdough-buttongroup-menu', props.wrapperClassName)}
      className={cx('sourdough-buttongroup-menu-button h-full', props.className)}
    />
  );
};
