import { Fragment, ReactNode } from 'react';
import React from 'react';
import { Menu, Transition } from '@headlessui/react';
import cx from 'classnames';
import { twMerge } from 'tailwind-merge';

import { Portal } from '../../context/PortalNode';
import {
  type Position,
  type TriggerLocation,
  useContainerPlacement,
} from '../../hooks';
import { Icon } from '../Icon';
import { RyeconCheckmark } from '../ryecons';
import { Ryecon } from '../ryecons/types';

/** Fields that are common to both {@link MenuItem} and {@link MenuItemGroup} */
type MenuItemBase = {
  /** Text to be displayed for the menu item. */
  label: string;
  /** Icon to be displayed next to menu item. */
  ryecon?: Ryecon;
  /** Whether or not a divider should be added above this item */
  includeTopDivider?: boolean;
};

export type MenuItem = MenuItemBase & {
  /** Description (smaller text) to be displayed in menu item. */
  description?: string | ReactNode;
  /** Text to be displayed on hover. */
  title?: string;
  value?: number | string;
  /** A boolean representing whether the item is disabled */
  isDisabled?: boolean;
  /** A boolean representing whether the item is selected */
  isSelected?: boolean;
};

export type MenuItemGroup = MenuItemBase & {
  /** An array of options for the menu */
  items: MenuItem[];
};

/**
 * An optional manual override which allows you to take control of when
 * the Menu is open or closed.
 */
type MenuOverride = {
  /**
   * Will display the menu if `true`.
   */
  isOpen: boolean;
  /**
   * When called, isOpen must become `false`.
   */
  close: () => void;
};

export interface MenuItemsProps {
  /** An array of options for the menu */
  items: (MenuItem | MenuItemGroup)[];

  /**
   * Since value will be the label if no value is provided.
   * If multiple selections are allowed, always supply an array (empty or not)
   * to ensure consistent accessibility.
   */
  selectedValue?: (string | number) | null | (string | number)[];

  /** A callback handler */
  onClick?(item: string | number, event: React.MouseEvent): void;

  /** Custom classnames for the menu option list */
  className?: string;

  /** Placement options for the menu, auto will self-determine position */
  placement?: 'auto' | TriggerLocation | Position;

  /** Align with the left or right edge of the trigger element. Default to left */
  alignment?: 'auto' | 'left' | 'right';

  /**
   * If the placement is clipped by an overflow parent, setting this to true
   * will portal the MenuItems to the same place visually, but into the
   * nearest {@link PortalNodeContext}
   */
  shouldPortal?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;

  /**
   * Use this override if you want the menu to appear relative to something
   * like mouse position rather than a UI element
   */
  targetPosition?: Position;

  /** Enable additional logging */
  debug?: boolean;

  /**
   * Allows you to manually control when the menu is open or closed
   */
  stateOverride?: MenuOverride;

  /**
   * If specified, we will use the element with this ID as the scroll parent
   * instead of automatically trying to detect it
   */
  scrollRootId?: string;
}

const MenuContents = ({
  items,
  onClick,
  testId = 'menu-button-options',
  trackingId = 'menu-button-options',
  className,
  stateOverride,
  selectedValue,
}: MenuItemsProps) => {
  const isGroup = (item: MenuItem | MenuItemGroup): item is MenuItemGroup => {
    return (item as MenuItemGroup).items !== undefined;
  };
  const isSelected = (value: number | string) => {
    return Array.isArray(selectedValue)
      ? selectedValue.includes(value)
      : value === selectedValue;
  };

  return (
    <Menu.Items
      className={cx(
        'border-borderMuted bg-bgMain shadow-hover flex min-w-max flex-col overflow-auto rounded-lg border p-1 py-2 text-left focus:outline-none',
        className,
      )}
      aria-multiselectable={Array.isArray(selectedValue)}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      {items.map((item, index) => {
        if (isGroup(item)) {
          const { label, items, ryecon, includeTopDivider } = item;
          return (
            <div key={`${label}-${index}`}>
              <div
                className={twMerge(
                  'flex items-center gap-2 py-2 pl-3',
                  cx(
                    includeTopDivider &&
                      'border-t-borderMuted rounded-t-none border-t border-b-transparent border-l-transparent border-r-transparent',
                  ),
                )}
              >
                {!!ryecon && <Icon ryecon={ryecon} className="text-fgDecorative" />}
                <span className="text-fgDecorative font-label">{label}</span>
              </div>
              {items.map((item, innerIndex) => {
                const value = item.value ?? item.label;
                return (
                  <MenuItemComponent
                    key={value}
                    {...item}
                    isSelected={isSelected(value)}
                    autoFocus={index === 0 && innerIndex === 0}
                    onClick={(...params) => {
                      onClick?.(...params);
                      stateOverride?.close?.();
                    }}
                    testId={`${testId}-${index}`}
                    trackingId={`${trackingId}-${index}`}
                  />
                );
              })}
            </div>
          );
        }
        const value = item.value ?? item.label;
        return (
          <MenuItemComponent
            key={value}
            autoFocus={index === 0}
            isTopLevel
            isSelected={isSelected(value)}
            onClick={(...params) => {
              onClick?.(...params);
              stateOverride?.close?.();
            }}
            testId={`${testId}-${index}`}
            trackingId={`${trackingId}-${index}`}
            {...item}
          />
        );
      })}
    </Menu.Items>
  );
};

/*
 * The <MenuItems> component defines common menu items styling and behavior that can
 * be used across multiple menu related components.
 *
 * For example, currently these items are used in:
 * - MenuButton
 * - ButtonGroup.Menu
 */
export const MenuItems = React.forwardRef<HTMLDivElement | null, MenuItemsProps>(
  (
    {
      placement = 'auto',
      alignment = 'left',
      shouldPortal = false,
      scrollRootId,
      ...props
    },
    menuForwardRef,
  ) => {
    const {
      menuRef,
      triggerRef,
      triggerAt,
      update,
      elementPosition,
      horizontalAlignment,
    } = useContainerPlacement({
      alignment,
      placement: typeof placement === 'string' ? placement : 'auto',
      relativeToPortal: shouldPortal,
      targetPosition: props.targetPosition,
      scrollRootId,
      debug: props.debug,
    });

    // Make sure both `top-full` and `bottom-full`
    // is not added or menu height will be 0px
    const isTop = placement === 'bottom' || triggerAt === 'bottom';
    const isBottom = placement === 'top' || triggerAt === 'top';
    const positionalClasses = cx(
      `font-label-lg absolute z-20 ${
        horizontalAlignment === 'left' ? 'left-0' : elementPosition ? '' : 'right-0'
      }`,
      {
        'top-full mt-2': isTop,
        'bottom-full mb-2': !isTop && isBottom,
      },
      props.className,
    );

    // adds additional gap between button and menu that is not accounted for in `elementPosition`
    const topOffset = shouldPortal && placement === 'top' ? -8 : 0;

    return (
      <div ref={triggerRef} className={positionalClasses}>
        <Portal enable={shouldPortal}>
          <Transition
            as={Fragment}
            leave="transition ease-in duration-100"
            leaveFrom="opacity-100"
            leaveTo="opacity-0"
            beforeEnter={placement === 'auto' ? update : undefined}
            beforeLeave={props.stateOverride?.close}
            show={props.stateOverride?.isOpen}
          >
            <div
              ref={menuRef}
              style={
                elementPosition
                  ? {
                      top: `${elementPosition.y + topOffset}px`,
                      left: `${elementPosition.x}px`,
                    }
                  : shouldPortal
                    ? // take out of page flow until elementPosition is calculated
                      { position: 'fixed' }
                    : undefined
              }
              className={shouldPortal ? positionalClasses : undefined}
            >
              <div ref={menuForwardRef}>
                <MenuContents
                  placement={placement}
                  shouldPortal={shouldPortal}
                  {...props}
                />
              </div>
            </div>
          </Transition>
        </Portal>
      </div>
    );
  },
);

type MenuItemProps<TValue extends string | number> = MenuItem & {
  isTopLevel?: boolean;
  onClick?(item: TValue, event: React.MouseEvent): void;
  testId?: string;
  trackingId?: string;
  autoFocus: boolean;
};

const MenuItemComponent = <TValue extends string | number>({
  label,
  description,
  title,
  value,
  isTopLevel,
  includeTopDivider,
  ryecon,
  onClick,
  autoFocus,
  isDisabled = false,
  isSelected = false,
  testId = 'menu-item',
  trackingId = 'menu-item',
}: MenuItemProps<TValue>) => {
  return (
    <Menu.Item disabled={isDisabled || isSelected}>
      {({ active }) => (
        <button
          title={title}
          aria-label={label}
          autoFocus={autoFocus}
          role="option"
          aria-selected={isSelected}
          disabled={isDisabled || isSelected}
          aria-disabled={isDisabled}
          className={twMerge(
            'font-label flex w-full gap-2 truncate rounded-md border border-transparent py-[5px] pl-2 text-left',
            includeTopDivider &&
              'border-t-borderMuted rounded-t-none border-t border-b-transparent border-l-transparent border-r-transparent',
            'bg-bgMain text-fgMain',
            isDisabled && 'text-fgDisabled',
            !isDisabled && 'hover:bg-bgMainHover',
            active && 'bg-bgNeutralMuted',
            !active && 'bg-bgMain',
            !isTopLevel && 'pl-3',
            isSelected && 'border-borderMuted bg-bgDisabled border',
            isSelected && !isDisabled ? 'hover:border-borderMuted' : '',
          )}
          onClick={(e) => {
            e.stopPropagation();
            if (onClick) {
              onClick((value ?? label) as TValue, e);
            }
          }}
          data-testid={testId}
          data-trackingid={trackingId}
        >
          {!!ryecon && (
            <Icon
              ryecon={ryecon}
              iconColor={cx({
                'text-fgDisabled': isDisabled,
                'text-fgAlt': !isDisabled,
              })}
              className="mt-[1px]"
            />
          )}
          <div className="flex flex-col gap-0.5">
            <div>{label}</div>
            {!!description && (
              <div
                className={cx(
                  'font-caption',
                  isDisabled ? 'text-fgDisabled' : 'text-fgDecorative',
                )}
              >
                {description}
              </div>
            )}
          </div>
          <div className="relative ml-auto pr-9">
            {isSelected && (
              <Icon
                className="text-fgMain absolute right-3 mt-1"
                ryecon={RyeconCheckmark}
                size={'xs'}
                alt="Selected"
              />
            )}
          </div>
        </button>
      )}
    </Menu.Item>
  );
};
