import cx from 'classnames';

import { useSkeletonContext } from '../../../context/SkeletonProvider';
import { LoadingBlock } from '../../LoadingBlock/LoadingBlock';
import { DEFAULT_STATUS_BAR_CHILD_CLASSES } from '../StatusBar';

export interface StatusBarStateTileProps {
  /** The high level text to display */
  headerText: React.ReactNode;

  /** The label text to display */
  label: string;

  /** The status */
  status: 'success' | 'warning' | 'error' | 'default';

  /** Custom classnames */
  className?: string;

  /** Flag to render in skeleton mode */
  skeleton?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export const StatusBarStateTile: React.FC<StatusBarStateTileProps> = ({
  headerText,
  label,
  status,
  className,
  skeleton = false,
  testId = 'status-bar-state-tile',
  trackingId = 'status-bar-state-tile',
}): React.ReactElement => {
  const globalSkeleton = useSkeletonContext()?.skeleton;
  const shouldSkeleton = skeleton || globalSkeleton;
  return (
    <div
      className={cx(
        'flex flex-col items-center font-semibold transition-colors first:border-l-0',
        {
          'bg-bgSuccessTinted': status === 'success' && !shouldSkeleton,
          'bg-bgWarningTinted': status === 'warning' && !shouldSkeleton,
          'bg-bgDangerTinted': status === 'error' && !shouldSkeleton,
        },
        DEFAULT_STATUS_BAR_CHILD_CLASSES,
        className,
      )}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      <div
        className={cx('flex grow basis-0 items-center text-lg', {
          'text-fgSuccess': status === 'success' && !shouldSkeleton,
          'text-fgWarning': status === 'warning' && !shouldSkeleton,
          'text-fgDanger': status === 'error' && !shouldSkeleton,
        })}
        data-testid={`${testId}-header-text`}
        data-trackingid={`${trackingId}-header-text`}
      >
        {shouldSkeleton && <LoadingBlock width={105} height={24} />}
        {!shouldSkeleton && headerText}
      </div>
      <div
        className="text-fgDecorative font-label flex grow basis-0 items-end"
        data-testid={`${testId}-label`}
        data-trackingid={`${trackingId}-label`}
      >
        {label}
      </div>
    </div>
  );
};
