import { useEffect, useRef, useState } from 'react';
import React from 'react';

import { Dialog, Transition } from '@/externals/headlessui';

/**
 * @deprecated use Drawer instead. Alternatively, convert the internal content to a full page (especially if a form is contained within)
 */
export interface SidePanelProps {
  /** A boolean to determine whether the sidepanel is open */
  isOpen: boolean;

  /** Event handler for close button click */
  onClose: () => void;

  /** The content to display. Should be a `SidePanelContent` component */
  children: (onClose: () => void) => React.ReactNode;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** If you set this to false, you can allow hidden children to render even when the panel is closed */
  shouldFreezeContents?: boolean;

  /**
   * CSS selectors to ignore when checking for outside clicks.
   * Use this to prevent the dialog from closing when clicking on portaled content.
   * Example: ['[data-testid="portal-node-root"]', '.my-portaled-element']
   */
  interactOutsideIgnoreSelectors?: string[];
}

/**
 * @deprecated use Drawer instead. Alternatively, convert the internal content to a full page (especially if a form is contained within)
 */
export const SidePanel: React.FC<SidePanelProps> = ({
  isOpen,
  onClose,
  children,
  shouldFreezeContents = true,
  testId = 'sidepanel',
  trackingId = 'sidepanel',
  interactOutsideIgnoreSelectors = ['[data-testid="portal-node-root"]'],
}): React.ReactElement => {
  const [dialogIsOpen, setDialogIsOpen] = useState(isOpen);
  const panelRef = useRef<HTMLDivElement>(null);
  const lastMouseDownTargetRef = useRef<EventTarget | null>(null);

  useEffect(() => {
    if (isOpen) {
      setDialogIsOpen(true);
    }
  }, [isOpen, setDialogIsOpen]);

  // Track mousedown target to determine if clicks should be ignored
  useEffect(() => {
    if (!isOpen || interactOutsideIgnoreSelectors.length === 0) return;

    const handleMouseDown = (event: MouseEvent) => {
      lastMouseDownTargetRef.current = event.target;
    };

    document.addEventListener('mousedown', handleMouseDown, true);
    return () => document.removeEventListener('mousedown', handleMouseDown, true);
  }, [isOpen, interactOutsideIgnoreSelectors]);

  // Wrapped onClose that checks if the click should be ignored
  const handleClose = () => {
    if (interactOutsideIgnoreSelectors.length === 0) {
      onClose();
      return;
    }

    const target = lastMouseDownTargetRef.current as Element | null;
    if (!target) {
      onClose();
      return;
    }

    // Check if the click was on an ignored selector (e.g., portaled content)
    for (const selector of interactOutsideIgnoreSelectors) {
      try {
        if (target.closest(selector)) {
          // Don't close - click was on portaled content
          return;
        }
      } catch {
        // Invalid selector; ignore
      }
    }

    // Click was not on portaled content, proceed with close
    onClose();
  };

  return (
    <Transition.Root show={isOpen} as={React.Fragment}>
      <Dialog
        as="div"
        className="fixed z-20 overflow-hidden"
        onClose={handleClose}
        open={dialogIsOpen}
      >
        <div className="absolute overflow-hidden">
          <div
            ref={panelRef}
            className="fixed bottom-0 right-0 top-0 flex max-w-full pl-10"
            data-testid={testId}
            data-trackingid={trackingId}
          >
            <Transition.Child
              as={React.Fragment}
              enter="transform transition ease-in-out duration-500"
              enterFrom="translate-x-full"
              enterTo="translate-x-0"
              leave="transform transition ease-in-out duration-500"
              leaveFrom="translate-x-0"
              leaveTo="translate-x-full"
              afterLeave={() => setDialogIsOpen(false)}
            >
              <div className="h-full w-full">
                {(dialogIsOpen || !shouldFreezeContents) && children(onClose)}
              </div>
            </Transition.Child>
          </div>
        </div>
      </Dialog>
    </Transition.Root>
  );
};
