import { useEffect, useState } from 'react';

import { useFormContext } from '@/externals/react-hook-form';
import { PillTextarea, type PillTextareaProps } from './PillTextarea';
import { type Delimiter } from './types';

type FieldPillTextareaProps = Omit<PillTextareaProps, 'value'> & {
  delimiter?: Delimiter;
  defaultValue: string;
};

export const FieldPillTextarea = ({
  name,
  defaultValue = '',
  delimiter,
  testId = 'field-pill-textarea',
  trackingId = 'field-pill-textarea',
  ...props
}: FieldPillTextareaProps) => {
  const formMethods = useFormContext();
  const [fullValue, setFullValue] = useState(defaultValue);

  useEffect(() => {
    formMethods.register(name, {
      setValueAs: () => fullValue,
      validate: () => !!fullValue,
    });
  }, [formMethods, name, fullValue, delimiter]);

  useEffect(() => {
    formMethods.setValue(name, fullValue);
  }, [formMethods, fullValue, name]);

  return (
    <PillTextarea
      {...props}
      value={fullValue}
      name={name}
      onChange={setFullValue}
      testId={testId}
      trackingId={trackingId}
    />
  );
};
