import cx from 'classnames';

import { Icon } from '../Icon';
import { getIconProps } from '../Icon/helpers';
import { isIconProps } from '../Icon/helpers.internal';
import { StatusIconVariant } from '../Icon/types';
import type { Ryecon } from '../ryecons';
import { Sizes } from '../types';

export type BadgeType =
  | 'default'
  | 'success'
  | 'error'
  | 'warning'
  | 'info'
  | 'info-alt'
  | 'teal'
  | 'green'
  | 'red'
  | 'yellow'
  | 'blue'
  | 'purple'
  | 'orange'
  | 'brand'
  | 'brand-alt';

export type BadgeProps = {
  /** The badge text */
  text: string;

  /** Extra screenreader context for badge text; useful if the badge text is ambiguous (e.g., just a number) or the badge visually communicates state */
  textDescription?: string;

  /** The badge type */
  type?: BadgeType;

  ryecon?: Ryecon;

  /** The badge size */
  size?: 'xxs' | 'xs' | 'sm' | 'lg' | 'xl';

  /** A boolean representing whether the badge should be rounded */
  isRounded?: boolean;

  /** A badge id. If provided, will be passed to onRemove handler */
  id?: number;

  /** A removal handler function */
  onRemove?(id: number | string): void;

  /** Classnames for badge element */
  className?: string;

  /** Classnames for the icon */
  iconClassName?: string;

  /** Status Icon Variant. Use for adding a status icon to the badge */
  statusIconVariant?: StatusIconVariant;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo tracking */
  trackingId?: string;
};

export const Badge: React.FC<BadgeProps> = ({
  id,
  ryecon,
  size = 'sm',
  isRounded,
  text,
  textDescription,
  onRemove,
  className,
  iconClassName,
  statusIconVariant,
  type = 'default',
  testId = 'badge',
  trackingId = 'badge',
}): React.ReactElement => {
  const classNames = cx(
    'text-fgMain inline-flex items-center no-underline',
    {
      'font-label': size === 'xxs' || size === 'xs' || size === 'sm',
      'font-label-lg': size === 'lg' || size === 'xl',
      'rounded-md': !isRounded,
      'rounded-full': isRounded,
      'py-0': size === 'xxs',
      'py-0.5': size === 'xs',
      'py-1': size === 'sm',
      'py-1.5': size === 'lg',
      'py-2': size === 'xl',
      'px-1.5': !onRemove && !isRounded,
      'px-2': !onRemove && isRounded,
      'pl-2 pr-1': !!onRemove && isRounded,
      'pl-1.5 pr-1': !!onRemove && !isRounded,
      'bg-bgBadgeNeutralMuted': type === 'default',
      'bg-bgBadgeEmeraldMuted': type === 'success' || type === 'green',
      'bg-bgBadgeRedMuted': type === 'error' || type === 'red',
      'bg-bgBadgeAmberMuted': type === 'warning' || type === 'yellow',
      'bg-bgBadgeSkyBlueMuted': type === 'info' || type === 'blue',
      'bg-bgBadgeIndigoMuted':
        type === 'info-alt' || type === 'purple' || type === 'brand',
      'bg-bgBadgeTealMuted': type === 'teal',
      'bg-bgBadgeOrangeMuted': type === 'orange' || type === 'brand-alt',
    },
    className,
  );

  const baseIconProps = {
    className: cx('text-fgMain mr-1.5', iconClassName),
    size: size === 'xl' ? Sizes.md : Sizes.sm,
    testId: `${testId}-icon`,
  };
  const iconProps = getIconProps(baseIconProps, {
    statusIconVariant,
    ryecon,
  });

  return (
    <span className={classNames} data-testid={testId} data-trackingid={trackingId}>
      {isIconProps(iconProps) && <Icon {...iconProps} />}
      {text}
      {textDescription && <span className="sr-only"> {textDescription}</span>}
      {onRemove && (
        <button
          type="button"
          className={cx(
            'text-fgAlt hover:text-fgAltHover active:text-fgAltActive ml-0.5 inline-flex h-4 w-4 flex-shrink-0 items-center justify-center rounded-sm focus:outline-none',
            {
              'hover:bg-bgNeutralMuted': type === 'default',
              'hover:bg-bgSuccessMuted': type === 'success',
              'hover:bg-bgDangerMuted': type === 'error',
              'hover:bg-bgWarningMuted': type === 'warning',
              'hover:bg-bgInfoMuted': type === 'info',
              'hover:bg-bgInfoAltMuted': type === 'info-alt',
              'hover:bg-bgBrandMuted': type === 'teal',
            },
          )}
          data-testid={`${testId}-remove-button`}
          onClick={() => onRemove(id || text)}
        >
          <span className="sr-only">Remove {text} option</span>
          <svg className="h-2 w-2" stroke="currentColor" fill="none" viewBox="0 0 8 8">
            <path strokeLinecap="round" strokeWidth="1.5" d="M1 1l6 6m0-6L1 7" />
          </svg>
        </button>
      )}
    </span>
  );
};

export const StatusIconCircleClassName = 'text-[0.4rem]';
