import { useCallback } from 'react';

import { DropdownOption } from '../DropdownOptions/DropdownOptions';
import { Dropdown } from '../forms';

interface PaginationRowsPerPageSelectorProps {
  /**
   * onChange handler for changing number of rows displayed per page.
   *
   * @param rows number of rows to update rowsPerPage to
   * @returns void
   */
  onChange: (rows: number) => void;

  /**
   * Current value
   */
  rowsPerPage: number;
}

const OPTIONS = [10, 25, 50, 100];
const optionConfigs: DropdownOption[] = OPTIONS.map((option) => ({
  label: `${option}`,
  value: option,
}));

const PaginationRowsPerPageSelector = ({
  onChange,
  rowsPerPage,
}: PaginationRowsPerPageSelectorProps) => {
  const hanelChange = useCallback(
    (option: DropdownOption) => {
      onChange(option.value as number);
    },
    [onChange],
  );

  return (
    <div className="h-full w-auto" data-testid="rows-per-page-wrapper">
      <Dropdown
        isEdit
        name="rowsPerPage"
        size="sm"
        defaultValue={{
          label: (
            <span>
              Results per page{' '}
              <span className="ml-[4px] font-medium">{rowsPerPage}</span>
            </span>
          ),
          value: rowsPerPage,
        }}
        onChange={hanelChange}
        options={optionConfigs}
        testId="rows-per-page-value"
      />
    </div>
  );
};

export default PaginationRowsPerPageSelector;
