import cx from 'classnames';

import { IconProps, IconSizeType, RyeconIconProps, StatusIconProps } from './types';

export const getSizeClasses = (size: IconSizeType) => {
  return {
    'ryecon-xs': size === 'xs',
    'ryecon-sm': size === 'sm',
    'ryecon-md': size === 'md',
    'ryecon-lg': size === 'lg',
    'ryecon-xl': size === 'xl',
    'ryecon-2xl': size === '2xl',
    'ryecon-3xl': size === '3xl',
    'ryecon-4xl': size === '4xl',
    // Custom size used for icons in the nav bar
    'ryecon-nav': size === 'nav',
  };
};

export const getWrapperClasses = (size: IconSizeType, className?: string) => {
  const sizeClasses = getSizeClasses(size);
  return cx(
    className,
    'icon-wrapper',
    'leading-none',
    'inline-flex',
    'items-center',
    'justify-center',
    sizeClasses,
  );
};

export const getBaseIconClasses = (iconColor?: string, animate?: string) => {
  return cx('block', '!h-auto', 'max-h-full', '!w-full', {
    [`text-${iconColor}`]: Boolean(iconColor),
    [`animate-${animate}`]: Boolean(animate),
  });
};

export const isStatusIconProps = (props: unknown): props is StatusIconProps =>
  typeof (props as StatusIconProps).statusIconVariant === 'string';

export const isRyeconIconProps = (props: unknown): props is RyeconIconProps =>
  typeof (props as RyeconIconProps).ryecon === 'function';

export const isIconProps = (props: IconProps): props is IconProps =>
  isStatusIconProps(props) || isRyeconIconProps(props);
