import { useCallback, useMemo, useState } from 'react';
import {
  autoUpdate,
  flip,
  hide,
  type OpenChangeReason,
  safePolygon,
  useClick,
  useDismiss,
  useFloating,
  useHover,
  useInteractions,
  useRole,
} from '@floating-ui/react';

import type { UsePopoverArgs, UsePopoverReturn } from './types';

export const usePopover = ({
  testId = 'popover',
  trackingId = 'popover',
  isInitialOpen = false,
  placement = 'top-start',
  shouldShowOnHover = false,
  offset,
  zIndex = 10,
  labelledBy,
  describedBy,
  isOpen: controlledIsOpen,
  onOpenChange: controlledSetIsOpen,
  isDismissable,
  outsidePress = true,
  autoUpdateOptions = {},
}: UsePopoverArgs): UsePopoverReturn => {
  const [uncontrolledIsOpen, setUncontrolledIsOpen] = useState(isInitialOpen);
  const [openChangeReason, setOpenChangeReason] = useState<OpenChangeReason | null>(
    null,
  );
  const isControlled = controlledIsOpen !== undefined;
  const canDismiss = isDismissable ?? !isControlled;

  const open = isControlled ? controlledIsOpen : uncontrolledIsOpen;
  const setOpen = controlledSetIsOpen ?? setUncontrolledIsOpen;

  /** still inform parent of state changes, even if uncontrolled */
  const handleChange = useCallback(
    (nextIsOpen: boolean) => {
      // call both in this case
      if (!isControlled && controlledSetIsOpen) {
        setUncontrolledIsOpen(nextIsOpen);
        controlledSetIsOpen(nextIsOpen);
        return;
      }
      // call either one
      setOpen(nextIsOpen);
    },
    [controlledSetIsOpen, isControlled, setOpen],
  );

  const handleOpenChange = useCallback(
    (nextIsOpen: boolean, _event: Event, reason: OpenChangeReason) => {
      handleChange(nextIsOpen);
      setOpenChangeReason(reason);
    },
    [handleChange],
  );

  const data = useFloating({
    placement,
    open,
    onOpenChange: handleOpenChange,
    whileElementsMounted(referenceEl, floatingEl, update) {
      const cleanup = autoUpdate(referenceEl, floatingEl, update, {
        ...autoUpdateOptions,
      });
      return cleanup;
    },
    middleware: [
      hide({
        strategy: 'referenceHidden',
      }),
      hide({
        strategy: 'escaped',
      }),
      flip({
        crossAxis: placement.includes('-'),
        fallbackAxisSideDirection: 'end',
      }),
    ],
  });

  const context = data.context;

  const click = useClick(context, {
    enabled: !isControlled,
  });

  // dismisses on escape press
  const dismiss = useDismiss(context, {
    enabled: canDismiss,
    outsidePress,
  });
  // add accessible props
  const role = useRole(context, { role: 'dialog' });
  // show on hover
  const hover = useHover(context, {
    enabled: !isControlled && shouldShowOnHover,
    handleClose: safePolygon(),
    mouseOnly: true,
    delay: {
      open: 100,
      close: 300,
    },
  });

  const interactions = useInteractions([click, dismiss, role, hover]);

  return useMemo(
    () => ({
      isOpen: open,
      setIsOpen: handleChange,
      labelledBy,
      describedBy,
      testId,
      trackingId,
      offset,
      zIndex,
      shouldShowOnHover,
      openChangeReason,
      outsidePress,
      ...interactions,
      ...data,
    }),
    [
      open,
      handleChange,
      labelledBy,
      describedBy,
      testId,
      trackingId,
      interactions,
      openChangeReason,
      data,
      offset,
      zIndex,
      shouldShowOnHover,
      outsidePress,
    ],
  );
};
