import { useEffect, useState } from 'react';
import React from 'react';
import cx from 'classnames';

import { Dialog, Transition } from '@/externals/headlessui';
import { useInertContext } from '../../context/InertContextProvider';

export interface ModalAnimationContainerProps {
  /** Boolean representing whether the modal is open */
  isOpen: boolean;

  /** An onclose handler function, fired immediately after the user requests to close the modal */
  onClose?: () => void;

  /** Content to display in the modal */
  children: (onClose: () => void) => React.ReactNode;

  /** If you set this to false, you can allow hidden children to render even when the modal is closed */
  shouldFreezeContents?: boolean;

  /** Force enable dark mode. Useful since this element is portaled */
  forceDark?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** Whether the modal should take up full height and width */
  isFullscreen?: boolean;
}

export const ModalAnimationContainer: React.FC<ModalAnimationContainerProps> = ({
  children,
  isOpen,
  forceDark,
  shouldFreezeContents = true,
  onClose = () => {},
  testId = 'modal-animation-container',
  trackingId = 'modal-animation-container',
}) => {
  // Providing a fallback in case provider is not set in consuming app
  const { setInert } = useInertContext() || { setInert: () => {} };
  const [dialogIsOpen, setDialogIsOpen] = useState(isOpen);
  const shouldRenderChildren = isOpen || dialogIsOpen || !shouldFreezeContents;

  useEffect(() => {
    if (isOpen) {
      setDialogIsOpen(true);
    }
    setInert(isOpen);

    return () => {
      setInert(false);
    };
  }, [isOpen, setDialogIsOpen, setInert]);

  return (
    <Transition.Root show={isOpen} as={React.Fragment}>
      <Dialog
        as="div"
        className={cx('fixed inset-0 z-30 overflow-y-auto', { dark: forceDark })}
        onClose={onClose}
        open={dialogIsOpen}
        data-testid={testId}
        data-trackingid={trackingId}
      >
        <div className="flex min-h-screen items-center justify-center p-0 px-4 text-center">
          <Transition.Child
            as={React.Fragment}
            enter="ease-out duration-300"
            enterFrom="opacity-0"
            enterTo="opacity-100"
            leave="ease-in duration-200"
            leaveFrom="opacity-100"
            leaveTo="opacity-0"
            afterLeave={() => setDialogIsOpen(false)}
          >
            <Dialog.Overlay className="bg-bgOverlayTinted fixed inset-0 transition-opacity" />
          </Transition.Child>

          <span className="hidden h-screen align-middle" aria-hidden="true">
            &#8203;
          </span>

          <Transition.Child
            as={React.Fragment}
            enter="ease-out duration-300"
            enterFrom="opacity-0 translate-y-4 translate-y-0 scale-95"
            enterTo="opacity-100 translate-y-0 scale-100"
            leave="ease-in duration-200"
            leaveFrom="opacity-100 translate-y-0 scale-100"
            leaveTo="opacity-0 translate-y-4 translate-y-0 scale-95"
          >
            <div className="h-full w-full">
              {shouldRenderChildren && children(onClose)}
            </div>
          </Transition.Child>
        </div>
      </Dialog>
    </Transition.Root>
  );
};
