import { PropsWithChildren } from 'react';
import cx from 'classnames';

import './customIcon.css';

export interface CustomIconProps {
  ariaLabel?: string;
  className?: string;

  /** For now we have two sizes, this may change */
  size?: 'sm' | 'lg';
}

export const CustomIcon: React.FC<PropsWithChildren<CustomIconProps>> = ({
  ariaLabel,
  children,
  className,
  size = 'sm',
}) => {
  const classNames = cx('dbt-icon', className);

  return (
    <svg
      aria-label={ariaLabel}
      className={classNames}
      height={size === 'sm' ? 16 : 24}
      role={ariaLabel ? 'img' : 'presentation'}
      viewBox="0 0 24 24"
      width={size === 'sm' ? 16 : 24}
      xmlns="http://www.w3.org/2000/svg"
    >
      {children}
    </svg>
  );
};
