import React, { useEffect, useState } from 'react';
import cx from 'classnames';

import { Listbox } from '@/externals/headlessui';
import type { TriggerLocation } from '../../hooks';
import { Badge } from '../Badge';
import { Button, type ButtonProps } from '../Button';
import {
  type DropdownOption,
  type DropdownOptionGroup,
  DropdownOptions,
  getFlattenedDropdownOptions,
} from '../DropdownOptions';
import { Icon } from '../Icon';
import { RyeconCaretDown } from '../ryecons';
import { Sizes } from '../types';

export interface DropdownButtonProps {
  /** The dropdown name. Displayed to the left of the selected option */
  name?: string;

  /** The default selected option */
  defaultOption?: DropdownOption;

  /** An array of options for the select */
  options: (DropdownOption | DropdownOptionGroup)[];

  /** OnChange handler */
  onChange(selected: DropdownOption): void;

  /** Placement of the menu, auto will let the component self-determine position */
  menuPlacement?: 'auto' | TriggerLocation;

  /** Boolean representing whether this dropdown is disabled */
  isDisabled?: boolean;

  /** Custom classnames for the DropdownButton */
  className?: string;

  /** Button Size */
  size?: Sizes;

  /** Custom classnames for the dropdown list wrapper */
  listClassName?: string;

  /** Button Variant for the inner button */
  buttonVariant?: ButtonProps['variant'];

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export const DropdownButton: React.FC<DropdownButtonProps> = ({
  name,
  defaultOption,
  options,
  onChange,
  isDisabled,
  className,
  size = Sizes.md,
  listClassName,
  buttonVariant = 'default',
  menuPlacement = 'auto',
  testId = 'dropdown-button',
  trackingId = 'dropdown-button',
}): React.ReactElement => {
  const [selected, setSelected] = useState<DropdownOption>(
    defaultOption || getFlattenedDropdownOptions(options)[0],
  );

  useEffect(() => {
    if (defaultOption) {
      setSelected(defaultOption);
    }
  }, [defaultOption]);

  return (
    <Listbox
      as="div"
      value={selected}
      onChange={(value: DropdownOption) => {
        if (onChange && value) {
          onChange(value);
        }
        setSelected(value);
      }}
      disabled={isDisabled}
      className="relative"
    >
      <DropdownOptions
        options={options}
        testId={`${testId}-options`}
        trackingId={`${trackingId}-options`}
        placement={menuPlacement}
        className={cx('left-0', listClassName)}
      />
      <Listbox.Button
        as={Button}
        className={cx('flex items-center', className)}
        type="secondary"
        size={size}
        variant={buttonVariant}
        buttonType="button"
        testId={testId}
        isDisabled={isDisabled}
      >
        {name && (
          <div
            className={cx('font-body-sm font-normal', {
              'text-fgAlt': !isDisabled,
              'text-fgDisabled': isDisabled,
            })}
          >
            {name}
          </div>
        )}
        <span className="font-label truncate">{selected?.label}</span>
        {!!selected?.badge && (
          <span>
            <Badge {...selected.badge} />
          </span>
        )}
        <Icon ryecon={RyeconCaretDown} size="xs" />
      </Listbox.Button>
    </Listbox>
  );
};
