import { useDrag, useDrop } from 'react-dnd';

import { DROP_ITEM_TYPE } from './constants';
import { NodeDataProps } from './types';

const emptyFn = () => {};

type DragItem = {
  index: number;
  id: string;
  name: string;
  type: string;
  relativePath: string | null;
  pathType: string;
  dropPath: string;
};

export const useFileItemDrag = (
  { relativePath, pathType, dropPath, name, parent }: NodeDataProps,
  {
    isReadOnly = false,
    onMoveFile = emptyFn,
    isRootDropPath,
  }: {
    isReadOnly?: boolean;
    onMoveFile?: (
      currentFilePath: string,
      newFilePath: string,
      filePath: 'file' | 'directory',
    ) => void;
    isRootDropPath: boolean;
  },
) => {
  const [{ isOver }, drop] = useDrop<DragItem, void, { isOver: boolean }>(
    {
      accept: DROP_ITEM_TYPE,
      collect(monitor) {
        return {
          isOver: monitor.isOver(),
        };
      },
      drop(item: DragItem, _monitor) {
        if (!item.relativePath || item.relativePath === dropPath) return;
        const newPath = isRootDropPath ? item.name : `${dropPath}/${item.name}`;
        const filePath = item.relativePath;

        if (filePath !== newPath) {
          onMoveFile(filePath, newPath, pathType);
        }
      },
    },
    [relativePath],
  );

  const [{ isDragging }, drag] = useDrag(() => {
    const item: Partial<DragItem> = { relativePath, name };
    return {
      type: DROP_ITEM_TYPE,
      item, // passed to drop zone
      collect: (monitor) => {
        return {
          handlerId: monitor.getHandlerId(),
          isDragging: monitor.isDragging(),
        };
      },
      canDrag: () => {
        // Cannot drag root directory
        return !isReadOnly && parent !== 'root';
      },
    };
  }, [relativePath]);

  return {
    drop,
    drag,
    isOver,
    isDragging,
  };
};
