import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
} from 'react';

import { getInitialTheme, getThemeClass } from './theme-utils';

export type Theme = 'light' | 'dark' | 'system';
export type ThemeClass = 'light' | 'dark';
const supportedThemes: Theme[] = ['light', 'dark', 'system'];

export const DBT_THEME_USER_PREF_KEY = 'dbt-theme-user-preference';

export type TThemeContext = {
  /**
   * when undefined, the theme will be computed based on users/system preference
   */
  theme: Theme | undefined;
  supportsSystemPreference: boolean;
  isEnabled: boolean;
  setTheme: (theme: Theme) => void;
  shouldStoreLocally: boolean;
  themeClass: ThemeClass;
};

const ThemeContext = createContext<TThemeContext>({
  theme: undefined,
  supportsSystemPreference: false,
  isEnabled: false,
  setTheme: () => {},
  shouldStoreLocally: false,
  themeClass: 'light',
});

export type ThemeProviderProps = {
  children: React.ReactNode;
  /**
   * used to gate via a feature flag and allow for controlled rollout
   */
  isEnabled: boolean;
  /**
   * theme to use when the component is mounted.
   * this should be set by the hosting application e.g. when pulled from the server
   */
  theme?: Theme;
  /**
   * callback function to be called when the theme is updated
   */
  onUpdate?: (theme: Theme) => void;
  /**
   * if true, the theme will be set to the system preference
   * this should only be used once we have gone GA with dark mode support
   */
  supportsSystemPreference?: boolean;
  /**
   * fallback to using/setting the theme in localStorage
   * mainly used for when the user-preferences endpoint is not available or errors
   * e.g. running localhost against a non-prod environment
   */
  shouldStoreLocally?: boolean;
};

export const ThemeProvider = ({
  children,
  isEnabled,
  theme: appTheme,
  onUpdate,
  supportsSystemPreference = false,
  shouldStoreLocally = false,
}: ThemeProviderProps) => {
  const { initialTheme, mode } = getInitialTheme(
    appTheme,
    supportsSystemPreference,
    shouldStoreLocally,
  );
  const isControlled = appTheme !== undefined;
  const [_theme, _setTheme] = useState<Theme | undefined>(
    isControlled ? appTheme : isEnabled ? initialTheme : undefined,
  );

  const setTheme = useCallback(
    (nextTheme: Theme) => {
      if (!isEnabled) {
        return;
      }
      _setTheme(nextTheme);
      onUpdate?.(nextTheme);
    },
    [isEnabled, onUpdate],
  );

  // when controlled, always use appTheme as passed in
  const derivedTheme = isControlled ? appTheme : _theme;
  const themeClass = derivedTheme ? getThemeClass(derivedTheme) : 'light';

  useEffect(() => {
    if (!isEnabled || !derivedTheme) {
      return;
    }
    // set class as derived class (i.e. not `system`)
    // update the body to only have the theme class
    supportedThemes.forEach((supportedTheme) => {
      if (supportedTheme !== themeClass) {
        document.body.classList.remove(supportedTheme);
      } else {
        document.body.classList.add(supportedTheme);
      }
    });
    if (shouldStoreLocally) {
      localStorage.setItem(DBT_THEME_USER_PREF_KEY, derivedTheme);
    }
    document.body.setAttribute('data-theme', derivedTheme);
    document.body.setAttribute('data-theme-determination', mode);

    let metaTag = document.querySelector<HTMLMetaElement>('meta[name="color-scheme"]');
    if (!metaTag) {
      // Create the meta tag if it doesn't exist
      metaTag = document.createElement('meta');
      metaTag.name = 'color-scheme';
      document.head.appendChild(metaTag);
    }
    metaTag.content = themeClass;
  }, [derivedTheme, mode, isEnabled, shouldStoreLocally, isControlled, themeClass]);

  const value = useMemo(
    () => ({
      theme: derivedTheme,
      setTheme,
      supportsSystemPreference,
      isEnabled,
      shouldStoreLocally,
      themeClass,
    }),
    [
      derivedTheme,
      setTheme,
      supportsSystemPreference,
      isEnabled,
      shouldStoreLocally,
      themeClass,
    ],
  );

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
};

export const useTheme = (): TThemeContext => {
  const context = useContext(ThemeContext);

  if (context === undefined) {
    throw new Error('useTheme must be used within a <ThemeProvider />');
  }

  return context;
};
