import {
  createContext,
  createRef,
  Dispatch,
  RefObject,
  SetStateAction,
  useContext,
  useEffect,
  useState,
} from 'react';

/**
 * Provider for setting the root node as inert for when it is not interactable.
 * Esp helpful for assistive technology.
 */

interface InertContextProps {
  ref: RefObject<HTMLDivElement | null>;
  setInert: Dispatch<SetStateAction<boolean>>;
}

const ref = createRef<HTMLDivElement>();
const InertContext = createContext<InertContextProps | undefined>(undefined);

export interface InertContextProviderProps {
  children: React.ReactNode;
}

export const InertContextProvider = ({ children }: InertContextProviderProps) => {
  const [inert, setInert] = useState(false);

  useEffect(() => {
    if (inert) {
      ref.current?.setAttribute('inert', '');
    } else {
      ref.current?.removeAttribute('inert');
    }
  }, [inert]);

  return (
    <InertContext.Provider value={{ ref, setInert }}>{children}</InertContext.Provider>
  );
};

export const useInertContext = () => useContext(InertContext);
