import { Ryecon } from '../ryecons/types';
import {
  IconBaseProps,
  IconProps,
  RyeconIconProps,
  StatusIconProps,
  StatusIconVariant,
} from './types';

type OptionalIconProps = {
  statusIconVariant?: StatusIconVariant;
  ryecon?: Ryecon;
};
/**
 * used for type narrowing to the different icon types
 * input all optional properties and get back the correct props with correct type
 */
export const getIconProps = (
  baseProps: IconBaseProps,
  { statusIconVariant, ryecon }: OptionalIconProps,
) => {
  if (statusIconVariant) {
    return { ...baseProps, statusIconVariant } as StatusIconProps;
  }
  if (ryecon) {
    return { ...baseProps, ryecon } as RyeconIconProps;
  }
  return baseProps as IconProps; // no narrowing available
};
