import React, { useContext, useMemo, useState } from 'react';
import ReactDOM from 'react-dom';
import { Portal as HeadlessUIPortal } from '@headlessui/react';

export interface PortalNodeContext {
  /** @deprecated use `node` instead */
  ref: React.MutableRefObject<HTMLElement | null> | null;
  /** The html element that the portal is mounted to */
  node: HTMLElement | null;
}

const PortalNodeContextContext = React.createContext<PortalNodeContext>({
  ref: null,
  node: null,
});

export interface PortalNodeContextProviderProps {
  children: React.ReactNode;
  /** className applied to the wrapping container (e.g. used for darkmode support) */
  className?: string;
  /**
   * The element to mount the container to, using a React Portal (defaults to `document.body`)
   * @deprecated
   */
  rootContainer?: Element;
}

export function PortalNodeContextProvider({
  children,
  className,
}: PortalNodeContextProviderProps) {
  const [node, setNode] = useState<HTMLDivElement | null>(null);
  // `ref` maintained for backwards compatibility but is a bad name so will be replaced with `node` in the future
  const value = useMemo(() => ({ ref: { current: node }, node }), [node]);

  return (
    <PortalNodeContextContext.Provider value={value}>
      {children}
      <HeadlessUIPortal>
        <div ref={setNode} className={className} data-testid="portal-node-root" />
      </HeadlessUIPortal>
    </PortalNodeContextContext.Provider>
  );
}

export const usePortalNodeContext = () => useContext(PortalNodeContextContext);

export interface PortalProps {
  children: React.ReactNode;
  enable?: boolean;
}

export const Portal = ({ children, enable = true }: PortalProps) => {
  const { node } = usePortalNodeContext();

  if (!node || !enable) return <>{children}</>;
  return ReactDOM.createPortal(children, node);
};
