import { PropsWithChildren } from 'react';
import classNames from 'classnames';
import { twMerge } from 'tailwind-merge';

export interface PingProps {
  /**
   * The position of the ping
   */
  position?: 'left' | 'right';
  /**
   * Whether to enable the ping
   */
  enable?: boolean;
  /**
   * Whether the ping should be animated
   */
  animated?: boolean;
  /**
   * The size of the ping (t-shirt sizes)
   */
  size?: 'xs' | 'sm' | 'md' | 'lg' | 'xl';
  /**
   * The class name to apply to the wrapper container
   */
  className?: string;
  /**
   * The tooltip to display when the user hovers over the ping
   */
  tooltip: string;
  testId?: string;
}

const sizeClassMap: Record<string, string> = {
  xs: 'h-1 w-1',
  sm: 'h-2 w-2',
  md: 'h-3 w-3',
  lg: 'h-4 w-4',
  xl: 'h-5 w-5',
};

export const Ping: React.FC<PropsWithChildren<PingProps>> = ({
  position = 'right',
  className,
  children,
  tooltip,
  testId = 'ping',
  enable = true,
  animated = true,
  size = 'sm',
}) => {
  const sizeClass = sizeClassMap[size] || sizeClassMap.sm;
  return (
    <div className={twMerge('relative inline-flex', className)}>
      {enable && (
        <div
          className={classNames('absolute z-10 size-0', {
            'right-0': position === 'right',
            'left-0': position === 'left',
          })}
        >
          <div
            aria-label={tooltip}
            className={twMerge(sizeClass, '-translate-x-1/2 -translate-y-1/2')}
            data-testid={testId}
            role="img"
            title={tooltip}
          >
            {animated && (
              <div className="bg-fgVizOrange absolute inline-flex h-full w-full rounded-full motion-safe:animate-ping" />
            )}
            <div className="bg-fgVizOrange ring-bgMain absolute inline-flex h-full w-full rounded-full ring-2" />
          </div>
        </div>
      )}
      {children}
    </div>
  );
};
