import cx from 'classnames';

import { DropdownButton, type DropdownButtonProps } from '../../DropdownButton';
import { DEFAULT_BUTTON_GROUP_CHILD_CLASSES } from '../ButtonGroup';

export interface ButtonGroupDropdownProps
  extends Omit<DropdownButtonProps, 'onChange'> {
  onChange?: DropdownButtonProps['onChange'];
}

export const ButtonGroupDropdown: React.FC<ButtonGroupDropdownProps> = ({
  testId = 'button-group-dropdown',
  trackingId = 'button-group-dropdown',
  ...props
}): React.ReactElement => {
  const onChange = props.onChange ?? (() => null);
  return (
    <DropdownButton
      {...props}
      onChange={onChange}
      className={cx(DEFAULT_BUTTON_GROUP_CHILD_CLASSES, props.className)}
      testId={testId}
      trackingId={trackingId}
      buttonVariant="group"
    />
  );
};
