import { Placement } from '@floating-ui/react';
import { RadioGroup } from '@headlessui/react';
import cx from 'classnames';

import { BaseInputProps } from '../../globalTypes';
import { Field } from '../forms';
import { Tooltip } from '../Tooltip';

export interface RadioCardOption {
  /** A unique id for the radio card */
  id: string;

  /** Label for the radio card */
  label: string;

  /** Secondary label for the radio card */
  secondaryLabel?: string;

  /** An icon or custom element (img, etc) for the radio card */
  image?: React.ReactNode;

  /** Custom classes for the item */
  className?: string;

  /** Whether to disable the option */
  isDisabled?: boolean;

  /** Tooltip content to display when hovering over the entire radio card option */
  tooltip?: React.ReactNode;

  /**
   * Controls where a tooltip is placed in relation to the target.
   * If not provided, tooltip will default to `autoPlacement`
   */
  tooltipPlacement?: Placement;

  /** Use a portal to render the tooltip */
  tooltipPortal?: boolean;
}

export interface RadioCardGroupProps {
  /** The id of the selected card. Can be undefined to represent no selection */
  selectedValue: string | undefined;

  /** An array of cards to display */
  options: RadioCardOption[];

  /** An onchange callback handler */
  onChange: (value: string) => void;

  /** Whether to disable the options */
  isDisabled?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;

  /** Custom classes for the group */
  className?: string;

  /** Label for the radio card button group */
  label?: React.ReactNode;

  /** Description for the radio card button group */
  description?: string;

  /** A link to a help page. Will be placed on a help icon to the right of the label. Only present if label exists. Do not use with onHelpClick! */
  helpLink?: BaseInputProps['helpLink'];

  /** A click handler for the HelpIcon. Will be placed on a help icon to the right of the label. Only present if label exists. Do not use with helpLink! */
  onHelpClick?: BaseInputProps['onHelpClick'];
}

export const RadioCardGroup: React.FC<RadioCardGroupProps> = ({
  options,
  onChange,
  selectedValue,
  className,
  isDisabled,
  label,
  description,
  helpLink,
  onHelpClick,
  testId = 'radio-card',
  trackingId = 'radio-card',
}) => {
  return (
    <Field
      label={label}
      helpLink={helpLink}
      onHelpClick={onHelpClick}
      isDisabled={isDisabled}
      description={description}
      testId={`${testId}-field`}
      trackingId={`${trackingId}-field`}
    >
      <RadioGroup
        value={selectedValue}
        onChange={onChange}
        data-testid={`${testId}-group`}
        data-trackingid={`${trackingId}-group`}
        className={className}
      >
        <div className={cx('flex w-full flex-wrap gap-2', className)}>
          {options.map((option) => (
            <RadioCard
              {...option}
              key={option.id}
              testId={testId}
              trackingId={trackingId}
              // only override the options isDisabled if it is explicitly set
              {...(isDisabled !== undefined && { isDisabled })}
            />
          ))}
        </div>
      </RadioGroup>
    </Field>
  );
};

interface RadioCardProps extends RadioCardOption {
  testId: string;
  trackingId: string;
}

const RadioCard: React.FC<RadioCardProps> = ({
  id,
  label,
  secondaryLabel,
  image,
  className,
  isDisabled,
  tooltip,
  testId,
  trackingId,
  tooltipPlacement,
  tooltipPortal,
}) => {
  const radioCard = (
    <RadioGroup.Option
      key={id}
      value={id}
      disabled={isDisabled}
      className={({ checked }) =>
        cx(className, 'relative flex items-center rounded-md border px-3 py-[7px]', {
          'ring-focusBrand ring-offset-bgMain border-borderMain ring-2 ring-offset-2':
            checked,
          'hover:bg-bgMainHover border-borderMain': !checked && !isDisabled,
          'bg-bgMain shadow-rest cursor-pointer': !isDisabled,
          'border-borderDisabled bg-bgDisabled cursor-not-allowed': isDisabled,
        })
      }
      data-testid={`${testId}-item-${id}`}
      data-trackingid={`${trackingId}-item-${id}`}
    >
      <div className="flex items-center">
        {!!image && <div className="mr-2 flex items-center">{image}</div>}
        <RadioGroup.Label as="p" className="font-label text-fgMain block text-center ">
          {label}
        </RadioGroup.Label>
        {Boolean(secondaryLabel) && (
          <RadioGroup.Label
            as="p"
            className="text-fgDecorative font-body-sm ml-2 block text-center"
          >
            {secondaryLabel}
          </RadioGroup.Label>
        )}
      </div>
    </RadioGroup.Option>
  );

  if (tooltip) {
    const placementProps = tooltipPlacement
      ? { placement: tooltipPlacement }
      : { autoPlacement: true };
    return (
      <Tooltip
        content={tooltip}
        childrenAreInteractive
        portal={tooltipPortal}
        {...placementProps}
      >
        {radioCard}
      </Tooltip>
    );
  }

  return radioCard;
};
