import { DEFAULT_ITEM_HEIGHT, TREE_ROOT_ID } from './constants';
import { InternalFileTreeItemType, NodeData } from './types';

const getNodeData = (
  treeSize: number,
  node: InternalFileTreeItemType,
  openDirectories: string[],
  getDropPath: (node: InternalFileTreeItemType) => string,
  itemHeights?: Record<string, number>,
): NodeData => {
  const { id, parent, data } = node;
  const isOpen = openDirectories.includes(id);
  const isTrueRoot = parent === TREE_ROOT_ID && data.relativePath === null;
  const isRoot = parent === TREE_ROOT_ID;
  return {
    data: {
      defaultHeight:
        (isRoot || isTrueRoot ? itemHeights?.root : itemHeights?.[data.pathType]) ||
        DEFAULT_ITEM_HEIGHT,
      id: id.toString(), // mandatory
      isOpenByDefault: isTrueRoot || isOpen, // mandatory
      parent,
      dropPath: getDropPath(node),
      ...data,
    },
  };
};

// The `treeWalker` function runs only on tree re-build which is performed
// whenever the `treeWalker` prop is changed.
// export function* treeWalker(treeNodes: FileTree[]): Generator<any, any, any> {
export function* treeWalker(
  treeNodes: InternalFileTreeItemType[],
  openDirectories: string[],
  getDropPath: (node: InternalFileTreeItemType) => string,
  itemHeights?: Record<string, number>,
): Generator<NodeData | undefined, any, NodeData> {
  // Step [1]: Define the root node of our tree. There can be one or
  // multiple nodes.
  const rootNodes = treeNodes.filter(
    (node: InternalFileTreeItemType) => node.parent === TREE_ROOT_ID,
  );

  for (let i = 0; i < rootNodes.length; i++) {
    yield getNodeData(
      treeNodes.length,
      treeNodes[i],
      openDirectories,
      getDropPath,
      itemHeights,
    );
  }

  while (true) {
    // Step [2]: Get the parent component back. It will be the object
    // the `getNodeData` function constructed, so you can read any data from it.
    const parent: NodeData = yield;
    const children = treeNodes.filter(
      (n: InternalFileTreeItemType) => parent.data.id === n.parent,
    );
    for (let i = 0; i < children?.length; i++) {
      // Step [3]: Yielding all the children of the provided component. Then we
      // will return for the step [2] with the first children.
      yield getNodeData(
        treeNodes.length,
        children[i],
        openDirectories,
        getDropPath,
        itemHeights,
      );
    }
  }
}
