import { Axis, Orient } from 'd3-axis-for-react';

import { useChartContext } from '../../ChartProvider/ChartProvider';
import { generateAxisTextFormatter } from '../../util';
import { LinearAxisScale } from '../../util/scales';
import {
  AxisProps,
  BASE_AXIS_PROPS,
  BaseAxis,
  getTickWidth,
  TickSpacing,
} from '../BaseAxis';
import { useNumTicks } from '../numTicks';

interface LinearAxisProps extends AxisProps {
  /**
   * Defaults to `normal` for linear axes.
   * More at {@link TickSpacing}
   */
  tickSpacing?: TickSpacing;
  enableTruncation?: boolean;
  /**
   * Allow numerical formatting to be compact
   * 1000 -> 1K
   * 1 500 000 -> 1.5M
   */
  isCompact?: boolean;
}

/** @deprecated */
export const LinearAxis: React.FC<LinearAxisProps> = ({
  axis,
  tickSpacing = 100,
  enableTruncation = true,
  testId = 'linear-axis',
  isCompact = false,
  ...props
}) => {
  const numSuggestedTicks = useNumTicks(axis, tickSpacing);
  const { chartMeta } = useChartContext() ?? {};
  const axisScale = chartMeta?.[`${axis}Scale`] as LinearAxisScale;

  const tickValues = axisScale.scale.ticks(numSuggestedTicks);
  const numTicks = tickValues.length;
  const tickWidth = getTickWidth(axis, chartMeta, numTicks);
  const numFormat = Intl.NumberFormat('en', { notation: 'compact' }).format;

  return (
    <BaseAxis testId={testId} {...props} axis={axis}>
      <Axis
        scale={axisScale.scale}
        orient={axis === 'x' ? Orient.bottom : Orient.left}
        tickValues={axisScale.scale.ticks(numTicks)}
        tickSizeInner={0}
        tickSizeOuter={0}
        tickTextProps={{
          ...BASE_AXIS_PROPS.labelTextProps,
          y: axis === 'y' ? 0 : 10,
        }}
        tickFormat={(data: string | number) => {
          if (isCompact && typeof data === 'number') {
            return numFormat(data);
          }
          return generateAxisTextFormatter(
            enableTruncation,
            tickWidth,
          )(data.toString ? data.toString() : (data as string));
        }}
        domainPathProps={{ className: 'hidden' }}
      />
    </BaseAxis>
  );
};
