import {
  type Ryecon,
  RyeconFreshnessError,
  RyeconFreshnessPassed,
  RyeconFreshnessStale,
  RyeconFreshnessUnknown,
  RyeconHealthCaution,
  RyeconHealthDegraded,
  RyeconHealthUnknown,
  RyeconHealthVerified,
  RyeconSpinner,
  RyeconStateAdded,
  RyeconStateModified,
  RyeconStateRemoved,
  RyeconStatusCanceled,
  RyeconStatusError,
  RyeconStatusInfo,
  RyeconStatusSkipped,
  RyeconStatusSuccess,
  RyeconStatusWaiting,
  RyeconStatusWarning,
} from '../../ryecons';
import { getBaseIconClasses, getWrapperClasses } from '../helpers.internal';
import { StatusIconProps, StatusIconVariant } from '../types';

const statusIconMap: Record<StatusIconVariant, { ryecon: Ryecon; animate?: string }> = {
  success: {
    ryecon: RyeconStatusSuccess,
  },
  warning: {
    ryecon: RyeconStatusWarning,
  },
  error: {
    ryecon: RyeconStatusError,
  },
  'in-progress': {
    ryecon: RyeconSpinner,
    animate: 'spin',
  },
  canceled: {
    ryecon: RyeconStatusCanceled,
  },
  skipped: {
    ryecon: RyeconStatusSkipped,
  },
  waiting: {
    ryecon: RyeconStatusWaiting,
    animate: 'pulse',
  },
  info: {
    ryecon: RyeconStatusInfo,
  },
  'state-added': {
    ryecon: RyeconStateAdded,
  },
  'state-modified': {
    ryecon: RyeconStateModified,
  },
  'state-removed': {
    ryecon: RyeconStateRemoved,
  },
  'health-verified': {
    ryecon: RyeconHealthVerified,
  },
  'health-caution': {
    ryecon: RyeconHealthCaution,
  },
  'health-degraded': {
    ryecon: RyeconHealthDegraded,
  },
  'health-unknown': {
    ryecon: RyeconHealthUnknown,
  },
  'freshness-passed': {
    ryecon: RyeconFreshnessPassed,
  },
  'freshness-stale': {
    ryecon: RyeconFreshnessStale,
  },
  'freshness-error': {
    ryecon: RyeconFreshnessError,
  },
  'freshness-unknown': {
    ryecon: RyeconFreshnessUnknown,
  },
};

export const StatusIcon = ({
  statusIconVariant,
  alt,
  className,
  testId,
  trackingId,
  iconColor,
  size = 'sm',
}: StatusIconProps) => {
  const { ryecon: RyeconComponent, animate } = statusIconMap[statusIconVariant];

  const baseIconClasses = getBaseIconClasses(iconColor, animate);
  const wrapperClasses = getWrapperClasses(size, className);

  const _alt = alt ?? statusIconVariant;

  // wrap our icons in a span for sizing, and keep a consistent line-height.

  return (
    <span
      className={wrapperClasses}
      data-testid={`status-icon-${testId ?? statusIconVariant}`}
      data-trackingid={`status-icon-${trackingId ?? statusIconVariant}`}
    >
      <RyeconComponent
        aria-hidden={undefined}
        aria-label={_alt}
        role="img"
        className={baseIconClasses}
      />
    </span>
  );
};
