import {
  NumberValue,
  ScaleBand,
  scaleBand,
  ScaleLinear,
  scaleLinear,
  scaleLog,
  ScaleLogarithmic,
  ScaleTime,
  scaleTime,
} from 'd3';

export type ScaleKind = 'time' | 'category' | 'linear' | 'log';
export type Scale<SType, KType> = { scale: SType; kind: KType };

export type TimeAxisScale = Scale<ScaleTime<Date | NumberValue, number>, 'time'>;
export type CategoryAxisScale = Scale<ScaleBand<string>, 'category'>;
export type LinearAxisScale = Scale<ScaleLinear<number, number>, 'linear'>;
export type LogAxisScale = Scale<ScaleLogarithmic<number, number>, 'log'>;

export type XAxisScales = TimeAxisScale | CategoryAxisScale;
export type YAxisScales = LinearAxisScale | LogAxisScale;

export type Scales = XAxisScales | YAxisScales;

export interface NumericScaleProps {
  min: number;
  max: number;
}

export interface TimeScaleProps {
  min: Date;
  max: Date;
}

export interface CategoryScaleProps {
  labels: string[];
}

/** @deprecated */
export const timeScale = ({ min, max }: TimeScaleProps): TimeAxisScale => ({
  scale: scaleTime().domain([min, max]),
  kind: 'time',
});

/** @deprecated */
export const categoryScale = ({ labels }: CategoryScaleProps): CategoryAxisScale => ({
  scale: scaleBand().domain(labels).paddingInner(0.4).paddingOuter(0.2),
  kind: 'category',
});

/** @deprecated */
export const linearScale = ({ min, max }: NumericScaleProps): LinearAxisScale => ({
  scale: scaleLinear().domain([min, max]),
  kind: 'linear',
});

/** @deprecated */
export const logScale = ({ min, max }: NumericScaleProps): LogAxisScale => ({
  scale: scaleLog().domain([min, max]),
  kind: 'log',
});
