import { Link, To } from 'react-router-dom';
import cx from 'classnames';

import { useSkeletonContext } from '../../../context/SkeletonProvider';
import { LoadingBlock } from '../../LoadingBlock/LoadingBlock';
import { DEFAULT_STATUS_BAR_CHILD_CLASSES } from '../StatusBar';

export interface StatusBarLinkTileProps {
  /** The text to display */
  text: string;

  /** A route to link to, a string or a more complex react-router path */
  linkTo: To;

  /** A label for the tile */
  label: string;

  /** Size of the link text. If there are more than 3 tiles, this will generally be 'sm' */
  size?: 'sm' | 'lg';

  /** Custom classnames */
  className?: string;

  /** Flag to open link in a new tab */
  shouldOpenNewTab?: boolean;

  /** Flag to indicate the link is external and should be a plain anchor tag */
  isExternal?: boolean;

  /** Flag to render in skeleton mode */
  skeleton?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

export const StatusBarLinkTile: React.FC<StatusBarLinkTileProps> = ({
  text,
  linkTo,
  label,
  size = 'lg',
  className,
  shouldOpenNewTab = false,
  isExternal = false,
  skeleton = false,
  testId = 'status-bar-link-tile',
  trackingId = 'status-bar-link-tile',
}): React.ReactElement => {
  const globalSkeleton = useSkeletonContext()?.skeleton;
  const shouldSkeleton = skeleton || globalSkeleton;
  const linkContents = <>{text}</>;
  return (
    <div
      className={cx(
        'flex flex-col items-center font-semibold',
        DEFAULT_STATUS_BAR_CHILD_CLASSES,
        className,
      )}
      data-testid={testId}
      data-trackingid={trackingId}
    >
      {!isExternal && (
        <>
          {shouldSkeleton && (
            <LoadingBlock width={130} height={size === 'sm' ? 21 : 26} />
          )}
          {!shouldSkeleton && (
            <Link
              to={linkTo}
              target={shouldOpenNewTab ? '_blank' : undefined}
              className={cx('text-fgBrand flex grow basis-0 items-center', {
                'text-base': size === 'sm',
                'text-lg': size === 'lg',
              })}
              data-testid={`${testId}-link`}
            >
              {linkContents}
            </Link>
          )}
        </>
      )}
      {isExternal && (
        <>
          {shouldSkeleton && (
            <LoadingBlock width={130} height={size === 'sm' ? 18 : 21} />
          )}
          {!shouldSkeleton && (
            <a
              href={String(linkTo)}
              target={shouldOpenNewTab ? '_blank' : undefined}
              rel="noreferrer"
              className={cx('text-fgBrand flex grow basis-0 items-center', {
                'text-base': size === 'sm',
                'text-lg': size === 'lg',
              })}
              data-testid={`${testId}-link`}
              data-trackingid={`${trackingId}-link`}
            >
              {linkContents}
            </a>
          )}
        </>
      )}
      <div
        className="text-fgDecorative font-label flex grow basis-0 items-end justify-self-end"
        data-testid={`${testId}-label`}
        data-trackingid={`${trackingId}-label`}
      >
        {label}
      </div>
    </div>
  );
};
