import cx from 'classnames';

import { SkeletonContextProvider } from '../../context/SkeletonProvider';
import { StatusBarCountTile } from './statusBarTiles/StatusBarCountTile.internal';
import { StatusBarLinkTile } from './statusBarTiles/StatusBarLinkTile.internal';
import { StatusBarStateTile } from './statusBarTiles/StatusBarStateTile.internal';
import { StatusBarTimingTile } from './statusBarTiles/StatusBarTimingTile.internal';

export interface StatusBarProps {
  /** Child status bar tile components. Should be a set of any combination of StatusBar sub components */
  children: React.ReactNode;

  /** Custom classnames for the StatusBar wrapper */
  className?: string;

  /** Flag to set component to a skeleton state, will be provided to inner-components via context */
  skeleton?: boolean;

  /** data-testid for cypress targeting */
  testId?: string;

  /** data-trackingid for pendo targeting */
  trackingId?: string;
}

/** @deprecated Please use InfoBar instead */
export interface StatusBarSubComponents {
  StateTile: typeof StatusBarStateTile;
  CountTile: typeof StatusBarCountTile;
  TimingTile: typeof StatusBarTimingTile;
  LinkTile: typeof StatusBarLinkTile;
}

/** @deprecated  */
export const StatusBar: React.FC<StatusBarProps> & StatusBarSubComponents = ({
  className,
  children,
  skeleton = false,
  testId = 'status-bar',
  trackingId = 'status-bar',
}): React.ReactElement => {
  return (
    <SkeletonContextProvider isSkeleton={skeleton}>
      <div
        className={cx(
          'border-borderMuted shadow-rest text-fgAlt flex w-full overflow-hidden rounded-md border text-sm',
          className,
        )}
        data-testid={testId}
        data-trackingid={trackingId}
      >
        {children}
      </div>
    </SkeletonContextProvider>
  );
};

export const DEFAULT_STATUS_BAR_CHILD_CLASSES =
  'p-5 basis-0 grow border-r border-borderMuted last:border-0 text-center';

StatusBar.StateTile = StatusBarStateTile;
StatusBar.CountTile = StatusBarCountTile;
StatusBar.TimingTile = StatusBarTimingTile;
StatusBar.LinkTile = StatusBarLinkTile;
